/* cotTruyen q04 (189 chương) — engine-API cotTruyen */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q04"]=window.__LIBQ["pham-nhan-tu-tien"]["q04"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q04"]["cotTruyen"]=[{"chuong":172,"tieuDe":"Tuyển Trạch","tomTat":"Đoàn đệ tử Hoàng Phong Cốc tập hợp tại hoang sơn biên giới Việt quốc – Nguyên Vũ quốc chuẩn bị vào Huyết Cấm. Hàn Lập quyết tham gia thay vì chờ lần sau: cấm địa sẽ bị phong bế 60 năm sau lần mở kế tiếp (đây là lần cuối trước phong bế lớn). Vương sư thúc phụ trách báo danh, kinh ngạc khi tu vi Hàn Lập tăng vọt từ tầng 9 lên tầng 11 — thử lại linh căn vẫn ngụy linh căn, không lý giải được. Hàn Lập giấu bí mật, giả vờ nhút nhát trộn vào đoàn."},{"chuong":173,"tieuDe":"Tụ Tập","tomTat":"Vương sư thúc tiếp tục gặng hỏi. Hàn Lập bịa thuyết 'Long Lân quả' từ 'Kỳ vật dị chí' — tiên gia chi quả thuở nhỏ ăn nhầm giúp bước tiến nhanh — đủ bảy phần thực ba phần giả để thuyết phục. Mã sư bá tặng hai bình đan dược dùng trong cấm địa. Đoàn đếm 25 người: phần lớn Luyện Khí từ tầng 11–13; ba người tầng 11 (gồm Hàn Lập và Trần sư muội trung tầng 12) được ngầm xem là 'vật hy sinh' nếu tình huống nguy cấp. Hàn Lập ý thức rõ vị trí mình trong bàn cờ."},{"chuong":174,"tieuDe":"Lý Sư Tổ","tomTat":"Chưởng môn Chung Linh Đạo phát biểu tiễn đoàn, phát pháp khí qua bốc thăm túi tơ vàng. Lần đầu tiên Lý Sư Tổ — trưởng lão Kết Đan kỳ Hoàng Phong Cốc bao năm chỉ nghe danh chưa gặp — xuất hiện. Khoảng 56-60 tuổi, tóc hơi bạc, mắt hổ uy nghiêm; cưỡi Ngân Giáp Giác Mãng bay 2 ngày dẫn đoàn tới điểm hẹn Kiến Châu. Hướng Chi Lễ tiếp cận Hàn Lập đề nghị liên minh — bị từ chối."},{"chuong":175,"tieuDe":"Thanh Hư Môn","tomTat":"Hướng Tính (Hướng Chi Lễ) từ chối xong cáo từ. Đoàn Hoàng Phong Cốc chờ trên đỉnh núi mấy canh giờ. Đột nhiên Tuyết Hồng Lăng — pháp khí phi hành hình hồng kiều ngân quang của Thanh Hư môn — hạ xuống. Phù Vân Tử dẫn đoàn đạo sĩ áo xám bước ra. Khẩu chiến với Lý Sư Tổ về ván cược cũ (thiết tinh luyện nhập Thanh Quân kiếm). Phù Vân Tử rủ tái cược với vật cược 'hơn hẳn thiết tinh'."},{"chuong":176,"tieuDe":"Đổ Ước","tomTat":"Phù Vân Tử tung mồi nội đan Huyết Tuyến Giao — viên cầu trắng phủ tơ máu, vật Lý Sư Tổ mai phục hơn 30 năm ở Bàn Long giang không bắt được. Lý Sư Tổ đồng ý. Khung tiền bối Yểm Nguyệt tông (áo lam bẩn, Vô hình độn pháp đỉnh cao, chân đã đạp ngưỡng Nguyên Anh kỳ) xuất hiện xen vào ván cược ba bên. Vật cược của Khung: 3 Vô hình châm tự luyện. Lý sư tổ và Phù Vân Tử thấy vẻ tham lam lộ ra trong mắt nhau."},{"chuong":177,"tieuDe":"Tu Tiên Giới Dữ Chánh Tà","tomTat":"Ba bên chốt ván cược. Khung tiền bối tiết lộ Nghê Thường mới là người thực sự dẫn Yểm Nguyệt tông lần này — lão chỉ đến xem đệ tử thiên tư. Lý Sư Tổ giảng cho đoàn đệ tử: chính-tà chỉ là 'cá lớn nuốt cá bé'; thất đại phái Việt quốc là trung lập, ngàn năm trước liên thủ diệt chính-tà. Hứa: đệ tử giúp thắng cược + Trúc Cơ thành công sẽ được thu làm môn hạ. Hàn Lập ngồi nghe, tự nhủ đây là cơ hội thoát khỏi địa vị thấp kém."},{"chuong":178,"tieuDe":"Yểm Nguyệt Tông","tomTat":"Nghê Thường tiên tử dẫn Yểm Nguyệt tông xuất hiện trên Thiên Nguyệt thần chu — thuyền phi hành chạm trổ vàng bạc tả long họa phượng, nguy nga hơn Tuyết Hồng Lăng. Nghê Thường: thiếu phụ phong tình vạn chủng, câu hồn toàn bộ nam đệ tử. Khung tiền bối ẩn thân biến mất sau vài câu, tuyên bố 'lần này thắng chắc'. Hàn Lập quan sát bốn phái còn lại: Cự Kiếm Môn (hắc y cự kiếm sát khí), Linh Thú Sơn (túi da linh thú), Hóa Đao Ổ, Thiên Khuyết Bảo (đại ấn vàng)."},{"chuong":179,"tieuDe":"Phá Cấm","tomTat":"Hàn Lập quan sát thêm nhân vật nổi trội: cô gái bán Kim Trúc Bút cũ (Linh Thú Sơn) nhận ra hắn, bị gã râu quai nón ức hiếp. Bảy tổ sư Kết Đan kỳ cùng xuất pháp bảo bản mệnh công phá Phong nhận đại trận 3-4 canh giờ: Lý Sư Tổ dùng Giới thước, Phù Vân Tử phun phi kiếm hóa giao long. Sau khi thông đạo mở, toàn đoàn bay vào. Bên trong, na di trận pháp truyền tống ngay tức thì — trời đất xoay chuyển, Hàn Lập bị tống đến góc ngẫu nhiên trong cấm địa, mọi người tan tác."},{"chuong":180,"tieuDe":"Ô Long Đàm","tomTat":"Hàn Lập tỉnh dậy trong cấm địa — vũng bùn lầy, cây cối vặn vẹo, mùi khó chịu. Định hướng, nhận biết Ô Long đàm phía đông bắc. Bờ đàm đóng băng sương mù, sâu hơn 10 trượng, có Hủ cốt hoa, Xà diên thụ và — bất ngờ — Hàn yên thảo 5 lá trắng tuyền (kỳ thảo quý, hơn mười mấy năm mới xuất hiện một lần). Dùng Ẩn hình thuật ẩn mình. Quan sát Vu sư huynh nhóm Linh Thú Sơn dùng Khu thú phấn + Băng trùy thuật + Hàn băng thiềm giết đệ tử Thiên Khuyết Bảo, sau đó đề nghị nhau dùng Hàn yên thảo làm mồi câu người khác. Thu thập Kim phù tử mẫu nhận trong vùng."},{"chuong":364,"tieuDe":"Cô Đảo, Cự Chu","tomTat":"Hàn Lập tỉnh lại sau truyền tống trong một nơi tối lạ, được Đại Na Di Lệnh phát thanh quang bảo hộ khỏi áp lực nhưng cũng bị hút linh lực do tu vi hiện tại còn thấp. Hắn lập tức sai Khúc Hồn dùng ngân sắc cự kiếm phá hủy Truyền Tống trận cổ xưa để cắt nguy cơ có người truy theo. Hai người rời thạch động bỏ hoang, men theo cầu thang đá lên trên và chém mở khối đá chắn lối ra. Bên ngoài, Hàn Lập phát hiện trước mắt là đại hải xanh vô tận, màu nước không giống Vô Biên Hải trong ghi chép nên suy đoán mình đã rời khỏi Thiên Nam. Hắn dùng thần thức và Thần Phong Chu khảo sát, xác định nơi đến là một cô đảo khoảng mười dặm, linh khí thấp và không thích hợp ở lâu để điều chế linh dược. Sau khi nghỉ một ngày một đêm dưới sự bảo hộ của Khúc Hồn, Hàn Lập che lại động khẩu rồi bay theo hướng mặt trời lặn tìm người hoặc đất liền. Nửa ngày sau, hắn phát hiện một hải thuyền lớn không buồm do hơn mười con cá khổng lồ không có linh khí kéo đi, nên quyết định áp sát tìm hiểu."},{"chuong":365,"tieuDe":"Vương Trường Thanh","tomTat":"Hàn Lập phát hiện một hải thuyền trên biển, bay tới quan sát và khiến hai ba trăm phàm nhân trên thuyền kính sợ hành lễ, nhưng hắn không hiểu ngôn ngữ của họ. Sau khi thử tiếng Thiên Nam và nhiều cổ ngữ, hắn gặp Vương Trường Thanh, một lão giả từng học ngôn ngữ tiên gia, nhờ đó có người thông dịch với Cố đông chủ. Hàn Lập dùng thần thức kiểm tra toàn thuyền, xác nhận không có tu sĩ, rồi thu Thần Phong Chu sau khi đưa Khúc Hồn lên thuyền. Cố đông chủ mời Hàn Lập đến Khôi Tinh Đảo và hứa cung ứng chi phí tu hành, nhưng Hàn Lập chỉ nhận tạm ở lại vài ngày để học ngôn ngữ và tìm hiểu tình hình. Trong phòng hảo hạng trên thuyền, Vương Trường Thanh giới thiệu Ngân Giác Thụ, một cây bạc có khả năng làm không khí u ám trở nên thuần tịnh. Theo lời lão, Hàn Lập biết nơi này là vùng tây nam Loạn Tinh Hải, phụ cận có Vĩ Tinh đảo, Khôi Tinh Đảo và Tang Tinh cùng nhiều đảo lớn nhỏ, mỗi đảo do đảo chủ là tiên sư mạnh nhất quản lý tu sĩ bằng chức vụ và linh thạch."},{"chuong":366,"tieuDe":"Sinh Ý Của Cố Đông Chủ","tomTat":"Vương Trường Thanh giải thích cho Hàn Lập rằng phàm nhân ở Thất Tinh Hải hoặc sống trên đảo, hoặc làm lao dịch, hoặc lên thuyền đi biển và thường phải mời tu sĩ hộ tống để tránh hiểm nguy. Lão kể tam đại thiên tai của vùng biển là Yêu thú, Thiên phong và Quỷ vụ, trong đó Thiên phong có thể cuốn cả tiên sư vào chỗ chết còn Quỷ vụ khiến vật sống bị vây vào chưa từng trở ra. Việc Hàn Lập không biết những điều này khiến Vương Trường Thanh thầm nghi xuất thân của hắn không thuộc vùng biển, còn Hàn Lập thì nhận ra kế hoạch tìm tiểu đảo có linh khí để ẩn tu một mình đã thất bại. Hàn Lập tiếp tục truy hỏi nguyên do Cố đông chủ mời mình tới Khôi Tinh Đảo, buộc Vương Trường Thanh nói thật rằng chuyến thuyền vừa hoàn thành sinh ý và đang về đảo. Cố đông chủ vốn muốn chen vào buôn bán đường dài giữa các đại đảo, nhưng tư cách ấy bị mười hộ phàm nhân nắm giữ và cứ ba năm phải chọn lại bằng đấu pháp của tiên sư. Vì không kịp tìm người ra tay, Cố đông chủ mới bám lấy Hàn Lập mong hắn thay mình khiêu chiến. Hàn Lập nhìn ra quan hệ giữa tu sĩ và phàm nhân ở Loạn Tinh Hải phức tạp hơn Thiên Nam, nhưng trong lòng không muốn hạ mình vì một vụ sinh ý của phàm nhân. Cuối chương, hắn đặt câu hỏi vì sao tu sĩ có túi trữ vật và có thể phi hành lại không trực tiếp vận chuyển hàng hóa."},{"chuong":367,"tieuDe":"Bảo Nhân Dữ Định Cư","tomTat":"Vương Trường Thanh giải thích với Hàn Lập rằng túi trữ vật của tu tiên giả tuy thần diệu nhưng không dùng để chở hàng phàm nhân và cũng không đủ chứa lượng hàng giao dịch giữa các đảo. Hàn Lập ban đầu từ chối lời nhờ của Cố đông chủ vì tu vi chưa khôi phục, không muốn vừa đến Khôi Tinh Đảo đã dính thị phi, chỉ xin được đưa tới vùng đảo và trả linh thạch thù lao. Sau đó hắn giữ kín số linh dược trên người, uống Hoàn Long Đan và luyện khí để sớm khôi phục tu vi. Cố đông chủ cùng Vương Trường Thanh trở lại thương lượng, đưa ra linh thạch, tư cách bảo nhân giúp Hàn Lập định cư tại Khôi Tinh Đảo và ba thành lợi nhuận trong ba năm nếu Cố gia giành được tư cách buôn bán. Khi biết tu sĩ định cư có quyền nhận chức và dự đại hội tranh đoạt linh địa mười năm một lần, Hàn Lập nhận ra điều này phù hợp với nhu cầu tu luyện, trồng linh thảo và phục hồi thực lực của mình. Hắn đổi ý có điều kiện, yêu cầu biết rõ tu vi đối thủ và dự tính nếu không có Trúc Cơ kỳ thì có thể dựa vào khôi lỗi cùng pháp khí để ứng phó. Bốn ngày sau, thuyền của Cố đông chủ tới Khôi Tinh Đảo, Hàn Lập được dẫn đi làm thủ tục nhập cảng và chứng kiến bến cảng rộng lớn, thuyền bè đông đúc, người qua lại như nước."},{"chuong":368,"tieuDe":"Trang Viên","tomTat":"Hàn Lập theo Cố đông chủ và Vương Trường Thanh tới thạch ốc bên cảng khẩu Khôi Tinh Đảo để làm thủ tục, gặp Dương tiên sư là tu sĩ Trúc Cơ kỳ phụ trách cấp ngọc bài. Sau khi Cố đông chủ nộp linh thạch, Dương tiên sư khắc dấu hiệu lên ngọc bài màu xanh giao cho Hàn Lập và cảnh báo việc mất thẻ sẽ bị xử như kẻ xâm nhập; đồng thời ông nhìn ra Khúc Hồn là luyện thi và sau đó nghi ngờ thân thể tử thi này vẫn phát tán linh khí. Đoàn người thuê thú xa về Cố gia trang, nơi có nông trang, trạch viện mới xây và các cây tùng quanh nhà bị hạ cấm chế. Hàn Lập nhận ra trận pháp quanh Cố gia không cao minh nhưng đủ vây tu tiên giả cấp thấp, nên từ chối nghỉ trong nhà và chọn lên ngọn đồi gần đó dựng mộc ốc. Trong một tháng ở mộc ốc, hắn phục đan, dụng dược và luyện khí đả tọa, khôi phục tới Luyện khí kỳ tầng năm. Cố đông chủ nhiều lần lên núi bàn chuyện xuất thủ khiêu chiến, cho biết phần lớn tiên sư của mười hộ chỉ ở Luyện khí sáu, bảy tầng và còn đem vài pháp khí thượng giai để tăng phần thắng. Hai ngày sau, Hàn Lập cùng Cố đông chủ và Vương Trường Thanh đi thú xa vào thành thị đá trắng; tại cửa thành, vệ binh dùng vòng đồng kiểm tra thấy lục quang phát ra liền cung kính hành lễ với hắn."},{"chuong":369,"tieuDe":"Khiêu Chiến Thượng","tomTat":"Hàn Lập theo Cố đông chủ và Vương Trường Thanh vào Đông Thạch thành, chú ý việc vệ binh phàm nhân dùng Linh bàn để nhận biết tiên sư. Đúng ngày Khôi Tinh Đảo ba tháng mở cửa một lần, đường phố và quảng trường trung tâm đông nghịt người từ các thành trấn đông bộ tới giao dịch. Cố đông chủ đưa Hàn Lập tới cung điện trung tâm, nhưng chỉ Hàn Lập được Văn Tường dẫn vào khu dành cho tu sĩ tham gia khiêu chiến. Trong đại sảnh hình vòng tròn, lão giả Trúc Cơ sơ kỳ công bố luật đấu một trận phân thắng bại, được đả thương nhưng không được giết người, rồi cho các tu sĩ rút thẻ từ ống ngọc màu xanh. Hàn Lập nhận ra ống ngọc có thanh quang bài xích thần thức nhưng không phá để tránh gây chú ý; sau đó hắn rút thẻ mới nhớ mình không biết văn tự địa phương. Vì không đọc được số, hắn chậm bước ra khi lão giả gọi trận số bảy và phải lấy cớ nhìn nhầm thành số chín. Cuối chương, Hàn Lập cùng trung niên tu sĩ Luyện khí tầng bảy vào sàn đấu trận pháp, đối thủ tự tin khuyên hắn nhận thua còn hắn chỉ mỉm cười quan sát."},{"chuong":370,"tieuDe":"Khiêu Chiến (Hạ)","tomTat":"Hàn Lập bước vào sàn đấu và hạ trung niên tu sĩ đầu tiên trong chớp mắt, khiến cả đại sảnh kinh ngạc vì đối thủ vốn bị xem là có lợi thế tu vi hơn. Lão giả chủ trì tiếp tục công bố quy tắc khiêu chiến trong ngày, cho phép người hao pháp lực tạm hoãn nhưng buộc mọi lượt phải kết thúc trước khi mất quyền. Các khiêu chiến giả sau đó lần lượt thất bại hoặc chần chừ, còn Hàn Lập ở lượt của mình lại chọn hán tử khỏe mạnh tu vi sáu tầng và kéo đối phương cháy sém ra ngoài trong khi bản thân không hề bị thương. Cuối cùng lão giả tuyên bố chỉ Hàn Lập thay Cố gia đoạt được tư cách buôn bán giữa các đảo lớn, rồi giao ngọc giản màu lam để hắn chuyển lại cho Cố gia. Trên đường về, Cố đông chủ vui mừng hứa thực hiện điều kiện đã đáp ứng, nhưng Hàn Lập kín đáo cảnh cáo Cố gia không nên qua cầu rút ván khiến Cố đông chủ và Vương Trường Thanh tái mặt. Ba ngày sau, Vương Trường Thanh báo Hàn Lập có thể lên Đăng Tiên Các để làm thủ tục ở lại Khôi Tinh Đảo vĩnh cửu và xác định nơi tu luyện. Hàn Lập để Khúc Hồn ở lại mộc ốc, tự ngự khí tới tiên sơn trung bộ Khôi Tinh Đảo và gặp lại Văn Tường đang cưỡi pháp khí phi hành hình bánh xe. Văn Tường khen hắn đã đánh bại tu sĩ của hộ vệ đội, làm Hàn Lập bất ngờ trước thân phận thật của các đối thủ vừa qua."},{"chuong":371,"tieuDe":"Đăng Tiên Các","tomTat":"Sau khi Hàn Lập thắng nhóm hộ vệ đội, Văn Tường giải thích rằng những tu sĩ bị khiêu chiến tuy tu vi không cao nhưng thường ra biển săn yêu thú nên kinh nghiệm đấu pháp rất dày. Ông dẫn Hàn Lập tới Đăng Tiên Các, trên đường giới thiệu Thanh Vân Sơn có ba đại cự phong, hàng trăm tiểu sơn, nhiều động quật và sơn cốc, trong đó ba mươi sáu ngọn núi linh khí tốt nhất được tranh đoạt theo kỳ khiêu chiến mười năm. Khi Hàn Lập hỏi về ba chủ phong, Văn Tường cho biết Thiên Trụ Phong thuộc đảo chủ Mộc Long chân nhân Kết Đan trung kỳ, còn Thiên Môn Phong và Thiên Tiêu Phong là động phủ của hai phó đảo chủ Viên Quân chân nhân và Khản Cầm chân nhân, đều là Kết Đan sơ kỳ. Đăng Tiên Các bên ngoài chỉ là tiểu lầu cũ kỹ nhưng bên trong cực kỳ xa hoa, do một trung niên nhân Trúc Cơ hậu kỳ có dáng bệnh nặng phụ trách. Người này nhận văn thư bảo nhân của Cố gia, biết Hàn Lập từng đánh bại đệ tử thuộc hộ vệ đội của mình và yêu cầu Hàn Lập năm năm sau tỷ thí lại với đệ tử đó. Sau khi Hàn Lập đồng ý, ông ghi tên Hàn Lập vào kim sắc thư sách, thu ngọc bài màu xanh, đổi cho lam sắc ngọc bội tị thủy và đưa ngân sắc họa sách để Hàn Lập tự chọn nơi tu luyện."},{"chuong":372,"tieuDe":"Tiểu Hoàn Đảo","tomTat":"Hàn Lập nhận họa sách bản đồ chọn nơi tu luyện tại Đăng Tiên Các, nhận ra Thanh Vân Sơn tuy linh khí tốt nhưng nhiều nơi không dành cho Luyện Khí kỳ. Hắn hỏi kỹ quyền khai mở động phủ và được biết phạm vi mười dặm quanh động phủ thuộc về người chọn, có thể bố trí trận pháp cấm chế nếu đủ bản sự. Thay vì chọn nơi tốt trên Khôi Tinh Đảo, Hàn Lập chỉ vào Tiểu Hoàn Đảo, một đảo phụ linh khí yếu, diện tích nhỏ, có phòng hộ trận phải dùng linh thạch duy trì. Trung niên tu sĩ nhiều lần nhắc bất lợi, nhưng Hàn Lập vẫn xác nhận lựa chọn vì trên thực tế có thể làm chủ hòn đảo và tránh xa tu sĩ khác để bảo vệ bí mật tiểu bình tử. Sau khi được ghi nhận bằng họa sách và ngọc giản chứng minh, Hàn Lập rời Thanh Vân Sơn, không kết giao đồng đạo, về Cố gia trang để thư cho Cố đông chủ rồi mang Khúc Hồn đi. Hắn cũng tạm bỏ ý định đến Thiên đô nhai ở Khôi Tinh Thành vì tu vi hiện tại quá thấp. Bay một ngày một đêm rời khỏi cấm chế Khôi Tinh Đảo, Hàn Lập đến Tiểu Hoàn Đảo, hạ xuống bến tàu và gặp Hắc Quý cùng nhóm ngư dân. Sau khi xác nhận nơi đây là Tiểu Hoàn Đảo, hắn tuyên bố từ nay linh thạch tiêu hao trên đảo do mình bỏ ra và nơi này là chỗ tu luyện của hắn."},{"chuong":373,"tieuDe":"Thân Ngoại Hóa Thân","tomTat":"Hàn Lập cùng Khúc Hồn đến trấn nhỏ duy nhất trên đảo, dùng kim sắc ngọc giản xác nhận thân phận quản đảo với trưởng trấn. Sau khi hỏi kỹ, hắn phát hiện linh thạch dân cư nộp cho phòng hộ trận gần như không đáng kể nên phải tự cấp đủ chi phí duy trì một năm và dặn sau này tới động phủ lĩnh tiếp. Hắn khảo sát Tiểu Hoàn Sơn, dùng động phủ cũ ở núi thấp làm vỏ ngoài, đào thông đạo sang núi cao để xây động phủ thật bán phong bế, rồi bố trí Điên Đảo Ngũ Hành Trận, Thiên Phong Cuồng Liệt Trận và Huyễn Hành Thiên La Trận bảo vệ hai ngọn núi. Trong động phủ thật, Hàn Lập lập dược viên, đặt tiểu bình để ngưng tụ lục dịch, đồng thời xây hơn mười mật thất nuôi Bạch tri thù và kỳ trùng theo Dục Trùng tâm đắc. Sau đó hắn nghiên cứu hôi bạch sắc ngọc giản của Việt hoàng, phát hiện Thân ngoại hóa thân có điều kiện khắt khe và rủi ro mất thần thức nếu thất bại. Hàn Lập nhận định Khúc Hồn là khu thể phù hợp hiếm có, dự tính trước hết khôi phục Trúc Cơ, luyện Đại Diễn Quyết tầng hai rồi tế luyện phân thân, sau đó tiếp tục Tam Chuyển Trọng Nguyên Công và Thanh Nguyên Kiếm Quyết để hướng tới Kết Đan."},{"chuong":374,"tieuDe":"Tu Luyện Vô Tuế Nguyệt","tomTat":"Hàn Lập khép mình tu luyện trên Tiểu Hoàn Đảo, vừa thôi dục linh dược, điều chế Hoàng Long Đan và Kim Tủy Đan, vừa dùng Dục Trùng tâm đắc để dạy Bạch tri trù cùng kỳ trùng. Sau gần một năm, hắn đạt Luyện khí tầng chín, uống ba viên Trúc Cơ đan và trở lại Trúc Cơ kỳ, từ đó có thể dùng Tiên thiên chân hỏa luyện các đan dược phù hợp cảnh giới này. Hắn không vội tăng tu vi mà dồn sức tu Đại Diễn Quyết tầng hai, chịu rèn thần thức đau đớn suốt sáu năm mới miễn cưỡng thành công; trong thời gian ấy, đồ đệ của trung niên tu sĩ Đăng Tiên Các đến khiêu chiến nhưng bị đại trận vây rồi nhanh chóng thua trận. Sau khi tĩnh dưỡng nguyên thần, Hàn Lập đóng mật thất hơn một tháng để tế luyện Khúc Hồn thành thân ngoại hóa thân, thành công nhưng nguyên khí bị tổn thương nặng. Hồi phục xong, hắn nghiên cứu Tam chuyển trọng nguyên công, hiểu cơ chế tán tu vi Thanh Nguyên Kiếm Quyết rồi tu lại để áp súc chân nguyên và giảm bình cảnh kết đan, đồng thời chuẩn bị cho Khúc Hồn sau này Trúc Cơ rồi tu Huyết luyện thần quang. Hơn hai mươi năm trôi qua, Hàn Lập không rời động phủ, dân Tiểu Hoàn Đảo quen với bạch vụ che hai ngọn núi và trưởng trấn mới Hắc Quý vẫn theo lệ nhận linh thạch duy trì trận pháp. Cuối chương, Hàn Lập rời động phủ sau quãng bế quan dài."},{"chuong":375,"tieuDe":"Song Kiều","tomTat":"Sau hơn hai mươi năm bế quan, Hàn Lập đã hoàn thành nhất chuyển Tam chuyển trọng nguyên công, đưa pháp lực lên Trúc Cơ đỉnh phong, còn Khúc Hồn nhờ nhiều đan dược cũng gần đuổi kịp hắn. Vì Khúc Hồn còn thiếu vài vật phụ trợ để ngưng kết Sát đan và bản thân Hàn Lập cũng cần chuẩn bị cho việc kết đan, hai người rời Tiểu Hoàn Sơn đi Khôi Tinh Thành. Tới gần đại thành, Thần Phong Chu bị cấm không cấm chế câu thúc nên Hàn Lập chủ động hạ xuống rồi đi bộ vào thành để tránh gây chú ý. Hắn hỏi đường tới Thiên Đô Nhai và kinh ngạc khi thấy khu giao dịch tu sĩ nằm trong màn bạch quang, giữa đó có Vân Mộng Các xanh biếc lơ lửng giữa không trung. Trước khi tiếp xúc người ngoài, Hàn Lập thu liễm linh khí, chỉ để lộ mức Luyện Khí tầng tám chín, còn Khúc Hồn được hắn giới thiệu thành sư thúc có tu vi Trúc Cơ hậu kỳ. Tại đây, hai nữ tán tu Nghiên Lệ và Nguyên Dao chủ động bắt chuyện, tự xưng quen thuộc Thiên Đô Nhai và đề nghị dẫn đường cho hai người. Hàn Lập sinh lòng cảnh giác, bèn để Khúc Hồn lạnh lùng từ chối lời mời rồi cùng nhau nhanh chóng đi vào màn hào quang, bỏ lại hai nữ thất vọng và ba nam tu sĩ đi cùng thì ngầm mừng thầm."},{"chuong":376,"tieuDe":"Tuyết Linh Thủy Và Thiên Hỏa Dịch","tomTat":"Hàn Lập rời căn phòng khi hai nữ và ba nam tử đi vào khu cửa hàng, quan sát một lát rồi cùng Khúc Hồn hướng tới trung tâm Thiên Đô Nhai thay vì ghé các tiệm nhỏ hai bên đường. Tại quảng trường lát ngọc trắng, hắn thấy Vân Mộng Các lơ lửng giữa không trung, xung quanh có sáu lâu các nhỏ treo tiêu thức khác nhau nên suy đoán mỗi nơi chuyên một loại hàng. Hắn chọn Bạch Thủy Lâu để thăm dò, nhận ra pháp khí bày trong đại sảnh không đáng chú ý, nhưng Khúc Hồn được tiểu nhị mời vào phòng trong vì bị nhận ra là tu sĩ Trúc Cơ cao giai. Chưởng quầy Tào Lộc xuất hiện, kinh ngạc gọi Khúc Hồn đã tới cảnh giới Giả Đan, khiến Hàn Lập hiểu đây là cách gọi tu vi Trúc Cơ đỉnh phong. Hàn Lập mượn miệng Khúc Hồn hỏi mua Tuyết Linh Thủy và Thiên Hỏa Dịch để chuẩn bị Kết Đan, đồng thời dựng lai lịch Khúc Hồn là tu sĩ Khôi Tinh Đảo nhằm che giấu thân phận. Tào Lộc dùng truyền âm phù liên hệ Âu Dương đạo hữu của Ngọc Hoàn Cư, còn Hàn Lập cảnh giác trước sự nhiệt tình dò hỏi của Tào Lộc. Âu Dương đạo hữu mang tới hai hộp ngọc chứa hai linh vật đủ cho hai người kết đan, bề ngoài hào sảng nhưng bị Hàn Lập nhận ra tâm cơ thâm trầm. Sau khi Khúc Hồn mở hộp kiểm tra một vật tỏa hàn khí và một vật nóng rực màu hỏa hồng, Hàn Lập xác định Tuyết Linh Thủy cùng Thiên Hỏa Dịch là vật khó cầu và nhất định phải lấy để tăng hiệu suất kết đan."},{"chuong":377,"tieuDe":"Đan Phương Và Yêu Đan","tomTat":"Tại Bạch Thủy Lâu, Tào Lộc và đại hán Lục Liên Điện đem Tuyết Linh Thủy cùng Thiên Hỏa Dịch tặng Khúc Hồn dưới danh nghĩa hạ lễ kết đan, nhưng Hàn Lập không tin có chuyện vô cớ nhận lễ nên điều khiển Khúc Hồn hỏi rõ mục đích. Hai người Lục Liên Điện thừa nhận muốn nhờ Khúc Hồn tham gia hành động lấy Yêu Đan của một con yêu thú cấp sáu, với thù lao là Hàng Trần Đan có ích cho việc kết đan. Đại hán giải thích hành động sẽ có hai khách khanh trưởng lão Kết Đan kỳ ra tay, còn sáu tu sĩ Giả Đan chỉ cần chủ trì Lục độn thủy ba đại trận, khiến Hàn Lập nhớ tới tư liệu trận pháp Tân Như Âm từng tặng. Hàn Lập không lập tức quyết định, để Khúc Hồn xin vài ngày suy nghĩ rồi nhận hai hộp linh vật và rời khỏi Bạch Thủy Lâu. Sau đó hắn không tiếp tục vào các điện các cùng hệ thống Lục Liên Điện mà tìm cửa hàng nhỏ để mua nguyên liệu chế nhị cấp khôi lỗi thú và hạt giống luyện Tụ Linh Hoàn. Khi hỏi mua đan phương Trúc Cơ kỳ, hắn phát hiện đan phương cao giai ở Loạn Tinh Hải phần lớn lấy nội đan yêu thú làm chủ liệu, khác hẳn Thiên Nam nơi linh thảo giữ vai trò then chốt. Hàn Lập mua một tấm đan phương Trúc Cơ Đan bản địa để đối chiếu và nhận ra vài linh dược từng có trong Huyết Sắc Cấm Địa đã được thay bằng nội đan yêu thú cấp năm, rồi cất đan phương và lâm vào trầm tư."},{"chuong":378,"tieuDe":"Xuất Hải (Thượng)","tomTat":"Hàn Lập khảo sát các cửa hàng điển tịch ở Khôi Tinh Thành, nhận ra công pháp và pháp thuật nơi đây phần lớn tương tự Thiên Nam nhưng thủy hệ pháp thuật phong phú hơn. Vì Đan đạo bình giám có lời bình về Hàng Trần Đan, hắn mua sách để nghiên cứu trước khi quyết định có nhận lời Lục Liên Điện hay không. Sau đó Hàn Lập cùng Khúc Hồn trở lại Cố Gia Trang, thấy căn nhà cũ của mình vẫn được Cố Gia chăm sóc sạch sẽ, rồi gặp Cố đông chủ đã già yếu. Cố đông chủ giao linh thạch, giới thiệu hậu bối và ngầm gửi gắm Cố Gia cho Hàn Lập, khiến hắn vì nhân tình cũ mà đáp ứng mơ hồ. Trong khách điếm, Hàn Lập đọc sách suốt đêm, biết Hàng Trần Đan có thể tăng cơ hội Kết Đan nhưng nhiệm vụ Lục Liên Điện chắc chắn không đơn giản, cuối cùng vẫn quyết định mạo hiểm vì bản thân và Khúc Hồn đều cần Kết Đan. Nửa tháng sau, Hàn Lập, Khúc Hồn và Tào Lộc lên hải thuyền rời cảng Khôi Tinh Đảo; thuyền trưởng Lạc Chánh nghênh tiếp họ và cho biết các tiên sư khác đã có mặt để đi đến nơi yêu thú xuất hiện. Khi vào đại sảnh khoang thuyền, Khúc Hồn đứng ra tự xưng và gọi Hàn Lập là sư điệt, tạo lớp thân phận bề ngoài trước nhóm tu sĩ đồng hành."},{"chuong":379,"tieuDe":"Xuất Hải (Hạ)","tomTat":"Khúc Hồn được Phùng Tam Nương của Lục Liên Điện đón vào thuyền, còn Hàn Lập ẩn vai đứng sau quan sát nhóm tu sĩ được mời để chủ trì Lục Độn Thủy Ba Trận. Phùng Tam Nương giới thiệu Mao đạo hữu, Tiết đạo hữu, Thanh Toán Tử, Nghiêm đạo hữu và các tu sĩ khác, đồng thời cho thấy chuyến đi nhằm phối hợp bày trận bắt yêu thú. Mao đạo hữu tỏ thái độ cao ngạo, chất vấn lai lịch Khúc Hồn tại Khôi Tinh Đảo, nhưng bị Khúc Hồn bình thản đáp trả khiến không khí căng thẳng trước khi Tiết đạo hữu can thiệp. Sau đó Phùng Tam Nương giảng giải trận pháp, nhóm tu sĩ luyện tập nhiều ngày trên đường đi để nắm vững các biến hóa cần phối hợp. Một tháng sau, hải thuyền đến hoang đảo vô danh nơi đại trận đã được bố trí, Miêu trưởng lão hiện thân và được Hàn Lập nhận ra là tu sĩ Kết Đan kỳ. Miêu trưởng lão giao nhiệm vụ cho nhóm chủ trì trận pháp, cho biết Cổ trưởng lão đang truy đuổi yêu thú ở vùng hải vực phụ cận và dự tính sáng sớm hôm sau sẽ dẫn nó vào trận. Trước giờ hành động, Thanh Toán Tử hỏi thẳng vì sao Phùng Tam Nương vẫn giấu chủng loại yêu thú, khiến nghi vấn về mức nguy hiểm thật sự của con yêu thú càng nổi rõ."},{"chuong":380,"tieuDe":"Anh Lý Thú","tomTat":"Phùng Tam Nương giải thích rằng vì lệnh bề trên nên Lục Liên Điện chưa thể tiết lộ mục tiêu trước khi lên đảo, rồi công bố đối tượng thật là Anh Lý Thú. Nhóm Thanh Toán Tử lập tức biến sắc, còn trung niên nho sinh họ Mao chỉ rõ yêu thú này là thủy hệ linh thú trời sinh, tuy cấp sáu nhưng trong đại hải có thể không kém yêu thú cấp bảy. Trước sự bất mãn của các tu sĩ, Phùng Tam Nương khẳng định Lục Liên Điện không nói sai cấp bậc, nhắc Hàng Trần Đan vốn đã là thù lao quý trọng và hứa thêm mỗi người một ngàn linh thạch để bồi thường. Đêm đó Hàn Lập vẫn cảm thấy bất an, không thể nhập định, nên lấy Bích Thủy Thanh Giáp Trận ra lệnh Khúc Hồn bố trí quanh tảng đá làm hậu thủ. Sáng hôm sau, mọi người tới vùng biển cách đảo mười hải lý, sáu tu sĩ Trúc Cơ hậu kỳ cầm đại kỳ màu lam đứng thành nửa vòng tròn để chờ phong tỏa trận môn. Ngoài ngàn dặm, Miêu trưởng lão và Cổ trưởng lão bị khối sương trắng chứa Anh Lý Thú truy đuổi, phải dùng phi kiếm truyền thư báo tin và dựa vào Hỗn Nguyên Bát tăng tốc khi yêu thú sắp dùng Thủy Cương Thần Lôi. Phùng Tam Nương nhận kim quang truyền tin rồi ra lệnh chuẩn bị khóa trận, trong khi Hàn Lập nhìn thấy hai luồng sáng và mảng sương trắng đang lao tới nhưng vẫn chưa thấy rõ hình dạng yêu thú."},{"chuong":381,"tieuDe":"Dị Bảo Phục Yêu","tomTat":"Phùng Tam Nương phát lệnh khởi động trận pháp, cùng các tu sĩ dùng trận kỳ màu lam ẩn thân và dựng màn hào quang vây Anh Lý Thú khi Miêu trưởng lão, Cổ trưởng lão dẫn nó vào trận. Hai trưởng lão Kết Đan kỳ tế ra đôi giáo đồng xanh cũ kỹ, khiến dị bảo hóa thành hai trường thương vàng chĩa xuống trung tâm bạch vụ để chuẩn bị chế yêu. Bị vây, Anh Lý Thú thi triển Thủy cương thần lôi rồi cuộn bạch vụ thành cơn lốc lớn, đánh thẳng vào trận môn của trung niên nho sinh, khiến đại trận vỡ và các tu sĩ chủ trì đều bị phản chấn thổ huyết. Đúng lúc trận tan, hai đạo hoàng mang từ dị bảo giáng xuống, tiếng kêu như trẻ con vang lên, sương trắng tản đi và Anh Lý Thú bị hai thanh trường thương ghim chế trên mặt biển. Hàn Lập đưa linh thạch bậc trung cho Khúc Hồn hồi phục rồi quan sát chân thân kỳ dị của yêu thú, thấy bốn tay nó giữ con cua đỏ, thước san hô lam, châu trắng và vỏ trai bạc, tất cả đều sáng rực như bảo vật quý. Khi Miêu trưởng lão và Cổ trưởng lão mệt mỏi nhưng mừng rỡ bay xuống thu bảo, các tu sĩ khác lộ vẻ tham lam song bị Phùng Tam Nương canh chừng. Bất ngờ, từ biển dưới Anh Lý Thú bùng lên âm phong đen bao phủ mấy trăm trượng, cuốn cả yêu thú đang bị chế trụ rồi đánh về phía hai trưởng lão, khiến Hàn Lập và mọi người sững sờ."},{"chuong":382,"tieuDe":"Ô Sửu","tomTat":"Sau khi Huyền Âm ma khí xuất hiện quanh Anh Lý Thú bị đóng băng, hai trưởng lão Miêu, Cổ nhận ra lai lịch hắc khí và một nam hai nữ lộ diện. Nam tử khô gầy Ô Sửu tự xưng thuộc Cực Âm Đảo, nói gia tổ Cực âm lão tổ sắp xuất quan nên muốn lấy yêu đan Anh Lý Thú làm lễ vật, khiến Lục Liên Điện và các tu sĩ phụ cận đều kiêng sợ. Hàn Lập quan sát tà khí của Ô Sửu, liên hệ nó với Huyết luyện thần quang trên Khúc Hồn và Huyền Âm Kinh trong ngọc giản trắng xám. Ô Sửu dùng ma đao đen nhánh mổ Anh Lý Thú, lấy viên châu màu lam cùng các bộ phận quý bất chấp Cổ trưởng lão yêu cầu để lại yêu đan. Sau đó Cổ trưởng lão truyền âm và đưa ra lệnh bài đầu quỷ, khiến Hàn Lập sinh dự cảm xấu, còn Thanh Toán Tử lập tức hóa hồng quang bỏ chạy. Hàn Lập cũng lấy Thần phong chu kéo Khúc Hồn đào tẩu về phía tiểu đảo vô danh, trong khi hai trưởng lão Miêu, Cổ chia nhau truy sát người bỏ chạy và Ô Sửu phóng âm phong nhằm xử lý nhóm người ở lại."},{"chuong":383,"tieuDe":"Đấu Kết Đan","tomTat":"Hàn Lập điều khiển Thần Phong Chu lao về đảo vô danh, nhưng vừa thấy kiều thạch gần đảo thì Cổ trưởng lão của Lục Liên Điện đã đuổi kịp bằng hoàng hồng và suýt đánh trúng hắn. Biết cầu xin vô ích, Hàn Lập để Khúc Hồn chắn trước, đồng thời tế nhiều pháp khí phòng ngự và công kích để cản Nguyệt Nha quang nhận của tu sĩ Kết Đan. Thanh Ngưng Kính, Quy Xác pháp khí, Ô Long Cập và phi nhận trắng đen lần lượt bị phá hủy, chỉ còn huyết quang xích giao của Khúc Hồn cùng quang xử từ khôi lỗi thú tạm thời giữ thế giằng co. Đúng lúc Cổ trưởng lão muốn tiếp tục ra tay, thương thế cũ do nguyên khí đại thương tái phát, tạo cơ hội để Hàn Lập kéo Khúc Hồn lao xuống đảo vô danh. Cổ trưởng lão cưỡng ép áp chế thương thế và đuổi theo, vì vậy rơi vào Bích Thủy Thanh Giáp Đại Trận, nơi cảnh tượng trước mắt biến thành đại hải bát ngát và áp lực trận pháp đè lên thân thể hắn. Hàn Lập nhận ra nếu bỏ chạy thì đối phương sẽ phá trận quá nhanh, nên quay lại cùng Khúc Hồn lặng lẽ tiến vào trận, lấy chủ trận kỳ màu xanh niệm chú và tăng thêm uy lực vây khốn."},{"chuong":384,"tieuDe":"Trảm Sát Cao Giai","tomTat":"Trong đại trận trên biển, Hàn Lập phối hợp Khúc Hồn, phi châm, phù lục và độn thuật để vây công Cổ trưởng lão đang dựa vào Hỗn Nguyên Bát và hoàng quang hộ thể chống đỡ. Khi áp lực trận pháp tăng mạnh làm phòng hộ của Cổ trưởng lão suy yếu, phi châm đánh vào yếu hại và Hàn Lập xuất hiện bên cạnh chém bay đầu đối thủ. Sau trận, Hàn Lập lấy túi trữ vật từ thi thể, Khúc Hồn thu pháp bảo bát hình màu vàng, rồi cả hai lập tức rời khỏi chiến trường. Một luồng thần thức cường đại phẫn nộ dò xét vùng biển, khiến Hàn Lập phải lặn xuống đáy biển, dùng tấm lụa mỏng và vô danh khẩu quyết che giấu khí tức hơn nửa tháng. Khi thần thức không còn xuất hiện, Hàn Lập nhận định Khôi Tinh Đảo và Tiểu Hoàn Đảo đều không thể quay lại, đồng thời cần tránh xa Lục Liên Điện và thế lực liên quan Ô Sửu. Trên đường rời đi, hắn kiểm kê túi trữ vật Cổ trưởng lão, thu được linh thạch trung phẩm, phù bảo, phù lục, đạo thư Thổ Ly Quyết, nội đan yêu thú cấp năm và năm viên Hàn Trần Đan được nhận ra nhờ Đan Đạo Bình Giám."},{"chuong":385,"tieuDe":"Hải Viên Đảo","tomTat":"Hàn Lập cất các viên Hàng Trần Đan, nhận định lần mạo hiểm suýt mất mạng vẫn đáng giá vì số đan dược này có thể tăng cơ hội kết đan cho hắn và Khúc Hồn. Hắn hệ thống lại điều kiện kết đan ở Loạn Tinh Hải, gồm Tuyết Linh Thủy, Thiên Hỏa Dịch, nhiều linh dược phụ trợ, thời gian bế quan ba đến năm năm, tâm cảnh ổn định và thiên địa linh khí. Sau khi dùng ngọc giản hải đồ xác định phương hướng, Hàn Lập cùng Khúc Hồn liên tục đổi hướng trong hai tháng, tránh các đảo có tu sĩ để không lưu dấu truy tung. Hai người tới Hải Viên Đảo, một hòn đảo trung bình không có đảo chủ, có nhiều phàm nhân, tán tu cấp thấp và đặc sản yêu thú Hải Viên biết Thủy Tiến Thuật. Vì đảo có linh mạch rộng nhưng linh khí không đủ hấp dẫn cao giai tu sĩ hay thế lực lớn, Hàn Lập chọn nơi này làm chỗ ẩn thân kết đan. Hai ngày sau, hắn dựng động phủ tạm trên núi hoang, bố trí dược viên, hai mật thất, trận khí, ẩn nặc trận pháp và thả hai con Huyết bạch tri thù canh giữ. Hàn Lập cũng suy tính động phủ cũ ở Tiểu Hoàn Đảo có thể bị kẻ địch tìm đến, còn chỗ giấu độc trùng chỉ đành phó mặc thiên số. Cuối chương, hắn cùng Khúc Hồn đi vào mật thất, mở đầu giai đoạn bế quan kết đan trên Hải Viên Đảo."},{"chuong":386,"tieuDe":"Tứ Niên Kết Đan","tomTat":"Hàn Lập vào mật thất bế quan, uống Thiên Hỏa Dịch, dùng thêm đan dược và vận Thanh nguyên kiếm quyết để trùng kích bình cảnh Kết Đan; cùng lúc, hắn điều khiển Khúc Hồn ở mật thất bên cạnh dùng linh dược và Huyết Ngưng Ngũ Hành Đan để đi theo hướng kết Sát Đan. Bốn năm sau, trên một ngọn núi hoang ở Hải Viên Đảo xuất hiện mây đen, lôi điện và lốc xoáy linh khí quy mô lớn, khiến các tán tu cấp thấp nhận ra đây là dị tượng có tu sĩ kết đan. Họ bay tới định xem xét hoặc kết giao nhưng bị lời cảnh cáo lạnh lùng buộc phải dừng lại và rút lui, rồi tin Hải Viên Đảo có thêm một tu sĩ Kết Đan nhanh chóng lan truyền. Sự thật là Hàn Lập đã thất bại từ một năm trước vì ba năm luyện khí vẫn không có dấu hiệu ngưng tụ chân nguyên, còn Khúc Hồn nhờ lượng lớn linh dược phụ trợ đã kết thành Sát Đan. Hàn Lập bí mật mang Khúc Hồn rời Hải Viên Đảo, dự tính quay về Tiểu Hoàn Đảo lấy kỳ trùng rồi rời Tây Nam Hải Vực, đồng thời cân nhắc để Khúc Hồn dùng Hỗn Nguyên Bát và phù bảo nhằm có sức giao đấu với tu sĩ Kết Đan. Hơn một tháng sau, hai người tới Tiểu Hoàn Đảo; Hàn Lập dò xét không thấy mai phục nhưng kinh ngạc vì động phủ thật giả và ba tòa trận pháp đều nguyên vẹn bất thường. Sau khi kiểm tra bên ngoài, hắn tiến vào động phủ thật, đi thẳng tới mật thất nuôi kỳ trùng và lập tức sững sờ trước cảnh tượng bên trong."},{"chuong":387,"tieuDe":"Phệ Kim Trùng","tomTat":"Hàn Lập vào khu mật thất nuôi kỳ trùng trong động phủ và phát hiện cấm chế đã biến mất, cửa đá bị đục thủng, các mật thất đều trống rỗng, ngay cả những kỳ trùng cũ trong bách bảng cũng mất tích. Khi dùng thần thức kiểm tra, hắn tìm được một vỏ trùng màu bạc cứng rắn, từ đó nghi ngờ có kỳ trùng lạ xâm nhập. Lần theo dấu vết, Hàn Lập phát hiện ngân cầu dưới tán cây trong dược viên và dùng ngọc giản tâm đắc dục trùng của tu sĩ Ngự Linh Tông để nhận ra đó là Phệ Kim Trùng bài danh mười hai. Hắn sai Khúc Hồn dùng huyết quang và tử diễm ma hỏa thử uy lực, nhưng đàn trùng không bị thiêu chết mà còn cắn nuốt ma hỏa. Hàn Lập lập tức thả hai Huyết Ngọc Tri Thù phun tơ trắng, bao Phệ Kim Trùng thành kén rồi đặt vào hộp ngọc và cất trong túi trữ vật. Sau khi kiểm tra động phủ, hắn nhận ra đàn trùng chui từ dưới đất vào, không dám ở lại lâu nên thu ba bộ trận pháp đầy đủ rồi ngự khí rời đi."},{"chuong":388,"tieuDe":"Khúc Hồn Ma Uy","tomTat":"Hàn Lập và Khúc Hồn vừa rời tiểu đảo bằng Thần Phong Chu thì Hàn Lập phát hiện có người ẩn nấp, khiến bảy tám tu sĩ Trúc Cơ kỳ thuộc chấp pháp Khôi Tinh Đảo phải hiện thân. Lão giả đầu bạc dẫn đầu buộc tội hai người vì Hàng Trần Đan mà giết Mao sư đệ môn hạ đảo chủ Vĩ Tinh Đảo, viện lời chứng của Miêu trưởng lão Lục Liên Điện và lệnh Mộc đảo chủ để định phế tu vi trước. Nhận ra đối phương ngoài mặt nói chế trụ nhưng thực chất ra tay với sát ý, Hàn Lập hạ lệnh Khúc Hồn giết sạch không để ai thoát. Khúc Hồn lập tức lộ uy Kết Đan kỳ, dùng huyết quang cấm và thu pháp khí của nhóm Trúc Cơ, rồi lấy huyết trụ và huyết vân tử hỏa diệt toàn bộ nhóm chấp pháp, sau đó thu các túi trữ vật. Hàn Lập lo có tu sĩ Kết Đan kỳ khác kéo tới nên cùng Khúc Hồn nhanh chóng rời hiện trường bằng Thần Phong Chu. Không lâu sau, Viên đảo chủ và Tề đạo hữu tới nơi vì nguyên thần bài báo tin một đệ tử của Viên đảo chủ đã chết, nhưng hung thủ đã rời đi. Tề đạo hữu tuy có Phù Vân Tầm Tung Thuật để tra hướng nhưng khuyên Viên đảo chủ không nên vì một đệ tử bình thường mà mạo hiểm xung đột với tu sĩ Kết Đan kỳ không rõ lai lịch. Hai người cuối cùng bỏ ý định truy sát, đồng thời hé lộ việc Mộc đảo chủ và Lục Liên Điện đang liên thủ truy Hàn Lập cùng Khúc Hồn."},{"chuong":389,"tieuDe":"Thiên Tinh Thành Dữ Tinh Cung","tomTat":"Sau khi bị truy nã, Hàn Lập nhận ra Tây Nam Hải Vực không thể ở lâu, nhưng vì bản đồ trong tay quá hạn hẹp nên cần tìm thêm hải đồ và điển tịch. Một tháng sau, hắn cùng Khúc Hồn ghé một phường thị trên tiểu đảo vùng biên, dùng bí thuật che giấu dung mạo rồi mua nguyên liệu, ngọc giản và bản đồ trước khi rời đi ngay trong ngày. Trên Thần Phong Chu, Hàn Lập đọc điển tịch và biết Loạn Tinh Hải chia thành Nội Tinh Hải đã thăm dò và Ngoại Tinh Hải còn gọi là Yêu Hải, nơi có nhiều yêu thú cực mạnh. Điển tịch cũng giới thiệu Tinh Cung là thế lực quản hạt Loạn Tinh Hải, trung tâm đặt tại Thiên Tinh Thành, do Thiên Tinh Song Thánh thần bí thống trị. Hàn Lập đặc biệt chú ý việc Thiên Tinh Thành tự do giao thương, cấm tranh đấu trong thành, có đấu giá, Trích Tinh đại hội và truyền tống trận tới Yêu Thú Đảo ở Ngoại Tinh Hải để săn yêu thú lấy Yêu Đan. Vì nơi này vừa an toàn vừa mở ra nguồn tài nguyên tu luyện, hắn quyết định đi Thiên Tinh Thành. Trên đường dài, Hàn Lập thử vận dụng Đại Diễn Quyết để vừa điều khiển Thần Phong Chu vừa tu luyện, sau nhiều lần thất bại mới miễn cưỡng đạt được nhất tâm nhị dụng. Khoảng một tháng sau, hắn nhìn thấy một điểm đen phía trước và thúc pháp khí bay nhanh hơn về hướng Thiên Tinh Thành."},{"chuong":390,"tieuDe":"Cự Thành","tomTat":"Hàn Lập cưỡi Thần Phong Chu tiếp cận Thiên Tinh Thành — đệ nhất đại thành của Loạn Tinh Hải, một siêu cấp thành thị chiếm trọn hải đảo với cự sơn cao tới mây làm trung tâm. Trên đường tới, hắn thấy vô số tu sĩ ngự khí và hải thuyền phàm nhân cùng hướng về thành. Tại cửa thành, tu sĩ canh cửa nhận ra Khúc Hồn là tiền bối Kết Đan kỳ nên cung kính miễn phí vào thành và phát hồng sắc thân phận hoàn, đồng thời giải thích quy định lam sắc tạm trú bảy ngày và hồng sắc ở lâu. Hàn Lập chủ động trả tám trăm linh thạch mua hồng sắc giới chỉ, nhỏ máu nhận chủ rồi vào thành. Phát hiện nội thành không có cấm chế phi hành, hắn định dùng Thần Phong Chu bay tiếp thì phàm nhân Lỗ Nhị từ khách điếm bước ra tự tiến cử làm người dẫn đường. Hàn Lập thuê Lỗ Nhị với điều kiện trả năm linh thạch nếu hài lòng, đưa hắn lên thuyền rồi hỏi ngay nơi nào trong thành tu sĩ có thể tu luyện không bị quấy rầy."},{"chuong":391,"tieuDe":"Tân Cư","tomTat":"Hàn Lập hỏi Lỗ Nhị về quy chế thuê nơi tu luyện ở Thiên Tinh thành và được biết Thánh sơn chia tám mươi mốt tầng, năm mươi tầng dưới cho ngoại lai tu sĩ thuê, ba mươi tầng trên dành cho Tinh Cung, tầng cao nhất là Thánh cung. Hắn để Khúc Hồn ra mặt giao dịch với bạch y tu sĩ Tinh Cung nhờ uy thế Kết Đan kỳ, chọn thuê một động phủ ở tầng ba mươi chín với giá hai ngàn bảy trăm linh thạch và nhận lệnh bài cấm chế màu vàng. Sau đó Hàn Lập sai Lỗ Nhị dẫn đi khảo sát phường thị rồi trả thù lao chia tay. Trở về động phủ, hắn hài lòng vì nơi ở yên tĩnh, linh khí tốt không kém động phủ cũ ở Thiên Nam, nhưng không hoàn toàn tin cấm chế sẵn có nên sáng hôm sau tự bố trí thêm ba bộ đại trận phòng hộ. Hắn trồng dược thảo trong dược viên dự trữ linh dược, mua mỹ ngọc thượng phẩm lát kín một gian mật thất rồi đưa Phệ Kim Trùng vào bên trong, kỳ vọng bồi dưỡng chúng thành trợ lực trong tương lai."},{"chuong":392,"tieuDe":"Dục Trùng","tomTat":"Hàn Lập nghiên cứu giá trị thật của Phệ Kim Trùng qua Kỳ trùng bảng, nhận ra chúng chỉ đáng sợ khi đạt số lượng mười mấy vạn trở lên. Chương hé lộ ấu trùng Phệ Kim Trùng vốn ngủ say từ thượng cổ dưới Tiểu Hoàn Đảo, bị mùi đàn trùng Hàn Lập nuôi trong động phủ đánh thức, chờ Huyết ngọc tri thù rời đi mới xông vào nuốt sạch kỳ trùng và chiếm dược viên. Hàn Lập lần lượt thử trùng lương, ngũ kim nguyên quáng, linh thạch bậc thấp, trứng Kim Bối Đao Lang và Tự Linh Hoàn để bồi dưỡng Phệ Kim Trùng, nhưng chỉ trứng kỳ trùng và Tự Linh Hoàn có chút tác dụng, hiệu quả quá thấp so với nhu cầu nuôi đại quân. Hắn tạm gác kế hoạch, chuyển Tự Linh Hoàn còn lại cho Huyết ngọc tri thù. Sau hai năm bế quan ở Thiên Tinh Thành, Hàn Lập chế nhiều phù lục sơ cấp và luyện xong hơn hai trăm khôi lỗi thú hình cấp hai. Hai con Huyết ngọc tri thù nhờ Tự Linh Hoàn thăng cấp lên nhóm yêu thú đỉnh cấp hàng đầu, Khúc Hồn luyện hóa dung hợp Hỗn Nguyên Bát thành công phát huy được bảy phần uy lực. Hàn Lập quyết định ra Ngoại Tinh Hải săn yêu thú để lấy nội đan luyện linh dược phục vụ nhị chuyển Tam chuyển trọng nguyên công, rồi đến phường thị Thiên Tinh Thành tìm tư liệu."},{"chuong":393,"tieuDe":"Ngưng Thúy Đảo","tomTat":"Trong hai năm chuẩn bị ra biển, Hàn Lập nhiều lần tới phường thị Thiên Tinh Thành mua tài liệu luyện Khôi Lỗi, sao chép tư liệu yêu thú Loạn Tinh Hải tại Bạch Môn Các và tìm thêm tài liệu Ngoại Tinh Hải ở tiểu điếm cũ. Hắn mua hai túi trữ vật dung lượng cực lớn bằng hơn một ngàn linh thạch, đi ngang phòng đấu giá Phong Nhạc thấy yêu đan cấp cao nhưng không đủ tài lực, cũng không muốn bán thiên niên linh thảo để tránh phiền phức. Hàn Lập dành trọn một tháng nghiên cứu tập tính, nhược điểm yêu thú Ngoại Tinh Hải; một ngày tháng sau cầm ngọc giản cười lớn hưng phấn nhưng nội dung chưa lộ. Nửa năm sau, Hàn Lập cùng Khúc Hồn tới Tinh Không Điện tầng năm mươi, ghép nhóm năm tu sĩ do một phụ nhân Trúc Cơ hậu kỳ mời để chia phí truyền tống. Bạch y tu sĩ Tinh Cung thu bảy trăm linh thạch, phát Truyền tống phù bảo vệ rồi truyền tống thuận lợi tới Ngưng Thúy Đảo. Tại đảo, lão giả Kết Đan trong nhóm mời Khúc Hồn liên thủ săn yêu thú cấp sáu nhưng bị từ chối, đồng thời cảnh báo phải đề phòng bại hoại và tà tu đánh lén. Hàn Lập ra ngoài thạch ốc quan sát thấy một khu phố nhỏ tạm bợ với cửa hiệu sơ sài bố trí lộn xộn quanh điểm truyền tống."},{"chuong":394,"tieuDe":"Tu Sĩ, Yêu Thú, Tiểu Đảo","tomTat":"Hàn Lập đến cửa hiệu tạp hóa Phong Nhạc thương minh trên Ngưng Thúy Đảo mua Hải Vực Đồ tinh tế giá 100 linh thạch bậc trung dạng ngọc giản. Đại hán Kết Đan kỳ Hác Viễn Thiên cưỡi lục hồng hạ xuống bán thi thể Bích lân ngư yêu, nhiệt tình mời Hàn Lập và Khúc Hồn cùng đi bắt yêu thú nhưng bị Khúc Hồn lắc đầu cự tuyệt. Hàn Lập suy ngẫm về cục diện Ngoại tinh hải: tu sĩ kết nhóm nhỏ vì từng có tiền lệ toàn bộ tu sĩ một đảo ra biển bị yêu thú ngoài thất cấp vây công hủy cả đảo. Hàn Lập có kế hoạch riêng nên không nhập nhóm, cùng Khúc Hồn lên Thần Phong Chu rời Ngưng Thúy Đảo, toàn lực phi hành xuyên Ngoại tinh hải ba ngày, phóng thần thức mấy chục trượng cảnh giác. Cuối cùng đến một tiểu đảo toàn san hô đỏ — đích đến theo kế hoạch — mặt lộ vẻ mừng rỡ."},{"chuong":395,"tieuDe":"Nghê Thường Thảo","tomTat":"Hàn Lập cưỡi Thần Phong Chu tìm thấy Hồng Hô đảo gần hải vực Ngưng Thúy Đảo, dành hai ngày khám phá toàn đảo rồi quyết định lấy đây làm căn cứ sát yêu. Hắn sai Khúc Hồn bố trí ba đại trận — Điên Đảo Ngũ Hành, Thiên Phong Cuồng Liệt, Huyễn Hình Thiên La — trên ba con đường vào trung tâm, tự bày thêm tiểu trận phong bế bốn phía tạo thế thiên la địa võng. Hàn Lập lấy ra Nghê Thường Thảo, loại linh thảo mọc trên rạn san hô Loạn Tinh Hải có biệt danh Dụ Yêu Thảo — cứ hơn trăm năm giăng một lá phát mùi dẫn dụ yêu thú biển. Tu sĩ từng bỏ cuộc vì không nắm chính xác thời điểm giăng lá và cây mất kỳ hiệu nếu di chuyển trước trăm năm. Hàn Lập phá giới hạn bằng lục dịch tiểu bình: thí nghiệm tại động phủ cho thấy chỉ cần tích lục dịch vào, một đến bốn ngày cây giăng lá; thử với hai con Huyết Ngọc Tri Chu xác nhận chúng bị mùi dẫn dụ nhưng sau khi ăn sạch cây thì trở lại bình thường. Tại Hồng Hô đảo, hắn đặt gốc trăm năm tuổi lên rạn san hô trung tâm, tích một giọt lục dịch, đến ngày thứ ba cây bắt đầu giăng lá phát tán mùi, rồi cắm trận kỳ ngồi chờ yêu thú tự tới."},{"chuong":396,"tieuDe":"Sát Yêu Thủ Đan","tomTat":"Hàn Lập triển khai chiến dịch sát yêu tại Hồng Hô đảo trong Ngoại Tinh Hải. Hắn bày hai bộ Huyễn Hình Thiên La trận dùng trận kỳ tím và vàng bẫy đồng thời hai yêu thú ngũ cấp, rồi phối hợp Khúc Hồn (dùng Hỗn Nguyên Bát đã dung hợp) cùng hơn trăm Khôi Lỗi thú song trọng công kích phá vỡ phòng thủ của Thiên Mục Yêu, cuối cùng dùng Hồng tuyến độn quang châm kết liễu và thu được đan ngũ cấp hình cầu xanh biếc. Hàn Lập dùng Nghê Thường Thảo làm mồi thu hút, cứ hai ba ngày có yêu thú đến, hơn một tháng tiêu diệt hơn mười con. Khi Nghê Thường Thảo đạt bốn trăm năm tuổi dẫn đến lục cấp yêu thú Kê Quan Giao, Hàn Lập hoảng sợ phong ấn khí tức khiến nó bỏ đi, rút bài học chỉ nên thôi thúc đến ba trăm năm tuổi rồi thay cây non. Sau khi yêu thú quanh Hồng Hô đảo hết, hắn chuyển đảo tiếp tục, tổng cộng năm năm chém hàng trăm ngũ cấp yêu thú, thu mấy trăm khỏa đan và rất nhiều tài liệu quý. Khôi Lỗi thú tiêu hao còn hai ba mươi con, khí cụ trận pháp hư hại phần lớn. Nửa năm trước hắn vô ý dẫn đến thất cấp yêu thú, phải bỏ lại đại trận Điên Đảo Ngũ Hành vây tạm rồi cùng Khúc Hồn bỏ chạy, mất luôn bộ trận. Kỹ thuật thực chiến của Hàn Lập đạt xuất thần nhập hóa, có thể một mình thong dong đối phó ngũ cấp yêu thú thường."},{"chuong":397,"tieuDe":"Bế Phủ Khổ Tu","tomTat":"Hàn Lập cùng Khúc Hồn cẩn thận bay vài tháng từ sâu trong Ngoại Tinh Hải trở về Ngưng Thúy Đảo, mang theo mấy trăm khỏa yêu đan cấp năm trị giá hơn mười vạn linh thạch. Về tới động phủ tầng ba chín Thiên Tinh thành, hắn bế phủ hai năm thu thập đan phương và luyện nhiều lô đan dược lớn từ yêu đan kết hợp linh thảo, giải quyết được vấn đề kháng dược tính, đồng thời bán tài liệu yêu thú thừa thu lượng lớn linh thạch. Hắn thực hiện tán công tu vi theo Tam chuyển trọng nguyên công suốt nửa tháng, hạ tu vi xuống Trúc Cơ sơ kỳ. Thử nghiệm cho Phệ Kim Trùng ăn Nghê Thường Thảo đã được lục dịch thôi thúc, ngân cầu nứt ra, mấy trăm con trùng mắt hồng quang xông tới gặm sạch cây thảo, Hàn Lập phân phó Khúc Hồn định kỳ cho ăn tiếp. Sau đó hắn mang toàn bộ đan dược vào mật thất bế quan sinh tử, giao mọi việc động phủ cho Khúc Hồn điều khiển từ xa. Sáu mươi năm sau, bầu trời trên động phủ đột nhiên mây đen che kín, sấm chớp loạn vũ, linh khí hơn trăm dặm tụ về — dấu hiệu kết đan thành công, kinh động tu sĩ khắp vùng và các cường giả trong thành."},{"chuong":398,"tieuDe":"Kết Đan Dữ Pháp Bảo","tomTat":"Hàn Lập xuất quan sau 60 năm bế quan trong mật thất, tuyên bố Kết đan thành công, Kim đan đại thành, chính thức bước vào Kết đan kỳ với thọ nguyên 500-600 năm. Kim đan ngưng kết thành hạt châu nhỏ bằng ngón cái bốn màu tại đan điền. Trong thời gian bế quan, hắn hoàn thành nhị chuyển Tam chuyển trọng nguyên công trong hơn 30 năm nhờ đan dược phụ trợ, tu luyện thành Đại Diễn Quyết tầng thứ ba trong hơn 20 năm theo gợi ý của Lâm sư huynh, và Kết đan mất 5 năm. Hắn kiểm tra Phệ Kim Trùng đã đạt mấy vạn con với trùng xác bạc xuất hiện đốm vàng nhờ phương pháp nuôi bằng Nghê Thường Thảo qua nhiều đời cắn nuốt-đẻ trứng, quyết chờ thêm vài đời mới mang ra đại dụng. Hai con Huyết ngọc tri thù nhờ ăn Tự Linh Hoàn đã thăng lên yêu thú cấp bốn đỉnh phong, toàn thân trong suốt như ngọc, được thu vào túi linh thú. Hàn Lập giao pháp bảo Hỗn Nguyên Bát cho Khúc Hồn luyện hóa, giữ Lục Hoàng Kiếm tạm hộ thân, và lên kế hoạch thu thập tài liệu luyện chế Thanh Trúc Phong Vân Kiếm từ Kim hiệt."},{"chuong":399,"tieuDe":"Diệu Âm Môn","tomTat":"Hàn Lập vừa Kết Đan thành công, nhận hàng loạt truyền âm phù chiêu lãm khách khanh trưởng lão từ các tổ chức lớn nhỏ nhưng cự tuyệt hết, chỉ khách khí trả lời Kết Đan kỳ tu sĩ. Hắn dành thời gian củng cố cảnh giới, lui tới thỉnh giáo các Kết Đan kỳ tu sĩ lân cận, dùng Định Nhan Đan đổi vật phẩm trân quý. Song song đó, Hàn Lập luyện hóa Lục Hoàng Kiếm và muốn luyện Thanh Trúc Phong Vân Kiếm nhưng chưa tìm được dị chủng thần trúc nên tạm gác. Hắn chế tạo Khôi Lỗi tam cấp chất liệu gỗ, tốn linh thạch gần cạn kiệt, buộc phải bán tài liệu yêu thú cấp năm giải quẫn, vô tình bị người chú ý. Phạm Tĩnh Mai thuộc Diệu Âm Môn sai thiếu nữ Liên nhi chặn đường mời Hàn Lập, Liên nhi lén dùng mị thuật nhưng bị phát hiện ngay. Hàn Lập cự tuyệt lần đầu nhưng sau khi Phạm Tĩnh Mai đích thân xuất hiện xin lỗi và nói thẳng ý định mua tài liệu, hắn cuối cùng đồng ý đến Thanh Hà trà quán. Trong phòng tao nhã lầu hai đã có một lão giả áo xám bí ẩn ngồi sẵn pha trà, thấy Hàn Lập vào mà mi mắt không động."},{"chuong":400,"tieuDe":"Đạo Mạo Ngạn Nhiên","tomTat":"Phạm Tĩnh Mai dẫn Hàn Lập vào gặp Triệu trưởng lão — lão giả áo xám tu vi Kết đan sơ kỳ, đôi tai đỏ bất thường, dáng như mới khỏi bệnh. Hàn Lập cẩn thận từ chối uống trà người lạ. Phạm phu nhân thay mặt Diệu Âm Môn đề nghị mua toàn bộ tài liệu yêu thú, tiết lộ môn phái đã phát động lực lượng tại Thiên Tinh thành điều tra thói quen bán nhỏ lẻ của Hàn Lập. Hàn Lập tức giận nhưng cân nhắc lợi hại rồi đồng ý bán, nói ra số lượng kinh người khiến Phạm phu nhân vừa mừng vừa sợ. Sau khi Hàn Lập rời đi lấy hàng, Phạm phu nhân lộ bộ mặt thật âm trầm đáng sợ: bàn với Triệu trưởng lão cướp trắng tài liệu, nhưng lão phản đối vì đánh giá Hàn Lập pháp lực tinh thuần, cơ thể ẩn chứa bảo khí. Hai người chuyển sang kế hoạch nửa tháng sau lôi Hàn Lập xuống nước — thuận lợi thì mượn sức, không thì dùng hắn làm vật thế mạng. Phạm phu nhân tháo lụa che mặt lộ khuôn mặt đẹp điên đảo chúng sanh, dùng sắc dụ dỗ Triệu trưởng lão. Liên nhi bị đuổi ra ngoài, nghe lời đùa bỡn bên trong rồi thở dài rời đi."},{"chuong":401,"tieuDe":"Thiên Lôi Trúc","tomTat":"Hàn Lập rời trà lâu, dùng thần thức nghe trộm gian phòng Phạm phu nhân nhưng bị cấm chế chặn lại, đành từ bỏ. Hắn ngự kiếm về động phủ thu toàn bộ tài liệu yêu thú rồi mang Khúc Hồn trở lại trà lâu. Hàn Lập giao tài liệu cho Phạm phu nhân, qua kiểm tra và mặc cả, nhận linh thạch bậc trung, hai bên hài lòng. Khi chuẩn bị cáo từ, Phạm phu nhân dùng hồ mỵ chi công qua ánh mắt nhằm khống chế tâm thần Hàn Lập nhưng bị hắn phản kích bằng hàn ý, phun máu bị thương, bị khóa cứng không thể cử động. Triệu trưởng lão định can thiệp nhưng bị Khúc Hồn chặn lại bằng thân pháp quỷ dị. Sau đó Phạm phu nhân chủ động xin lỗi và tiết lộ tin tức về Thiên Lôi Trúc — một trong tam đại thần mộc vốn tưởng đã tuyệt diệt, từng được Diệu Âm Môn sở hữu nhưng bị cướp giữa đường đến Thiên Tinh thành. Diệu Âm Môn đã tìm ra hung thủ, đang chuẩn bị mời đồng đạo đánh bắt. Hàn Lập vô cùng hưng phấn vì đây chính là loại linh trúc hắn tìm kiếm để luyện chế pháp bảo."},{"chuong":402,"tieuDe":"Tả Hữu Song Sứ","tomTat":"Phạm phu nhân (Tả sứ Diệu Âm môn) kể cho Hàn Lập rằng hai tháng trước, Uông bang chủ dẫn hơn nửa cao thủ đi áp tải hàng hóa, giữa đường bị năm sáu tu sĩ Kết đan kỳ bịt mặt tập kích, Uông bang chủ tử trận, hàng hóa gồm thanh Thiên lôi trúc bị cướp sạch. Nàng đề nghị thuê Hàn Lập ra tay đoạt lại, thù lao là Thiên lôi trúc — linh vật chưa luyện hóa, có thể tiếp tục sinh trưởng, nghìn năm mới cao thêm một tấc. Hàn Lập từ chối điều kiện tỳ nữ nhưng yêu cầu thêm một kiện vật phẩm, Phạm phu nhân đồng ý. Hàn Lập về động phủ điều tra Diệu Âm môn qua tu sĩ lân cận, xác nhận đây là thế lực bậc trung, nổi tiếng nữ tu sĩ xinh đẹp và Hồ mỵ thuật, chưa có ác tích, bèn gia tăng luyện chế tam cấp khôi lỗi chuẩn bị. Nửa tháng sau, Hàn Lập nhận truyền âm phù, mang theo Khúc Hồn và hai đầu Huyết ngọc tri thù rời động phủ, thiếu nữ Liên nhi đợi ở cửa Thiên tinh thành dẫn đường tới đảo tập kết. Tại đảo, khoảng năm tu sĩ Kết đan kỳ cùng hơn mười Trúc cơ hậu kỳ chia thành hai nhóm: phe Phạm phu nhân và phe Trác Như Đình — Hữu sứ Diệu Âm môn, hai bên tỏ thái độ lạnh nhạt rõ ràng. Hàn Lập cảm thấy phong tư Trác Như Đình có gì đó hết sức quen thuộc, lâm vào trầm tư."},{"chuong":403,"tieuDe":"Xích Hỏa Lão Quái","tomTat":"Hàn Lập nhận ra phong vận Trác Như Đình gợi nhớ Nam Cung Uyển, giải tỏa cảm giác xao động nội tâm rồi khôi phục bình tĩnh. Phạm phu nhân và Trác Như Đình chờ thêm người, gần nửa ngày sau một đám mây đen khổng lồ có lôi điện xuất hiện — phi hành pháp khí của Xích Hỏa lão quái, tu sĩ ma đạo Kết Đan hậu kỳ từ Nguyên Quy Đảo. Từ đám mây bay ra nữ tử áo tím Uông Ngưng (Tử Linh tiên tử), con gái môn chủ Diệu Âm Môn đã bị giết. Nàng tiết lộ sào huyệt đối phương có thêm đầu mục Kết Đan hậu kỳ tọa trấn nên đã tự mình tới Nguyên Quy Đảo mời Xích Hỏa lão quái trợ giúp, đồng thời hứa nhường vị trí lãnh đạo Diệu Âm Môn cho hai sư tỷ sau khi báo thù. Mười đạo quang hoa bay hướng Bắc tới hoang đảo tập kết, nơi đệ tử cấp thấp Diệu Âm Môn đã chờ sẵn. Dọc đường tu sĩ họ Mạnh bay cạnh Hàn Lập tán gẫu, kể mình tham gia vì tiểu thiếp là thân truyền đệ tử Phạm phu nhân. Tử Linh tiên tử ra lệnh nghỉ ngơi, sáng sớm hôm sau sẽ đánh lén sào huyệt tà tu."},{"chuong":404,"tieuDe":"Quỷ Cục","tomTat":"Nhóm tu sĩ Diệu Âm Môn do Tử Linh tiên tử chỉ huy đột kích sào huyệt tạm thời của nhóm tà tu trên một tiểu đảo. Xích Hỏa lão quái phá ảo trận, Phạm phu nhân dẫn đầu tấn công gần năm mươi tà tu. Hàn Lập và Khúc Hồn dùng Lục Hoàng Kiếm, Hỗn Nguyên Bát diệt nhóm tà tu Trúc Cơ kỳ đã biến thân Sát yêu — thuật biến thân này khác Hắc Sát Giáo vì không cần niệm chú hóa kén và không có Huyết Ngưng Ngũ Hành Đan. Khi ba tà tu Kết Đan kỳ bị Xích Hỏa lão quái bao vây, môn chủ Ẩn Sát Môn — đại hán trung niên tu vi Kết Đan hậu kỳ — dẫn bốn Kết Đan sơ kỳ bay ra nghênh chiến, thi triển quỷ đầu thuật nuốt hỏa quang của Triệu trưởng lão. Triệu trưởng lão hoảng sợ bay về rồi hét lớn xúi giục mọi người đồng loạt tấn công. Hàn Lập nhận ra bất thường, cùng Khúc Hồn lùi về phía sau chuẩn bị thoát thân. Hai phe tạm ngưng chiến đối chất: Ẩn Sát Môn phủ nhận cướp hàng, Diệu Âm Môn phủ nhận giết vô cớ. Phạm phu nhân nhận ra có người trong song phương bày mưu hãm hại. Tử Linh tiên tử quay lại truy vấn Triệu trưởng lão và Phù trưởng lão, ám chỉ hai người chính là nội gian."},{"chuong":405,"tieuDe":"Phụ Thân Đại Pháp","tomTat":"Xích Hỏa lão quái phát hiện kẻ ẩn nặc, Ô Sửu (thiếu chủ Cực Âm đảo) hiện thân từ hắc khí và công khai thừa nhận toàn bộ âm mưu: cướp hàng Diệu Âm Môn, giết hai trưởng lão, giá họa Ẩn Sát Môn. Triệu trưởng lão và Mạnh trưởng lão bay sang phe Ô Sửu, thú nhận tính mạng bị nắm giữ, phản bội Diệu Âm Môn. Ô Sửu ngỏ lời cưới Tử Linh tiên tử bị cự tuyệt — nàng đặt điều kiện xử tử toàn bộ hung thủ giết mẫu thân, lộ mối thù sâu với Cực Âm đảo. Ô Sửu gọi thủ lĩnh Ẩn Sát Môn là Tôn sư thúc và dẫn dụ giao Hư Thiên tàn đồ nhưng bị từ chối. Đột ngột khuôn mặt Ô Sửu vặn vẹo biến thành lão già xấu xí — Cực Âm lão tổ dùng phụ thân thuật chiếm thân cháu mình, đích thân ra mặt. Người trung niên vạch trần lão tổ năm xưa coi đệ tử như nô lệ, trừu thần luyện hồn, tuyên bố phụ thân chỉ ba phần tu vi nên dám đối đầu. Cực Âm lão tổ cười trào phúng ám chỉ thực lực hiện tại đã khác xưa. Hàn Lập trù trừ giữa bỏ chạy và ở lại vì chưa rõ Thiên Lôi Trúc thật giả."},{"chuong":406,"tieuDe":"Thiên Đô Thi Hỏa","tomTat":"Cực Âm tổ sư phô diễn Thiên đô thi hỏa vừa luyện thành, tạo hỏa cầu đen như mực trước mặt mọi người. Tu sĩ mũi ưng họ Phong (Kết Đan kỳ, do Trác Như Đình mời) liều lĩnh hóa hoàng quang bỏ chạy, bị hắc diễm truy kích thiêu thành tro bụi trong nháy mắt, chỉ còn lại một kiện phi đao pháp bảo. Cực Âm tổ sư uy hiếp toàn bộ tu sĩ hai phe phải quy thuận Cực Âm đảo, lấy Cấm Thần bài yêu cầu mỗi người giao ba phần nguyên thần. Tử Linh tiên tử dùng cấm lệnh Tinh Cung và Thiên Tinh song thánh để dọa nhưng bị lão bác bỏ, cho rằng cấm lệnh là chuyện cũ và chỉ Thiên Tinh song thánh mới làm khó được lão. Trung niên nhân Ẩn Sát môn tiết lộ điểm yếu: lão ma chỉ phụ thân vào người khác nên ma hỏa dùng nhiều lắm vài lần, dùng nhiều thì thể xác bị phụ tự bạo chết, kêu gọi liên thủ. Tử Linh tiên tử phân công chiến đấu: trung niên nhân cùng Xích Hỏa lão quái đối phó Cực Âm tổ sư, còn lại liên thủ đánh nhóm phản đồ Triệu trưởng lão. Hàn Lập linh cảm bất ổn khi Cực Âm tổ sư không mang trợ thủ mà dám một mình đối đầu, lặng lẽ dặn dò Khúc Hồn rồi phóng xuất Lục Hoàng kiếm chuẩn bị chiến đấu."},{"chuong":407,"tieuDe":"Đảo Qua","tomTat":"Trung niên nhân hạ lệnh tấn công Cực Âm lão tổ, phe chính phái đồng loạt phóng pháp bảo nhưng lão ma thản nhiên dùng Thiên đô thi hoả phá đầu quỷ. Trung niên nhân xuất Hàn Lê châu biến bạch xà tấn công dữ dội, truyền âm nhờ Xích Hỏa phối hợp. Xích Hỏa lão quái bất ngờ trở giáo phóng lôi điện đánh chính trung niên nhân, lộ rõ đã cấu kết với Cực Âm lão tổ từ trước. Cực Âm nhân cơ dùng bàn tay hắc khí khổng lồ chộp Hàn Lê châu thu vào người. Phe chính phái tan rã bỏ chạy tứ tán, Hàn Lập và Khúc Hồn phản ứng nhanh nhất chạy trước. Ba nữ tu sĩ hợp pháp khí thành bia đá ba màu phi hành. Tu sĩ Kết Đan kỳ Ẩn Sát Môn xả thân liên thủ tấn công hai ma đầu, bị Cực Âm gọi là Sát Đan phân thân và thiêu chết ít nhất một người. Hàn Lập suy luận ra mối liên hệ giữa Huyền Âm đại pháp, Huyền Âm Kinh, cổ Truyền Tống trận, hài cốt ngũ sắc và lệnh bài đầu quỷ."},{"chuong":408,"tieuDe":"Yêu Thi","tomTat":"Hàn Lập và Khúc Hồn đang chạy trốn thì bị một yêu thi toàn thân bích lục khoác giáp sắt đen chặn đường — đây là luyện thi cấp cao do Cực Âm lão tổ tế luyện, không sợ pháp bảo thông thường, tốc độ dịch chuyển tức thì ngang La Yên bộ. Hàn Lập dùng Lục Hoàng Kiếm tấn công không hiệu quả, liền triệu hơn trăm thanh sắc cự hầu và hai Huyết ngọc tri thù phối hợp Khúc Hồn chiến đấu. Khúc Hồn thi triển Huyết Linh Toản xuyên thủng ngực yêu thi rồi biến huyết đao thành tử hỏa và hỏa xà tím, phối hợp lưới nhện của Huyết ngọc tri thù vây khốn yêu thi hai tầng. Hai người nắm cơ hội đào thoát hơn trăm dặm, ẩn thân dưới đất trên hòn đảo nhỏ vô danh. Cảnh chuyển sang Cực Âm tổ sư đang thảnh thơi cùng Xích Hỏa — đại hán áo đỏ tu sĩ Nguyên Anh kỳ — bên cạnh hơn mười yêu thi và một trung niên nhân hôn mê bị cắm châm lam. Cực Âm tiếc nuối vì để Tử Linh tiên tử chạy thoát, hứa tặng Xích Hỏa hai mươi nữ tu sĩ Cực Âm đảo bồi thường. Hai lão ma hé lộ trưởng lão Thiên Tinh cung đều đang bế quan, Thiên Tinh song thánh tu luyện Nguyên Từ thần quang bị giam lỏng tại Thiên Tinh thành mỗi năm chỉ rời nửa tháng, và nếu luyện thành thì Loạn Tinh hải sẽ thuộc về phe họ."},{"chuong":409,"tieuDe":"Chân Dung","tomTat":"Cực Âm tổ sư và Xích Hỏa lão quái bàn luận sau trận Thiên Đô Thi: chê bai công pháp Nguyên Từ Thần Quang chưa ai luyện thành, nhận xét nhóm Tử Linh tiên tử nhờ Mộc Long Bi (trấn phái chi bảo Diệu Âm Môn) hộ thể thoát nạn, và hai người lạ dùng hơn trăm Khôi Lỗi thoát thân là tà môn. Cực Âm tổ sư tiết lộ phụ thân chỉ thao túng được ít pháp lực, vẫn bị hạn chế. Sau khi Xích Hỏa lão quái cáo từ bay đi, Cực Âm tổ sư xòe tay lộ đoạn tơ nhện trắng, nhận ra là Huyết Ngọc Tri Thù, mừng rỡ cho rằng trời không tuyệt đường. Hắn chụp bắt trung niên tu sĩ nghịch đồ đã trộm Hư Thiên Tàn Đồ, mang về đảo. Hàn Lập ẩn dưới lòng đất một tháng rồi mang Khúc Hồn trở về Thiên Tinh Thành, buồn bực vì không lấy được Thiên Lôi trúc. Phát hiện Truyền âm phù của Phạm phu nhân trước cửa động phủ, nghe ẩn ý trong tay có Thiên Lôi trúc nên quyết định đến Long Hưng Khách Sạn. Tại phòng tầng ba, chỉ có hoàng sam nữ tử tự xưng Uông Ngưng nói đây là hình dáng thật của mình, Hàn Lập quan sát không thấy dấu vết huyễn thuật nhưng vẫn không tin đó là chân diện mục Tử Linh tiên tử."},{"chuong":410,"tieuDe":"Trưởng Lão","tomTat":"Tử Linh tiên tử gặp Hàn Lập và lập tức nhận ra Khúc Hồn là Thân Ngoại Hóa Thân (phân thân) của hắn, ngạc nhiên vì phân thân cũng đạt Kết Đan sơ kỳ. Nàng giải thích tình hình Diệu Âm Môn: kết đại cừu với Cực Âm đảo, hai đại trưởng lão Triệu và Mạnh đã phản bội, không dám trở về sơn môn, ba tỷ muội quyết định tạm dời vào Thiên Tinh Thành mua động phủ ở lâu dài. Tử Linh tiết lộ Diệu Âm Môn ban đầu lấy được hai đoạn Thiên Lôi Trúc, gia mẫu chỉ mang một đoạn đi bán, đoạn còn lại nàng giữ. Nàng đề nghị trao Thiên Lôi Trúc cùng ba trăm linh thạch mỗi năm để mời Hàn Lập làm khách khanh trưởng lão kèm đề nghị song tu, nhưng Hàn Lập từ chối vì không muốn bị câu thúc. Sau đàm phán, hai bên thỏa thuận Hàn Lập làm trưởng lão danh nghĩa — hưởng đãi ngộ nhưng không nhận mệnh lệnh, chỉ cần không phủ nhận; phân thân Khúc Hồn cũng được công bố là tu sĩ Kết Đan Kỳ riêng biệt. Tử Linh lấy ra hộp cao ngọc bán trong suốt không thuộc ngũ hành, dùng lục quang phá phong ấn thanh quang trên nắp, mở hộp cho Hàn Lập xem Thiên Lôi Trúc bên trong."},{"chuong":411,"tieuDe":"Bồi Trúc","tomTat":"Hàn Lập nhận Thiên Lôi Trúc (Bạch Lôi Trúc mấy ngàn năm) cùng lệnh bài trưởng lão khách khanh Diệu Âm Môn từ Tử Linh tiên tử, hoàn tất giao dịch. Sau khi Hàn Lập rời đi, ba nữ tu Diệu Âm Môn bàn bạc: Tử Linh tiên tử giải thích lợi ích của giao dịch, nhận xét Hàn Lập là khổ tu sĩ tâm chí kiên định không thể lung lạc, nhắc bài học gia mẫu bị phản bội khi dùng mị thuật mời tu sĩ cấp cao. Ba người quyết định tạm cùng quản lý nội bộ, chờ ai Kết Đan sẽ lập môn chủ. Hàn Lập tra ngọc giản tìm phương pháp bồi dưỡng Thiên Lôi Trúc, đem trúc vào dược viên dùng lục dịch từ bình thần bí tưới. Hắn dành hai năm đi khắp phường thị Thiên Tinh Thành thu thập tài liệu luyện bộ pháp bảo Thanh Trúc Phong Vân Kiếm, tiêu sạch linh thạch phải bán cả yêu đan. Sau thời gian bồi dưỡng, Bạch Lôi Trúc biến thành Kim Lôi Trúc vạn năm — cấp cao nhất trong tam đại thần trúc, phóng lôi điện vàng phá hủy pháp khí, khắc chế tà pháp ma công. Hàn Lập coi đây là lần chiếm tiện nghi lớn nhất từ khi bước vào tu tiên giới."},{"chuong":412,"tieuDe":"Thanh Trúc Tiểu Hiên","tomTat":"Hàn Lập dành mấy tháng tưới lục dịch cho Thiên Lôi Trúc vạn năm và phát hiện bên cạnh cây mẹ mọc ra ấu trúc mới, giải quyết hoàn toàn vấn đề thiếu nguyên liệu. Hắn nảy dã tâm luyện chế tối đa 72 thanh Thanh Trúc Phong Vân Kiếm thay vì 12 thanh ban đầu, dù tu vi Kết Đan Sơ Kỳ chưa đủ khu động hết. Hàn Lập lập kế hoạch tu luyện 20 năm gồm ba phương diện: học luyện khí, trận pháp, và ma luyện nhập thế tâm cảnh (yêu cầu bắt buộc của Đại Diễn Quyết tầng 4). Hắn cùng Khúc Hồn dịch dung đến phường thị Thiên Tinh Thành, mua lại tiệm Lý Thị Tạp Hóa đổi tên thành Thanh Trúc Tiểu Hiên, giả phàm nhân bán phù lục, dược tài và pháp khí cấp thấp tự luyện. Suốt ngày nghiên cứu Vân Tiêu Tâm Đắc và điển tịch trận pháp, quan sát đời sống phàm nhân. Định kỳ về động phủ chăm sóc Thiên Lôi Trúc, Phệ Kim Trùng và Huyết Ngọc Tri Chu. Khi ấu trúc thứ hai đạt 5-6 ngàn năm, cây mẹ vạn năm đột ngột rụng hết cành lá hóa lá vàng óng, thân xanh biếc được cất vào hộp Cao Ngọc bảo tồn."},{"chuong":413,"tieuDe":"Luyện Hóa","tomTat":"Hàn Lập hoàn thành hơn 20 năm nhập thế tại Thanh Trúc Tiểu Hiên, kinh doanh pháp khí và trung cấp phù lục, lĩnh ngộ tâm cảnh từ cuộc sống thế tục, nâng cao trình độ luyện khí và trận pháp. Từ năm thứ chín hắn tự lĩnh ngộ trận pháp đơn giản, bắt đầu luyện chế trận kỳ và trận bàn dựa trên tâm đắc của Tề Vân Tiêu và Tân Như Âm. Khi cây Thiên Lôi Trúc thứ sáu cuối cùng đủ vạn năm, Hàn Lập sang tay cửa hiệu, mang Khúc Hồn trở về động phủ. Hắn bố trí trận pháp quanh mật thất, ngồi ba ngày phục hồi tinh thần và pháp lực, rồi bắt đầu luyện hóa Thiên Lôi Trúc bằng đan hỏa xanh. Sau ba ngày phá được tầng điện hồ vàng nhạt bảo vệ bên ngoài, và hơn mười ngày liên tục loại bỏ tạp chất, cây trúc đầu tiên hóa thành lục dịch sền sệt to bằng nắm tay. Hàn Lập bắn mười đạo linh ti vào lục dịch, tách thành mười hai khối chất lỏng giống nhau phiêu phù trong không trung."},{"chuong":414,"tieuDe":"Thành Hình","tomTat":"Hàn Lập hoàn tất tinh luyện toàn bộ Thiên Lôi trúc thành lục dịch tinh khiết trong ba tháng, đóng vào hộp ngọc bạch ngọc rồi bố trí pháp trận mấu chốt trong mật thất suốt nửa tháng. Sau nửa năm trong mật thất, hắn ra ngoài phát hiện Phệ Kim trùng đã tiến hóa lần nữa nhờ Nghê Thường Thảo, kim ban chiếm non nửa thân, nhưng nhận ra lục dịch có hạn nên quyết định chỉ bồi dưỡng bộ phận nhỏ. Nghỉ ngơi một tháng, Hàn Lập chọn ngày hoàng đạo, thắp hương hai ngày rồi chính thức kích hoạt pháp trận luyện chế Thanh trúc phong vân kiếm. Pháp trận bắn ra 72 cột sáng bao phủ lục dịch, Hàn Lập dùng thần thức thao túng biến đổi lục dịch thành 72 phôi kiếm xanh biếc trong một ngày một đêm. Hắn cắn đầu lưỡi phun máu nhỏ huyết nhận chủ từng thanh, cho bột bạc và tài liệu phụ trợ hòa vào, rồi khắc pháp trận cỡ nhỏ lên mỗi thanh theo đồ hình trong Thanh Nguyên kiếm quyết dù bản thân không lý giải được nguyên lý."},{"chuong":415,"tieuDe":"Châu Trung","tomTat":"Sau hai tháng trong mật thất, Hàn Lập hoàn thành luyện chế 72 thanh Thanh Trúc Phong Vân kiếm — bổn mạng pháp bảo tốn hơn 20 năm tâm huyết, hút vào cơ thể và bắt đầu bồi luyện bằng đan điền chi hỏa mỗi đêm. Phệ Kim Trùng đẻ trứng, Hàn Lập lập trùng thất mới với Khống thần pháp trận, dùng tinh huyết nhận chủ, giữ lại gần ngàn trứng mạnh nhất, số còn lại nở được thu vào túi trữ linh thú và bắt đầu luyện điều khiển. Trong thời gian Hàn Lập nhập thế, Loạn Tinh Hải đại biến: Lục Liên điện cùng nhiều thế lực bị phản loạn đồng loạt trong một đêm, xuất hiện tin đồn Thiên Tinh song thánh tẩu hỏa nhập ma bị phế tu vi, Tinh Cung im lặng khiến lòng người hoang mang. Hàn Lập không quan tâm, xác lập kế hoạch tu luyện hướng tới Nguyên Anh kỳ. Tu sĩ Kết Đan kỳ Kim Thanh — bằng hữu thân thiết nhất — đến bái phỏng, đưa viên trân châu chứa bản đồ cổ dẫn đến cổ tu sĩ di chỉ bị đại trận bao phủ, mời Hàn Lập trợ giúp phá trận và hứa chia phần chiến lợi phẩm. Hàn Lập đang chần chờ cân nhắc."},{"chuong":416,"tieuDe":"Thổ Sơn","tomTat":"Kim Thanh mời Hàn Lập đồng hành thám hiểm di chỉ cổ tu sĩ trên Loạn Tinh Hải, Hàn Lập xin hai ngày suy nghĩ rồi đồng ý vì nhân tình và hứng thú. Ba người (Hàn Lập, Khúc Hồn, Kim Thanh) rời Thiên Tinh Thành phi hành nửa ngày đến hòn đảo hoang phương viên trên ngàn dặm toàn đất vàng, không cây cối không linh mạch. Vượt qua bão cát dữ dội, họ phát hiện tòa núi đất cao ngàn trượng có đại trận phong ấn cổ tu sĩ bao phủ sườn núi. Tại chân núi gặp nhóm Hồ Nguyệt gồm ba tu sĩ: Hồ Nguyệt (Kết Đan kỳ, cùng Kim Thanh phát hiện bản đồ cổ), Giản huynh (Kết Đan trung kỳ), và Thạch Điệp (Trúc Cơ kỳ, cao thủ trận pháp Hồng Nguyệt đảo, con gái Thạch chân nhân). Thạch Điệp kiêu ngạo đặt điều kiện chỉ phá trận không tham chiến và được chọn trước một món chiến lợi phẩm. Kim Thanh biết cô là con gái Thạch chân nhân (người từng có ân với hắn) nên lập tức đồng ý, truyền âm nhờ Hàn Lập chiếu cố."},{"chuong":417,"tieuDe":"Dĩ Trận Phá Trận","tomTat":"Hồ Nguyệt đề xuất thỏa thuận chia chiến lợi phẩm: Hàn Lập và Thạch Điệp phá trận thành công sẽ được chọn trước mỗi người một món, phần còn lại cả nhóm chia nhau. Cả nhóm bay đến sườn núi nơi đại trận cổ đại tồn tại, bao phủ bởi hoàng vụ dày đặc. Thạch Điệp nhận ra đây là trận pháp song thuộc tính Thổ–Phong, hưng phấn thử phá bằng nhiều pháp khí cổ quái nhưng đều thất bại, chỉ kính đồng vàng có chút tác dụng. Hàn Lập lấy mười cây trận kỳ nhiều màu bố trí thành thế Bắc Đẩu Lưỡng Nghi Trận trên không, mười cột sáng hợp nhất xạ xuống hoàng vụ. Hoàng vụ sôi trào chấn động rồi nổ tung tán loạn, tầng huyễn trận che mắt ngoài cùng bị phá. Thạch Điệp bỏ hết ngạo khí, thi lễ thành khẩn xin Hàn Lập chỉ điểm trận pháp. Hàn Lập thầm thừa nhận phương pháp dĩ trận phá trận hoàn toàn dựa vào cuốn tâm đắc mà Tân Như Âm tặng, trình độ trận pháp bản thân còn hạn chế. Sương mù tan lộ ra tầng hào quang vàng nhạt phạm vi hơn trăm trượng — đại trận thực sự vẫn chưa được phá."},{"chuong":418,"tieuDe":"Phá Trận","tomTat":"Nhóm Hàn Lập đến trước đại trận bảo vệ cột đá khắc cổ văn ở trung tâm cổ tu sĩ di chỉ, màn sáng vàng đục bao quanh với hào quang bảy màu bên trong, thần thức bị bắn ngược khi chạm vào. Hàn Lập nhận ra khí tức trận pháp có tà khí nhưng Thạch Điệp không phản ứng gì nên tạm yên tâm. Sau khi nghỉ ngơi một đêm trong thạch ốc tạm, Hàn Lập và Thạch Điệp bắt đầu phối hợp phá trận: Thạch Điệp giỏi phân tích nhược điểm, Hàn Lập dùng kỹ xảo phá trận từ điển tịch Tân Như Âm, hai người bổ sung cho nhau khiến tiến độ tăng vọt. Sau ba tháng, đại trận gần phá xong chỉ còn đạo cấm chế cuối cùng — màn sáng thu nhỏ đổi sang đỏ, hào quang bảy màu hóa thành vô số hỏa xà có cánh gọi là Sí Ác, yêu linh hỏa hệ cực hiếm phun Yêu Hỏa không kém Đan Hỏa và có thể cắn nuốt nguyên thần tu sĩ. Cấm chế cuối biến nơi đây thành Tam dương chi địa khiến Sí Ác vĩnh sinh bất diệt. Hàn Lập và Thạch Điệp phân phát pháp khí Thủy thuộc tính cho nhóm, cảnh báo tuyệt đối không dùng pháp bảo khác. Hàn Lập phóng hơn mười đạo trận kỳ và trận bàn màu lam bao quanh màn sáng đỏ, hình thành trận pháp sâm nghiêm chuẩn bị phá cấm chế cuối cùng."},{"chuong":419,"tieuDe":"Hồng Hoang Cổ Bảo","tomTat":"Khi Hàn Lập chuẩn bị kích hoạt trận pháp phá cấm chế trên hoang đảo, một quái nhân tu vi Kết Đan trung kỳ bay tới tự xưng đảo chủ, quát mắng bọn người phá cấm chế. Hồ Nguyệt đối chất chỉ ra hắn là đảo chủ tự phong vì lần trước tới đảo không gặp ai. Quái nhân tức giận dùng giỏ hoa trúc cổ quái phóng bạch khí vây khốn pháp bảo đối thủ, khiến phi đao Hồ Nguyệt gần mất linh. Hắn còn phun viên châu đen tự vỡ làm tổn thương nặng phi xoa của tu sĩ họ Giản. Tu sĩ họ Giản thất thanh nhận ra giỏ hoa trúc chính là Hồng Hoang Cổ Bảo — pháp bảo cổ tu sĩ luyện chế, không thể thu vào cơ thể, phải mang bên mình. Nhóm Hồ Nguyệt nảy sinh ý đoạt bảo, Kim Thanh dùng đại ấn trắng đàn áp song kiếm quái nhân, tu sĩ họ Giản phóng ba cây cờ đen phát tiếng quỷ khóc sói tru. Hàn Lập cố ý giấu chiêu bài sát thủ, chỉ biểu hiện bình thường bàng quan. Quái nhân xé áo lộ hai đầu lâu đen gắn trên ngực, niệm chú cổ quái, đầu lâu cắn đứt ngón tay hắn rồi bay ra nghênh chiến."},{"chuong":420,"tieuDe":"Phệ Kim Trùng Đích Uy Lực","tomTat":"Tu sĩ họ Giản điều khiển ba cây Hắc Kỳ (Hồng hoang cổ bảo) phóng hắc ti kết lưới chụp khô lâu quái nhân, nhưng bị lân hỏa thiêu rụi rồi cả ba cây bị khô lâu cuốn vào miệng cắn nát. Lôi hỏa của Hồ Nguyệt cũng bị khô lâu hút vào vô hiệu, Kim Thanh bị phi kiếm và giỏ hoa kìm giữ đại ấn trắng, phe Hàn Lập rơi vào thế bị động hoàn toàn. Hàn Lập quyết định xuất Phệ Kim Trùng lần đầu thực chiến, ném túi linh thú phóng hơn mười khối cầu kim ngân. Quái nhân vung Pháp luân đen đập nát khối cầu nhưng mảnh vụn hóa hàng ngàn Kim ngân giáp trùng bám vào cắn nuốt sạch Pháp luân đến khi biến thành hư không. Quái nhân hoảng sợ, triệu hồi khô lâu rồi chặt thêm hai ngón tay cho chúng nuốt, biến khô lâu thành quỷ đầu mọc sừng, răng dài, tóc đỏ, phun Bích Uyên Quỷ Hỏa mạnh hơn đan hỏa ba phần. Phệ Kim Trùng bị Bích Uyên Quỷ Hỏa phun trúng chỉ lăn lộn rồi bay lên không hề tổn thương, hai bên rơi vào giằng co. Cuối chương tiếng ông ông lớn hơn nhiều lần bất ngờ vang lên từ xa, quái nhân sắc mặt trắng bệch mất hết huyết sắc."},{"chuong":421,"tieuDe":"Phong Linh Trụ","tomTat":"Hàn Lập điều khiển đám trùng vân Phệ Kim Trùng bức hai đầu quỷ của quái nhân tự bạo, mất mấy trăm con trùng ở trung tâm nhưng đại bộ phận không việc gì. Quái nhân bỏ phi kiếm, thu giỏ hoa rồi quyết đoán bỏ chạy bằng độn thuật thần diệu. Hàn Lập dùng Lục Hoàng Kiếm truy đuổi không đủ nhanh, lần đầu bắn bảy thanh tiểu kiếm xanh biếc từ trong cơ thể hợp thành cự kiếm phi hành tốc độ gần gấp rưỡi, cùng Khúc Hồn đuổi kịp. Dùng pháp quyết phân hai thanh phi kiếm thành bốn đạo kiếm quang thật giả, phi kiếm cắm vào ngực quái nhân, hồ quang điện thiêu thành tro bụi. Hàn Lập thu chiến lợi phẩm gồm giỏ hoa pháp khí, túi trữ vật, cuộn tranh hồng quang bí ẩn và hắc khô lâu. Mở cuộn tranh xem thì ngây ngẩn nửa ngày, vẻ mặt thâm trầm nghi hoặc. Quay về hội hợp nhóm, phối hợp phá cấm chế cuối cùng, tiêu diệt toàn bộ Sí Ác. Cây cột đá kỳ lạ lộ ra — Thạch Điệp nhận ra đó là Phong Linh Trụ nhờ điển tịch pháp trận, giảng giải giá trị năm sáu ngàn linh thạch, khiến cả nhóm kinh ngạc."},{"chuong":422,"tieuDe":"Thất Hà Liên","tomTat":"Nhóm tu sĩ gồm Hàn Lập, Kim Thanh, Hồ Nguyệt, tu sĩ họ Giản và Thạch Điệp nhận ra cột đá là Phong Linh Trụ — pháp khí cổ chuyên phong ấn linh khí để bảo quản linh dược hoặc trấn áp yêu ma. Cả nhóm bàn bạc rồi quyết mạo hiểm mở ra, thỏa thuận nếu có yêu ma thì ai thu phục được sẽ sở hữu. Tu sĩ họ Giản tiết lộ công pháp mình có thần thông chuyên đối phó quỷ ma nhưng cần thời gian chuẩn bị, Thạch Điệp tự tin nhờ pháp bảo trừ ma do gia phụ cấp. Khúc Hồn chủ động dùng Cự Lực Phù xoay cột đá ba vòng rồi đẩy đổ, lộ ra cửa địa động với bậc thang đá trắng dẫn xuống lòng đất. Hàn Lập lưỡng lự lấy họa trục hồng quang ra nhìn với thần sắc đăm chiêu rồi mới theo xuống. Sau khoảng một khắc, nhóm tới đại sảnh ngầm rộng hơn 20 trượng, trần khảm Dạ minh châu, có hai cửa bán nguyệt hai bên chưa khám phá. Giữa sảnh có bộ hài cốt trắng tinh như ngọc bị mũi tên xanh biếc cắm xuyên đầu lâu, bên cạnh là ao nhỏ chứa dung dịch trắng sữa mọc một đóa hoa sen ba màu còn đang nụ với cầu vồng bảy màu phía trên. Hồ Nguyệt xác nhận đó là Thất Hà Liên — vật chỉ có trong truyền thuyết, tu sĩ họ Giản đánh giá đấu giá sẽ có giá trên trời, mắt tràn đầy tham lam."},{"chuong":423,"tieuDe":"Kịch Độc","tomTat":"Hàn Lập hỏi về Thất Hà Liên, Hồ Nguyệt giải thích đây là tiên gia chi vật trong truyền thuyết — phàm nhân dùng cải tử hồi sinh, tu sĩ ăn vào tu vi tăng mạnh lên một cấp. Nhóm Hồ Nguyệt sinh tâm tư bài xích Hàn Lập vì thực lực hắn quá mạnh, phân công tu sĩ họ Giản hái hoa và Thạch Điệp kiểm tra cấm chế mà không mời Hàn Lập tham gia. Kim Thanh do dự muốn phản đối nhưng cuối cùng im lặng. Tu sĩ họ Giản cố nhổ Thất Hà Liên nhưng hoa thụt xuống ao tạo lực hút kéo hắn ngã vào nước kịch độc — thi thể rữa nát nổi lên, toàn thân lộ xương trắng. Thạch Điệp bị nước bắn trúng mặt, da thịt ăn mòn xèo xèo, may mắn uống đan dược giải độc kịp. Hàn Lập chỉ ra đầu mối từ bộ hài cốt bên ao — tay phải đen một mảng, ngón trỏ bị cắn thiếu — kết luận thạch nhũ vốn không độc mà có người hạ độc. Hàn Lập bắn năm hỏa cầu thử hoa, Thất Hà Liên chui xuống nước, một bóng đen từ ao bay ra như mũi tên tấn công hắn."},{"chuong":424,"tieuDe":"Yêu Xà","tomTat":"Bóng đen từ ao phóng ra bị Hàn Lập dùng Lục Hoàng Kiếm đánh lui, lộ diện là Yêu Quan Xà đen dài ba bốn thước — mào trên đầu nó được người khác luyện chế thành hình dáng Thất Hà Liên giả, hào quang cầu vồng chính là yêu khí bảy màu. Thạch Điệp, Kim Thanh, Hồ Nguyệt hợp lực tấn công nhưng bị yêu châu bảy màu và yêu khí áp chế. Khúc Hồn dùng Huyết Linh Toản bắn xuyên thủng mào yêu xà, Hàn Lập khống chế Thanh Trúc Phong Vân Kiếm ghim chết đầu xà xuống tảng đá, cố ý không phóng Ích Tà Thần Lôi để giấu bí mật Thiên Lôi Trúc. Thạch Điệp chém đứt đôi yêu xà và thu lấy viên yêu châu bảy màu. Hàn Lập quan sát mũi tên xanh biếc ẩn hắc khí tà pháp trên bạch cốt, phân tích rằng đây là di chỉ tu sĩ cổ thật nhưng bảo vật đã bị kẻ khác cuỗm hết rồi mượn nơi bố trí cạm bẫy. Bất ngờ thi thể tu sĩ họ Giản bò ra từ ao, bị tà thuật thao túng lao vào tấn công, bị Hồ Nguyệt và Kim Thanh đánh nổ tung — nhưng đây là đòn nghi binh: ngay sau đó một cánh tay xương xẩu đâm xuyên bụng Hồ Nguyệt từ phía sau, năm ngón tay nắm chặt một viên đan màu lam nhỏ như hạt đậu."},{"chuong":425,"tieuDe":"Chi Dương Điểu","tomTat":"Hồ Nguyệt bị bạch cốt xuyên bụng từ chương trước, hồi tưởng cuộc đời từ bần hàn đến Kết Đan rồi đoạn khí chết — nhận ra phi đao thông linh hộ thể vô dụng trước bộ hài cốt người chết. Trong đại sảnh, Hàn Lập cầm bức họa đỏ rực phóng ra Chi Dương Điểu (chim yến lửa) tạo vòng lửa chống hắc vụ, Khúc Hồn bắn lửa tím hỗ trợ, Thạch Điệp dùng bảo châu trắng xua hắc khí, Kim Thanh bị bạch cốt đuổi sát. Tiếng quỷ khóc chói tai vang lên, Kim Thanh gầm rống thét kẻ ẩn mặt hiện thân khiến quỷ khóc ngừng và bạch cốt tan tành. Thạch Điệp thừa cơ bỏ chạy lên bậc thang nhưng bị quỷ trảo xanh biếc từ vách đá xuyên ngực, hút cạn máu thịt biến thành xác khô. Quái ảnh xanh biếc — bóng người trong suốt mắt đỏ máu — lộ diện sau khi Hàn Lập phóng Chi Dương Điểu khổng lồ phá cột đá ẩn thân. Quái ảnh nhận ra Hàn Lập dùng Khu Linh Thuật thất truyền tại Loạn Tinh Hải, tuyên bố cần một thi thể thích hợp và yêu cầu ba người phụng hiến. Tu vi quái ảnh áp đảo Kết Đan kỳ, bản chất chưa rõ là người hay quỷ."},{"chuong":426,"tieuDe":"Quỷ Trá","tomTat":"Hàn Lập ném bức họa Chi Dương điểu tấn công quái ảnh xanh biếc để dò thực lực, nhưng quái ảnh một quyền đánh tan tàn phách hỏa điểu, bức họa tự bốc cháy thành tro. Quái ảnh tuyên bố hứng thú với thân thể Hàn Lập và cho những người khác cút đi. Kim Thanh sợ hãi bỏ chạy, bị quái ảnh dùng xương vụn bạch cốt đâm thủng hộ thể, chết tại chỗ. Quái ảnh nhận ra Huyết Luyện thân quang trên Khúc Hồn, hỏi là môn hạ Cực Âm hay Cực Huyễn, nổi giận khi nghe Cực Âm tự xưng tổ sư, lộ ra chính là sư phụ của Cực Âm lão tổ. Quái ảnh dùng kế lừa Hàn Lập quay đầu rồi tấn công, Hàn Lập dùng chín thanh Thanh Trúc Phong Vân kiếm phát Ích Tà Thần Lôi đánh tan. Ngay sau đó Khúc Hồn mất khống chế, dùng Huyết Linh toản xuyên ngực Hàn Lập gây thương nặng, tiếp tục dùng Hỗn Nguyên Bát tập kích. Hàn Lập kịp bắt pháp quyết rút phân thần từ thân xác Khúc Hồn về cơ thể mình. Quái ảnh hóa ánh sáng nhập vào chiếm xác Khúc Hồn thành công, mở mắt đỏ như máu."},{"chuong":427,"tieuDe":"Huyền Hồn Luyện Yêu","tomTat":"Hàn Lập dán phù lam cầm máu vết thương do Huyết Linh Toản gây ra, triển khai chín thanh Thanh Trúc Phong Vân kiếm phòng bị. Hắn thử dùng Dẫn Hồn chung (có thấm máu Khúc Hồn) nhưng hoàn toàn vô hiệu — quái vật đã chiếm đoạt thân xác Khúc Hồn tuyên bố mình là chủ nhân gốc của Sát Đan nên cấm chế không tác dụng. Quái vật tự xưng thánh tổ, tiết lộ chính hắn truyền dạy Sát Đan và Phân Thân thuật cho hai phản đồ Cực Âm, Cực Huyễn, tu luyện công pháp Huyền Hồn Luyện Yêu cấp Nguyên Anh kỳ cho phép phụ thân tùy ý. Quái vật thi triển Huyền Hồn Ngưng Cốt thuật, triệu hồi bạch cốt dung nhập vào thân Khúc Hồn, biến hình thành thanh niên mi thanh mục tú với tu vi vượt Kết Đan sơ kỳ. Hàn Lập triển khai toàn lực: thả mấy ngàn Phệ Kim Trùng, triệu ba bốn mươi cự viên khôi lỗi, ngưng tụ chín thanh phi kiếm thành cự kiếm xanh biếc có điện hồ. Cự kiếm phá tan năm đạo hắc mang bán nguyệt của thiếu niên chỉ một kích, khiến đối thủ thần sắc đại biến. Thiếu niên nhận ra phi kiếm luyện từ Thiên Lôi Trúc và Hàn Lập không phải đệ tử Cực Âm/Cực Huyễn, đề nghị đàm phán nhưng Hàn Lập từ chối, tiếp tục tấn công. Thiếu niên vẫn bình tĩnh, dường như đã có đối sách."},{"chuong":428,"tieuDe":"Tiêu Sá","tomTat":"Thiếu niên lão quỷ Tiêu Sá phóng mũi tên pháp bảo Kim Lôi Trúc tà luyện đối đầu cự kiếm Thanh Trúc Phong Vân kiếm của Hàn Lập, chiếm thế thượng phong nhờ thời gian tế luyện dài hơn. Hàn Lập cân nhắc dù còn sát chiêu Phệ Kim trùng vẫn không chắc thắng, quyết định ngừng chiến. Hai bên thu pháp bảo chuyển sang đàm phán. Tiêu Sá đòi xem ngọc giản, dùng hắc xà và huyết quang mắt đọc rồi trả lại, xác nhận công pháp Hàn Lập không phải Huyền Âm Kinh hay ma đạo nhưng vẫn dè chừng vì Sát Đan phân thân. Hàn Lập thi triển Thanh Nguyên kiếm quyết cực hạn xuyên vách tường để chứng minh thân phận. Tiêu Sá tự xưng Huyền Cốt thượng nhân, tiết lộ đã sống hơn ngàn năm, tán Nguyên Anh tu Huyền Hồn đại pháp, mục đích là tìm hai nghịch đồ (trong đó có Cực Âm tổ sư) báo thù. Hàn Lập nổi hứng thú với Huyền Hồn đại pháp nhưng hai bên dò xét bế tắc, Tiêu Sá từ chối tiết lộ khuyết điểm pháp môn."},{"chuong":429,"tieuDe":"Tàn Đồ Tái Hiện","tomTat":"Huyền Cốt thượng nhân đấm vỡ khúc xương trắng ẩn trong cơ thể, thu được một mảnh tàn đồ dạng khăn gấm ố vàng, vui mừng cất vội rồi cảnh báo Hàn Lập nhanh rời đi và hóa huyết quang bay đi. Hàn Lập thu thập pháp bảo cùng túi trữ vật của nhóm Kim Thanh, thiêu hủy thi thể rồi rời đảo, trong lòng tức giận vì hóa thân Khúc Hồn bị Huyền Cốt đoạt đi nhưng bất lực. Kiểm tra mảnh tàn đồ của mình, phát hiện bản đồ mơ hồ trước đây biến mất, chỉ còn đồ án tiểu kiếm vàng luôn chỉ hướng Tây Bắc kèm hồng tuyến phát huỳnh quang, suy luận có giới hạn thời gian nên quyết định lập tức lên đường. Sau khi Hàn Lập rời đi một khắc, nghịch đồ của Huyền Cốt — một trung niên nhân da tái nhợt — đến đảo, phát hiện trận pháp bị phá, xuất mười hắc điểu dò xét trăm dặm không tìm được ai, tuyên bố bản thân đã vượt tu vi Kết Đan kỳ và chờ xong việc Hư Thiên điện sẽ truy bắt sư phụ, rồi phá hủy vùng động khẩu bay đi. Nhiều ngày sau Hàn Lập theo hướng Tây Bắc gặp đôi nam nữ đệ tử Diệu Âm môn đang bị ba tu sĩ Độc Long hội truy đánh, nữ tu nhận ra Hàn Lập và xưng là đệ tử thân truyền Trác hữu sử, cầu xin tương trợ."},{"chuong":430,"tieuDe":"Văn Tư Nguyệt","tomTat":"Hàn Lập dừng kiếm quang khi nghe tiếng gọi, được nữ tu sĩ Văn Tư Nguyệt — đệ tử Diệu Âm Môn, con gái Văn Tường — nhận diện qua bức hoạ chân dung trưởng lão tại Cung Phụng đường. Hàn Lập nhận ra Văn Tường, cố nhân từng gặp hai lần tại Khôi Tinh Đảo, nay đã trung niên tang thương, tu vi vẫn Trúc Cơ trung kỳ. Ba tu sĩ Trúc Cơ kỳ Độc Long hội lợi dụng lúc hai bên hàn huyên bỏ chạy, Hàn Lập phất tay phóng ba đạo Thanh Nguyên kiếm quang diệt gọn cả ba trong chớp mắt, ngầm hài lòng vì uy lực kiếm quang tăng theo tu vi Kết Đan. Văn Tường kể lại đời mình: sư phụ tọa hóa, mười năm mới Trúc Cơ, gia nhập Diệu Âm Môn làm đệ tử ngoại sự qua giới thiệu của vợ, vợ mắc bệnh lạ qua đời sau khi sinh con gái. Văn Tư Nguyệt hai mươi tuổi đã Trúc Cơ thành công, tư chất xuất sắc, từng kết đạo lữ song tu nhưng chồng sớm chết, trở thành góa phụ và từ chối mọi đề xuất song tu, đắc tội cao tầng Diệu Âm Môn. Nàng bị phái đi nhiệm vụ nguy hiểm hộ tống hàng quý qua lãnh địa Độc Long hội, tin tức bị rò rỉ dẫn đến hai cha con bị truy đuổi. Hàn Lập nhận ra Văn Tường muốn nhờ mình can thiệp nhưng quyết định không nhúng tay, cho rằng đó chỉ là lời phiến diện một phía, không vì chút giao tình mà làm loạn sự tình Diệu Âm Môn."},{"chuong":431,"tieuDe":"Hư Thiên Điện","tomTat":"Hàn Lập từ chối can thiệp chuyện nội bộ Diệu Âm Môn cho cha con Văn Tường, tự nhận chỉ là Trưởng lão danh nghĩa và hứa thuận tiện sẽ đề cập với Tử Linh nhưng không cam kết. Văn Tư Nguyệt tiết lộ sư phụ Trác Hữu sứ muốn nàng song tu với chí thân của sư phụ nhưng nàng cự tuyệt, khiến quan hệ sư đồ rạn nứt nên không thể nhờ giúp. Văn Tường hồi tưởng lúc quen biết Hàn Lập khi tu vi hai người tương đương, giật mình khi thấy bức họa Hàn Lập trong Cung phụng nội đường. Hàn Lập cáo từ bay đi theo bản đồ tìm tới vùng biển, phát hiện tòa cung điện bạch ngọc hùng vĩ cao trăm trượng lơ lửng trên không trung cao ngàn trượng, xung quanh bao bọc màn hào quang kim sắc. Ẩn nấp quan sát suốt bảy tám ngày, thấy nhiều tu sĩ Kết Đan cầm địa đồ bằng lụa bay vào. Rót linh lực vào địa đồ tạo linh quang bạch sắc bao bọc thân xuyên qua màn hào quang tiến vào Hư Thiên Điện. Đi qua thông đạo bằng ngọc có cấm chế chặn thần thức hoàn toàn, tới đại sảnh rộng lớn với mười ngọc trụ khổng lồ, nhận ra một số tu sĩ Kết Đan quen mặt đã có mặt sẵn."},{"chuong":432,"tieuDe":"Cực Âm Tổ Sư","tomTat":"Hàn Lập vào đại sảnh Hư Thiên điện, nhận ra Huyền Cốt thượng nhân ngồi ở một góc, Tử Linh Tiên Tử (Diệu Âm môn) đứng cùng nam tử áo xanh mang địch ý, và Miêu trưởng lão vẫn giữ hận về vụ Cổ trưởng lão. Hắn phán đoán hai vị Nguyên Anh kỳ: lão nho sinh áo vàng Nam Hạc đảo và Ôn phu nhân Bạch Bích sơn. Huyền Cốt truyền âm đề nghị hợp tác đoạt bảo vì cả hai đều có Hư Thiên tàn đồ, Hàn Lập không cự tuyệt. Cực Âm tổ sư cùng Ô Sửu bước vào đại sảnh khiến Hàn Lập và Huyền Cốt kinh hãi, Cực Âm tổ sư lộ vẻ vui mừng bất thường khi nhìn khuôn mặt Hàn Lập. Qua đối thoại giữa các Nguyên Anh kỳ, lộ ra Hư Thiên điện 300 năm mới mở một lần, bên trong có Thọ Nguyên quả luyện Trường Sinh đan, và Man hồ tử (Nguyên Anh kỳ thọ nguyên sắp cạn) cũng sắp đến."},{"chuong":433,"tieuDe":"Cửu Khúc Linh Sâm","tomTat":"Hàn Lập suy tính có nên ở lại Hư Thiên điện hay rời đi, nhận định nơi này giống Huyết sắc thí luyện ở Việt quốc, bảo vật nhiều nhưng nguy hiểm cũng lớn. Huyền Cốt thượng nhân chủ động truyền âm giễu cợt Hàn Lập về thái độ của Cực Âm tổ sư, bị Hàn Lập uy hiếp ngược sẽ tiết lộ bí mật cho Cực Âm biết. Huyền Cốt đưa ra đề nghị liên thủ diệt Cực Âm — gọi hắn là nghịch đồ, tiết lộ năm xưa Cực Âm phản bội hại mình phải chuyển sang quỷ đạo và phá hỏng con đường luân hồi. Huyền Cốt tiết lộ bí mật Cửu Khúc Linh Sâm — tiên thảo truyền thuyết tồn tại ở cửa thứ hai Hư Thiên điện, bản thể linh thảo nhưng có thể biến hình thành động vật côn trùng, am hiểu độn thổ độn mộc, điều chế thành linh dược tăng tỷ lệ ngưng kết Nguyên Anh. Hàn Lập phân tích tu vi Kết Đan sơ kỳ chênh lệch quá lớn với Nguyên Anh kỳ, cuối cùng chấp nhận giao kèo nhưng ý thức rõ quan hệ sẽ tan vỡ khi Cực Âm bị diệt. Cực Âm tổ sư cùng Ô Sửu bay đến hàn huyên với Thanh Dịch cư sĩ, nói chuyện với Ôn phu nhân nhưng bị phớt lờ, vẫn nói cười bình thường hiển lộ tâm cơ thâm sâu. Hàn Lập ngồi luyện khí, phát hiện đại sảnh có cấm chế khiến pháp lực tiết ra ngoài không thi thuật được, sau năm sáu ngày tu sĩ tụ đến hơn trăm người."},{"chuong":434,"tieuDe":"Tụ Tập","tomTat":"Những ngày tiếp theo tu tiên giả đến ngày càng thưa thớt, Cực Âm tổ sư và nho sinh lão giả liên tục đợi ai đó. Buổi chiều, hai cao nhân chính đạo Thiên Ngộ Tử và một lão nông bước vào, đối đầu bằng lời với phe ma đạo. Vạn Thiên Minh — môn chủ Vạn Pháp môn, nhân vật đầu lĩnh chính đạo Loạn Tinh hải — xuất hiện với khí thế áp chế Cực Âm, giải quyết chất vấn của Ôn phu nhân bằng cách nhắc tôn phu Lục Đạo. Man Hồ Tử (ma đạo) cuối cùng cũng đến, rung chuyển đại sảnh, khiêu khích Vạn Thiên Minh muốn đọ sức nhưng chưa ra tay. Man Hồ Tử đuổi Hàn Lập khỏi cột ngọc chiếm chỗ, Hàn Lập bị khinh nhục nhưng lý trí nén lại vì không chắc cấm chế hạn chế được tu sĩ Nguyên Anh. Phe ma đạo bàn luận: Man Hồ Tử muốn lấy nguyên liệu luyện Trường Sinh đan, suy đoán Thọ Nguyên quả đã trưởng thành có thể là mục tiêu của Vạn Thiên Minh, Cực Âm lo Vạn muốn lấy Hư Thiên đỉnh nhưng nho sinh lão giả bác bỏ."},{"chuong":435,"tieuDe":"Hư Thiên Đỉnh, Bổ Thiên Đan","tomTat":"Cực Âm tổ sư bàn mưu với Man Hồ Tử và Thanh Dịch cư sĩ, đề nghị liên thủ ma đạo chiếm Hư Thiên đỉnh trong nội điện: hắn giữ Hư Thiên đỉnh cùng một viên Bổ Thiên đan, chia cổ bảo còn lại. Man Hồ Tử bị vạch trần cũng có dã tâm, cuối cùng đồng ý đi theo nếu chính đạo vào nội điện. Cực Âm tiết lộ Bổ Thiên đan là thứ duy nhất trong Tu tiên giới có thể bù đắp ngũ hành linh căn, phục dụng đột phá giới hạn tuổi tác. Ôn phu nhân — phu nhân của đại ma đầu Lục Đạo cực thánh — lạnh lùng cự tuyệt lời mời, chỉ đến hái linh dược. Hai chấp pháp Tinh Cung đại diện hai thánh chủ (đang bế quan) xuất hiện, tuyên bố quy tắc: cấm giết người đoạt bảo ở ngoại điện, vi phạm bị truy sát; không can thiệp nội điện. Hàn Lập ngồi trong góc quan sát, mừng thầm vì các lão quái dây dưa nhau, có cơ hội đục nước béo cò. Huyền Cốt thượng nhân truyền âm cảnh báo: Tinh Cung chuyên chèn ép bên mạnh duy trì cân bằng, mỗi lần tầm bảo đều có tu sĩ chết bí ẩn nghi do Tinh Cung hạ độc thủ, dặn Hàn Lập bảo trọng."},{"chuong":436,"tieuDe":"Tử Linh Tái Ngộ","tomTat":"Hàn Lập tin lời cảnh báo của Huyền Cốt thượng nhân về mưu đồ của Tinh Cung, đề cao cảnh giác. Trong ba ngày chờ đợi, hai trưởng lão áo trắng Tinh Cung ngồi luyện khí bất động, thêm vài tu sĩ mới đến. Sáng ngày thứ tư, cửa đá bạch ngọc sập xuống phong bế đại sảnh, truyền tống trận chu vi mười trượng hiện ra trên sàn. Hai trưởng lão kiểm tra trận pháp, tuyên bố mọi người tự lo lấy thân rồi truyền tống đi trước. Cực Âm lão tổ nhìn Hàn Lập bằng ánh mắt hàn ý, hé lộ với Ô Sửu rằng Hàn Lập có tác dụng lớn đối với lão nhưng không nói rõ. Các tu sĩ lần lượt truyền tống rời đi. Hàn Lập truyền tống ra ngoài gặp lại Tử Linh tiên tử đã Trúc cơ hậu kỳ. Tử Linh kể tư chất không tốt, thất bại kết đan, phải mua Hư Thiên Tàn Đồ giá cao để vào đây tìm linh dược, quyết chỉ qua cửa đầu tiên. Hàn Lập nhớ nợ nhân tình từ Thiên Lôi Trúc và linh thạch Diệu Âm Môn nên đồng ý chiếu cố, nhưng cảnh báo nếu bất trắc phải tự lo. Tử Linh toát ra khí chất ôn nhu khiến Hàn Lập ngẩn ngơ mặt thoáng đỏ."},{"chuong":437,"tieuDe":"Đề Hồn","tomTat":"Tử Linh bất chợt tỏa vẻ yểu điệu khiến Hàn Lập giật mình, nhưng Đại Diễn quyết không phản ứng nên hắn loại trừ khả năng mị công. Lão giả áo xám Cát Lạp từ Thiên Thai Đảo chủ động đề nghị ba người liên thủ vượt qua vùng quỷ vụ trong Hư Thiên Điện, cảnh báo nơi đây đã từng có tu sĩ Kết đan bỏ mạng. Tử Linh giải thích nguồn gốc quỷ vụ là oán hồn tu sĩ chết tại điện tích tụ qua nhiều lần mở, và lần trước đã xuất hiện một Quỷ Vương cực mạnh giết sạch cả nhóm. Tu sĩ áo đen ma đạo lạnh lùng từ chối liên thủ cả Cát Lạp lẫn Hàn Lập, một mình xông vào quỷ vụ và triệu hồi linh thú Đề Hồn — con khỉ nhỏ lông xanh lục có năng lực dùng mũi hút quỷ hồn rồi luyện hóa. Cát Lạp kinh hãi nhận ra Đề Hồn thú và cảnh báo khi nó xuất hiện sẽ khiến tu tiên giới đại loạn, nhưng Hàn Lập không đồng tình, cho rằng cái loạn ở Loạn Tinh Hải vốn đã không thể tránh khỏi."},{"chuong":438,"tieuDe":"Quỷ Vụ Di Hài","tomTat":"Hàn Lập bày tỏ thẳng thắn không tin thuyết thiên mệnh, khiến Tử Linh tiên tử và Cát Lạp xấu hổ. Ba người lợi dụng người áo đen mang Đề Hồn mở đường, lần lượt tiến vào quỷ vụ — cửa ải đầu tiên của Hư Thiên Điện. Mỗi người triển khai phòng ngự riêng: Cát Lạp dùng ô hồng sắc, Tử Linh dùng bốn viên châu kết giới, Hàn Lập dùng hộ thể kiếm thuẫn của Thanh Nguyên Kiếm Quyết trải kiếm khí Thanh Trúc Phong Vân Kiếm phòng hộ, cố ý giữ điện quang trắng che giấu Kim Lôi Trúc. Sâu trong quỷ vụ, Hàn Lập giẫm phải bộ bạch cốt mặc áo lóe thanh quang bên cạnh kiếm gãy còn linh tính. Cát Lạp bắn hỏa cầu thử Ích Hỏa Bảo Y, xác nhận di hài là Ngọc chân nhân — tu sĩ Kết Đan sơ kỳ sắp lên trung kỳ, sở hữu dị linh căn hiếm, tu băng hệ công pháp, pháp lực cao hơn Cát Lạp nhiều, đã vào Hư Thiên Điện lần trước nhưng không trở về. Hàn Lập suy luận phụ cận có mối nguy lợi hại tiềm ẩn vì dọc đường quá yên tĩnh bất thường, trịnh trọng cảnh báo đồng hành."},{"chuong":439,"tieuDe":"Quỷ Vương (1)","tomTat":"Hàn Lập phân tích lệ quỷ vùng này gần cảnh giới Quỷ Vương, tu sĩ Kết Đan trung kỳ cũng bỏ mạng tại đây. Cát Lạp thừa nhận mục đích chỉ là Thọ Nguyên Quả, đánh giá nguy hiểm quá lớn nên ôm quyền từ biệt rồi theo đường cũ rút lui. Hàn Lập thu Ích Hỏa Bảo Y từ hài cốt rồi dùng kiếm quang đào hố chôn cất toàn bộ đồng đạo. Tử Linh kể chi tiết về Hư Thiên Điện: cứ 300 năm hạ xuống Loạn Tinh Hải, nội điện chứa bảo vật thực sự nhưng phải vượt ba cửa ải cực khó, bảo vật phần lớn đã bị tu sĩ Nguyên Anh thu gom. Hai người tiếp tục đi, Hàn Lập dùng thần thức phát hiện người áo đen đang kịch chiến với yêu quỷ phía trước và chủ động tiến lên. Tiếng quỷ khóc ai oán phát ra tác động mạnh vào tinh thần, Tử Linh bị ảnh hưởng nặng nề hai lần liên tiếp, hoa mắt choáng váng kinh hãi tột độ. Hàn Lập bị phát hiện đứng im giơ hai tay lên trong tư thế bất thường."},{"chuong":440,"tieuDe":"Quỷ Vương (2)","tomTat":"Tử Linh tiên tử nhận ra âm thanh tấn công tinh thần là Câu hồn quỷ âm — cao giai quỷ dị pháp thuật khiến đối thủ tu vi thấp nghịch chuyển máu huyết đến chết — và suýt bị mê hoặc tiến về phía tiếng gào thét, nhưng được Hàn Lập phát ra âm thanh chấn động tâm trí cứu thoát kịp thời. Hai người quan sát trận chiến phía trước: quỷ ảnh dùng lục châu phun Huyền Âm hàn khí áp chế phi chuỳ màu hồng của người áo đen, trong khi hai Quỷ Dạ Xoa — cương thi hiếm thấy toàn thân lông xanh, đầu có sừng — kìm chân Đề Hồn thú không cho hỗ trợ chủ nhân. Tử Linh nhận diện Quỷ Dạ Xoa từ sách cổ và giải thích cho Hàn Lập, khiến hắn cảm thán kiến thức nàng phong phú, tự nhận mình là tán tu thiếu điển tịch và dự định khi trở về sẽ tận dụng tư cách Trưởng lão Diệu Âm môn để nghiên cứu bí tịch. Hàn Lập lạnh lùng đứng nhìn suốt trận chiến, chờ đúng lúc quỷ ảnh hoá ô quang tấn công người áo đen mới bất ngờ phóng kiếm khí xanh buộc quỷ ảnh lùi, đồng thời phóng mười đạo thanh quang đánh lén hai Quỷ Dạ Xoa. Người áo đen thừa dịp thu hồi phi chuỳ và hoá hồng quang bay về phía Hàn Lập, nhưng một bóng hình người màu xám vô hình từ sương mù xuất hiện chặn đường, hắn không kịp tránh né, kinh hãi tràn ngập."},{"chuong":441,"tieuDe":"Quỷ Vương (3)","tomTat":"Khi quỷ ảnh xám sắp xuyên thủng hắc y nhân, bạch quang hình cự điểu lóe lên từ gương đồng cổ trong người hắn, xua quỷ ảnh thối lui, nhưng gương nứt vỡ thành phế phẩm. Bảy tám con Vĩ Ngô quỷ hiếm gặp (thực lực ngang Trúc Cơ hậu kỳ) xuất hiện từ sương mù bao vây ba người. Hàn Lập chủ động nhận đối đầu hai quỷ ảnh mạnh nhất, lệnh hắc y nhân và Tử Linh tiên tử câu giờ với đám Vĩ Ngô quỷ. Hàn Lập thả Phệ Kim Trùng hộ vệ, dùng Thanh Trúc Phong Vân kiếm hóa Thanh Giao phá tan Huyền Âm ma khí vây khốn từ quỷ châu, miễn nhiễm hoàn toàn khiến quỷ ảnh đen kinh ngạc. Quỷ ảnh đen kích hoạt quỷ châu biến thành yêu hổ đen khổng lồ — khí linh phong ấn bên trong. Cơ chế Khí linh được giải thích lần đầu: mỗi pháp bảo chỉ có một cơ hội phong ấn nguyên thần yêu thú, thất bại không có lần hai. Hàn Lập hồi tưởng Nam Cung Uyển từng thu nguyên thần Mặc giao để phong ấn khí linh, bản thân dù giết nhiều yêu thú vẫn chưa tìm được linh giao phù hợp. Đề Hồn thú nuốt một Vĩ Ngô quỷ nhưng bị quỷ dạ xoa dây dưa. Hàn Lập quyết thử sức yêu hổ khí linh trước khi tính bước tiếp."},{"chuong":442,"tieuDe":"Quỷ Vương (4)","tomTat":"Hư ảnh giao long do hai thanh Thanh Trúc Phong Vân kiếm hóa thành bị quang cầu đen của cự hổ đánh tan, linh tính tổn thương, Hàn Lập thu về tĩnh dưỡng. Hắn thả bốn thanh phi kiếm khác, dùng pháp quyết phân thành tám thanh tụ thành cự kiếm xanh vài trượng, phun chân nguyên biến thành dải lụa xanh hơn mười trượng chém nát nhiều quang cầu nhưng quang cầu vẫn tuôn ra vô tận. Quỷ ảnh đen phát tiếng kêu kích hoạt yêu hổ mọc thêm đầu thứ hai thành quái hổ hai đầu, yêu khí tăng mạnh. Quỷ ảnh xám dùng ẩn thân thuật lặng lẽ tiếp cận sau lưng Hàn Lập định bóp nát kim đan, nhưng bị đàn giáp trùng Phệ Kim Trùng tự động phát hiện bao vây cắn nuốt bất chấp mọi biến hóa. Hàn Lập ném thêm hai túi linh thú cho phi trùng gia nhập tiêu diệt quỷ ảnh xám. Quỷ ảnh đen nghe tiếng kêu cứu, quyết định biến thành quỷ vụ đen nhập vào yêu hổ hai đầu — thi triển Phụ Linh thuật dung hợp tạo thân thể nửa người nửa hổ. Hàn Lập nhận ra mật thuật này và kinh hãi vì lần đầu thấy yêu quỷ tu luyện Phụ Linh thuật trên khí linh của chính mình."},{"chuong":443,"tieuDe":"Quỷ Vương (5)","tomTat":"Phệ Kim trùng cắn nuốt hơn phân nửa quỷ ảnh xám, nhưng quái hổ hai đầu phát tiếng cười quái dị chấn bay đàn trùng rơi rụng nửa chết nửa sống, Hàn Lập phải thu chúng vào túi linh thú. Quỷ ảnh xám tàn dư không bỏ trốn mà chủ động bay về phía quái hổ, bị đầu hổ đen nuốt chửng và hợp nhất, khiến quái vật mọc thêm đầu hổ xám thứ ba mang khuôn mặt phụ nữ, hình thể phình to như tòa lầu hai ba tầng. Hàn Lập đánh giá quái vật thực lực tối thiểu Kết Đan hậu kỳ, nghi là Quỷ vương. Hắn tung hơn trăm cự viên khôi lỗi phối hợp Thanh Trúc Phong Vân kiếm tổng công kích, phi kiếm được tăng tốc ba phần phá phòng ngự thành công nhưng bị quái vật tay không chụp giữ, đầu giữa phun hắc khí ăn mòn linh quang trên thân kiếm. Tử Linh tiên tử dùng bia đá phòng ngự, hắc y nhân mất pháp bảo nên không chiếm thượng phong, cả hai chiến đấu riêng không chú ý Hàn Lập. Nhận ra không thể dây dưa, Hàn Lập quyết mạo hiểm tốc chiến, bắt kiếm quyết kỳ quái chưa từng dùng điểm về phía phi kiếm."},{"chuong":444,"tieuDe":"Hắc Bào","tomTat":"Hàn Lập kích hoạt Ích Tà thần lôi trên bốn thanh phi kiếm Kim Lôi Trúc, phóng hơn mười đạo điện hồ vàng nhạt kết lưới rồi bùng nổ bạch quang, tiêu diệt hoàn toàn hổ yêu ba đầu có thực lực vượt Kết Đan hậu kỳ. Viên châu ba màu rơi ra bị Hàn Lập chém vỡ, ba đạo hắc khí chủ hồn yêu quỷ thoát ra liền bị thiêu sạch bằng hỏa cầu, nhận ra bẫy tranh đoạt xá mà không mắc mưu. Bốn thanh kiếm Kim Lôi Trúc hết lôi điện biến mất cần tu dưỡng, bốn thanh còn lại bay vào cơ thể hắn ngủ say. Tử Linh tiên tử và hắc bào nhân đang giao đấu chỗ khác cũng kinh ngạc, đám Vĩ Ngô quỷ và dạ xoa bỏ chạy tán loạn, Đề Hồn thú thừa cơ nuốt một con. Hắc y nhân lần đầu lên tiếng hỏi về bạch quang, bị Hàn Lập vạch trần là nữ tu giả giọng. Hắc bào nữ tu xấu hổ gỡ mũ lộ gương mặt cực kỳ xinh đẹp, da trắng tuyết, tóc đen xõa vai, trán đeo vòng vàng, lạnh lùng diễm lệ. Tử Linh kinh diễm trước nhan sắc nữ tu, trộm liếc Hàn Lập thấy hắn nhìn chằm chằm nữ tử với thần sắc cổ quái, trong lòng không thoải mái."},{"chuong":445,"tieuDe":"Nguyên Dao","tomTat":"Hàn Lập nhận ra mỹ nữ áo đen chính là Nguyên Dao, người từng gặp ở Thiên Đô nhai Khôi Tinh đảo hơn trăm năm trước. Sau khi hắn nhắc lại chi tiết cũ về Khúc Hồn và Nghiên đạo hữu, Nguyên Dao dần nhớ ra và hai bên giải tỏa hiểu lầm. Hàn Lập thầm đánh giá Nguyên Dao tu một mạch từ Luyện Khí kỳ lên Kết Đan sơ kỳ trong hơn trăm năm, suy đoán nàng có tư chất hơn người hoặc gặp kỳ ngộ lớn. Ba người rời quỷ vụ đến khu hoa viên nơi hơn ba mươi tu sĩ tập kết, đa số mang thương tích; nhóm Nguyên Anh kỳ gồm Cực Âm tổ sư và Vạn Thiên Minh ngồi riêng hai ngọc đình, hai bạch y trưởng lão Tinh Cung ngồi giữa. Một nam tu sĩ trẻ áo xanh bí ẩn bước ra từ quỷ vụ hoàn toàn không tổn thương, nhìn Cực Âm tổ sư lộ vẻ oán độc thoáng qua rồi đứng riêng dò xét mọi người, nhíu mày khi không thấy Hàn Lập. Trong đầu hắn vang lên thanh âm hùng hậu lười biếng của một thực thể bí ẩn hỏi về trợ thủ và chế nhạo rằng người đó bị lệ quỷ nuốt, hắn tức giận bảo im vì sợ bị tu sĩ Nguyên Anh kỳ cảm ứng."},{"chuong":446,"tieuDe":"Tề Tụ","tomTat":"Huyền Cốt thượng nhân ngồi bên ngoài quỷ vụ, đối thoại trong đầu với đồng minh bí ẩn — một thực thể quỷ đạo đã giao tinh phách cho hắn, đổi lại Huyền Cốt hứa tìm thân thể thích hợp để cùng đối phó nghịch đồ Cực Âm. Huyền Cốt cảnh báo đồng minh rằng có ba bốn tu sĩ Nguyên Anh kỳ với pháp bảo khắc chế quỷ đạo, đồng thời tiết lộ Hàn Lập tuy chỉ Kết Đan sơ kỳ nhưng sở hữu phi kiếm Kim Lôi trúc ngoài Diệt Ma tiễn, nhiều thủ đoạn khó đối phó. Cực Âm lão tổ nhấp nhổm bất an vì thứ trên người Hàn Lập là mấu chốt đoạt bảo, bị nho sinh lão giả ngồi bên dò xét, phải che giấu. Cuối cùng Hàn Lập, Nguyên Dao và Tử Linh tiên tử sóng vai thoát quỷ vụ, là nhóm muộn nhất. Lý huynh vội vàng chạy tới hỏi thăm Tử Linh. Nguyên Dao đi theo Hàn Lập xin đồng hành vì pháp bảo tổn thất nặng sau đại chiến Quỷ Vương, nhưng Hàn Lập cự tuyệt, yêu cầu nàng giải thích rõ mục tiêu, số cửa ải định vượt và ẩn tình phiền phức trên người trước khi cân nhắc."},{"chuong":447,"tieuDe":"Không Gian","tomTat":"Hàn Lập hỏi Nguyên Dao ba vấn đề, vấn đề cuối khiến nàng kinh hoảng cố che đậy nhưng bị cắt ngang, tức giận bỏ đi. Huyền Cốt thượng nhân truyền âm bất mãn vì Hàn Lập chậm trong quỷ vụ, hai bên xác nhận thỏa thuận: Huyền Cốt giúp bắt Cửu Khúc Linh Sâm, đổi lại Hàn Lập trợ giúp diệt nghịch đồ Cực Âm — nhưng Hàn Lập lộ tia trào phúng cho thấy có tính toán riêng. Cực Âm tổ sư nhiều lần nhìn Hàn Lập bằng ánh mắt hổ đói mang vẻ vui mừng, khiến hắn bất an tức giận, khơi dậy sự hung hăng cứng đầu đã bỏ quên nhiều năm. Tử Linh tiên tử dù đang nói chuyện với nam tu sĩ nhưng ánh mắt lặng lẽ hướng về Hàn Lập. Cổ truyền tống trận xuất hiện, hai trưởng lão Tinh Cung thông báo quy tắc cửa thứ hai: có một ngày hái linh dược trước khi vào Băng Hỏa đạo, quá hạn ở lại sẽ mãi mãi mất tích. Sau truyền tống, Hàn Lập kinh ngạc trước không gian thực — thảo nguyên bao la, bầu trời xanh, linh khí tràn trề. Huyền Cốt giải thích đây là đại thần thông cổ tu sĩ khai phá thiên địa tạo không gian nhỏ, hậu nhân không tái hiện được, cổ tu sĩ đã biến mất khiến Tu tiên giới suy tàn."},{"chuong":448,"tieuDe":"Tiểu Thạch Sơn","tomTat":"Huyền Cốt thượng nhân giải thích cho Hàn Lập về cấu trúc cửa thứ hai Băng Hỏa Lộ: hạp cốc bị hạ cấm chế chứa hai thông đạo Huyền Tinh đạo (băng hàn) và Dung Nham lộ (cực nóng), cuối hạp cốc có cổ truyền tống trận đưa ra ngoài. Các nhóm Nguyên Anh kỳ tu sĩ lần lượt đến rồi tản mát mỗi người một hướng: Ôn phu nhân tuyên bố trung lập đi hái linh dược riêng, Vạn Thiên Minh cùng Thiên Ngộ Tử bay đi theo một hướng, Cực Âm tổ sư dùng hắc vụ đem Ô Sửu biến mất, Man Hồ Tử rủ Thanh Dịch cư sĩ hái Thọ Nguyên Quả nhưng bị từ chối nên tức giận thề trả đũa khi vào nội điện. Cực Âm tổ sư vừa đến liền tìm kiếm Hàn Lập nhưng không thấy, trong lòng thất vọng. Hàn Lập theo Huyền Cốt bay hơn hai thời thần qua đại thảo nguyên vào vùng núi trùng điệp, ngày càng cảnh giác vì Huyền Cốt bỏ qua nhiều ngọn núi linh khí dày đặc. Huyền Cốt kể lần đầu phát hiện Cửu Khúc Linh Sâm khi đuổi Linh Cầm Thử Hổ, nhận định đây là tiên gia bảo vật. Đến Tiểu Thạch Sơn — tòa núi đá nhỏ không cây cỏ, linh khí ít ỏi — Huyền Cốt dặn không được loạn động rồi hai mắt bắn ra huyết mang dài một tấc, khiến Hàn Lập thất kinh."},{"chuong":449,"tieuDe":"Ám Kế","tomTat":"Huyền Cốt thượng nhân dùng thần thức cấp Nguyên Anh kỳ xác nhận Cửu Khúc Linh Sâm vẫn còn ẩn trong ngọn núi đá phía dưới. Hàn Lập lặng lẽ vận dụng Đại Diễn quyết cũng nhìn thấy linh khí xanh mờ nhạt nhưng giấu không cho Huyền Cốt biết. Huyền Cốt giao cho Hàn Lập Kim Ti cầu (vật thuần kim duy nhất có thể bắt giữ Linh Sâm) và bốn trận kỳ Tứ Tượng Huyền Vũ, nhờ Hàn Lập bố trí trận pháp vì thấy hắn tinh thông trận pháp. Hàn Lập nhận trận kỳ nhưng mắt lóe tia cổ quái, cười lạnh, rõ ràng đã có phòng bị riêng. Bên trong thân Huyền Cốt, một nam tử bí ẩn có giọng hùng hậu lộ diện, là người quen cũ từng truyền công pháp quỷ tu cho Huyền Cốt. Hai bên mật đàm bộc lộ toàn bộ ám kế: Huyền Cốt quyết không giao Linh Sâm, sẽ lợi dụng trận pháp đã cài bẫy vây khốn Hàn Lập rồi giết, giúp nam tử đoạt xá thân thể Hàn Lập. Huyền Cốt tiết lộ Huyền Âm đại pháp truyền cho Cực Âm đã bị cài sơ hở từ đầu, tự tin liên thủ đủ sức diệt Cực Âm."},{"chuong":450,"tieuDe":"Hiện Hình","tomTat":"Huyền Cốt thượng nhân ra lệnh cho nam tử lệ hồn vô hình ẩn trong cơ thể lão trước tiên tìm Cửu Khúc Linh Sâm, sau đó giết Hàn Lập cho nam tử chiếm nhục thân. Hai bên phối hợp dùng Sưu Linh đại pháp phóng hắc khí và lục quang vào lòng đất, xác định Linh Sâm giấu bản thể trong hốc đá. Huyền Cốt đánh giá Hàn Lập chỉ là Kết Đan sơ kỳ, tự tin không cần hỗ trợ, cho rằng Thiên Lôi Trúc thần lôi tồn dư đã cạn nhưng vẫn e ngại đám kỳ trùng lạ. Hàn Lập nhận trận kỳ thổ thuộc tính do Huyền Cốt đưa nhưng nghi ngờ có gian kế, bí mật thay bằng hơn mười cây cờ thổ thuộc tính riêng. Huyền Cốt mang phân Xạ Lan Thú đặt vào trung tâm rừng dụ hoặc Linh Sâm, rồi dùng cờ mẫu kiểm tra trận pháp — xác nhận đúng loại lão đưa nên mặt lộ vẻ độc ác bay đi, nhưng thực chất đã bị Hàn Lập đánh lừa. Hàn Lập ẩn thân trên cây đại thụ chờ đợi, cuối cùng hóa thân Cửu Khúc Linh Sâm — con thỏ trắng mắt đỏ — bị mùi phân dụ hoặc, xông vào khu vực trận."},{"chuong":451,"tieuDe":"Phiên Kiểm","tomTat":"Bạch thỏ (hóa thân Cửu Khúc Linh Sâm) xuất hiện bên ngoài đại trận, ngửi ngửi hộp ngọc mồi nhử rồi lao vào ngậm đồ vật bỏ chạy. Hàn Lập kích hoạt quang tráo đại trận phong bế, dùng Kim Ti võng ụp bắt gọn bạch thỏ và cột vào eo lưng. Hắn bày giỏ trúc cổ bảo cùng Phệ Kim trùng phô trương thực lực, ngồi chờ Huyền Cốt đào bản thể Linh Sâm xong quay lại. Huyền Cốt hóa mây mù bay đến, hai bên đối thoại căng thẳng — Hàn Lập vạch trần Huyền Cốt có trợ thủ bí mật đã dùng Hóa hình chi thuật truy tìm Linh Sâm, cảnh cáo nếu nội đấu sẽ tiện nghi cho Cực Âm lão tổ. Huyền Cốt công kích quang tráo đại trận nhưng Hàn Lập bắn pháp quyết xanh hóa giải, cho thấy đã ngầm chỉnh sửa trận kỳ. Cuối cùng Huyền Cốt kích hoạt Kim Ti võng — thực chất là Âm Hồn ti do lão cài sẵn — hóa hắc khí nhốt chặt Hàn Lập, phong tỏa pháp lực. Hàn Lập cả kinh, sắc mặt tái xanh."},{"chuong":452,"tieuDe":"Lôi Đình Chi Kích","tomTat":"Hàn Lập phát hiện pháp lực bị đông cứng bởi Âm Hồn ti — tà vật do Huyền Cốt cài sẵn trên Kim Ti võng từ trước. Gã nam tử bóng xanh (quỷ ảnh cấp Quỷ Vương) dùng vô hình pháp thể xuyên qua trận pháp phòng hộ xâm nhập bên trong nhằm đoạt xá thân xác Hàn Lập. Hàn Lập dù mất pháp lực vẫn dùng thanh âm điều khiển Phệ Kim Trùng bao vây quỷ ảnh, đồng thời trùng cắn xé Âm Hồn ti giúp pháp lực hồi phục dần. Huyền Cốt từ bên ngoài phát hắc khí tấn công trận pháp phòng hộ, nhưng ngừng khi thấy quỷ ảnh sắp đoạt xá. Gã bóng xanh bị trùng bao vây, tự hủy nổ tung hóa quỷ đầu hung dữ lao tới Hàn Lập, nhưng Hàn Lập đã hồi phục phần lớn pháp lực, bạo phát sát khí rồi phóng Ích Tà Thần Lôi tiêu diệt quỷ ảnh, bóp nát viên châu nguyên thần. Sau đó Hàn Lập uy hiếp Huyền Cốt: giao Cửu Khúc Linh Sâm thì tiếp tục hợp tác, không thì một sống một chết. Huyền Cốt chấp nhận thực tế, tung hộp vàng chứa Cửu Khúc Linh Sâm xuống cho Hàn Lập."},{"chuong":453,"tieuDe":"Cực Âm Lai Tập","tomTat":"Huyền Cốt Thượng Nhân ném hộp vàng chứa bản thể Cửu Khúc Linh Sâm tới cho Hàn Lập, tuyên bố Âm Hồn ti đã chết nên cần liên thủ diệt Cực Âm, đồng thời nhận xét Kim Lôi Trúc pháp bảo của Hàn Lập có thể khắc chế Huyền Âm Đại Pháp. Hàn Lập dùng Ích Tà Thần Lôi kiểm tra hộp rồi mở ra, phát hiện khúc rễ vàng đất có đóa hoa bạc tỏa linh quang. Hóa thân thỏ trắng của Linh Sâm bật dậy lao tới bản thể xác nhận hàng thật, bị Hàn Lập đánh hôn mê cho nhập lại bản thể rồi niêm phong cất giữ. Huyền Cốt tiết lộ Cực Âm đã bí mật động tay động chân trên người Hàn Lập khiến y chạy đâu cũng bị truy tung, nhưng Hàn Lập không tin. Đúng lúc đó Huyền Cốt cảm nhận Cực Âm đang tới, lập tức hóa mây bỏ chạy biến mất. Cực Âm cưỡi đám mây đen khổng lồ kèm tiếng quỷ khóc bay tới, phát đạo hắc quang phá hủy trận pháp bảo hộ của Hàn Lập trong một kích. Hàn Lập thi triển thân pháp né tránh, triệu hồi mười khôi lỗi cự viên, phóng túi linh thú, tập trung chân nguyên lên chín thanh Thanh Trúc Phong Vân kiếm chuẩn bị tử chiến."},{"chuong":454,"tieuDe":"Dụ Hoặc","tomTat":"Cực Âm lão tổ (Nguyên Anh kỳ) cùng Ô Sửu bay đến tìm Hàn Lập, trước tiên thị uy bằng ma khí khiến Hàn Lập suýt hoảng loạn, được Huyền Cốt truyền âm trấn an. Cực Âm hiện thân dưới dạng trung niên nhân, đưa ra đoạn tơ nhện trắng thu được từ trận chiến với Ẩn Sát môn, yêu cầu Hàn Lập thả Huyết Ngọc Tri Chu ra xem. Khi nhện hiện thân (to bằng cối xay), Cực Âm mắt như phát hỏa, lộ tia tham lam, cười phá lên hưng phấn. Huyền Cốt ẩn nặc gần đó cũng kinh sợ hối hận khi biết Hàn Lập sở hữu linh thú này, nôn nóng thúc giục Hàn Lập đồng ý vào nội điện Hư Thiên Điện. Cực Âm mời Hàn Lập vào nội điện, hứa bảo đảm an toàn. Hàn Lập nhận ra mình bị cuốn vào tranh đấu giữa hai Nguyên Anh kỳ vì Huyết Ngọc Tri Chu, vừa mới chiếm được Cửu Khúc Linh Sâm có tác dụng ngưng anh nên kiên quyết từ chối mạo hiểm. Ô Sửu giận dữ đe dọa nhân danh Cực Âm Đảo, Cực Âm lộ vẻ âm lệ không vui."},{"chuong":455,"tieuDe":"Ý Ngoại Tần Sinh","tomTat":"Ô Sửu đóng vai kẻ ác theo dặn dò của Cực Âm, đe dọa giết Hàn Lập nếu không hợp tác, nhưng bị Hàn Lập phớt lờ hoàn toàn. Hàn Lập trực tiếp uy hiếp Cực Âm rằng lúc nguy cấp có thể ra lệnh Huyết Ngọc Tri Chu tự bạo, khiến Cực Âm biến sắc. Thanh Dịch cư sĩ bất ngờ xuất hiện trong hào quang xanh, tiết lộ bí mật rằng Huyết Ngọc Tri Chu là linh thú tốt nhất để lấy Hư Thiên đỉnh, phá vỡ toàn bộ mưu kế giữ bí mật của Cực Âm. Kế hoạch ban đầu của Cực Âm bị phơi bày: giấu Huyết Ngọc Tri Chu, xúi người cản chính đạo, dùng hỏa mãng giả thua rồi ngầm dùng Hàn Lập lấy Hư Thiên đỉnh một mình. Thanh Dịch cư sĩ giả vờ muốn thu Hàn Lập làm đệ tử để gây áp lực, nhắc đến Man Hồ Tử như mối đe dọa. Hai lão quái Nguyên Anh kỳ nhanh chóng đạt hiệp nghị bí mật, thống nhất ép Hàn Lập tự chọn bái một trong hai làm sư phó. Cực Âm đưa ra tối hậu thư: không chịu thì dùng phương pháp luyện linh thi giết Huyết Ngọc Tri Chu. Hàn Lập rơi vào thế bế tắc hoàn toàn, biết không đáp ứng thực sự không được."},{"chuong":456,"tieuDe":"Cực Âm Môn Đồ","tomTat":"Ba lão quái Nguyên Anh kỳ — Thanh Dịch cư sĩ, Cực Âm tổ sư và Huyền Cốt — tranh giành Hàn Lập làm đệ tử. Thanh Dịch hứa toàn bộ y bát kế thừa, Cực Âm dụ bằng quyền thế và mỹ nữ, Huyền Cốt uy hiếp bằng phương thuốc Cửu Khúc Linh Sâm buộc Hàn Lập phải bái Cực Âm để tìm cơ hội giết nghịch đồ. Hàn Lập cân nhắc rồi đành chọn Cực Âm, được thu làm ký danh đệ tử và nhận Huyền Âm hoàn làm tín vật phòng thân. Huyền Cốt tiết lộ nhẫn vốn tên Âm Dương hoàn do mình ban cho Cực Âm năm xưa, Âm hoàn bị Dương hoàn trên người Cực Âm khắc chế nên không thể dùng chống lại hắn. Nhóm bốn người bay tới Đại Hạp Cốc chờ vào Băng Hỏa đạo, trên đường Cực Âm hòa nhã chỉ điểm tu luyện cho Hàn Lập khiến Ô Sửu ghen tị. Tại Đại Hạp Cốc khoảng ba mươi tu sĩ Kết Đan đã tập trung, Hàn Lập nhận ra Nguyên Dao trong đám — nàng kinh ngạc khi thấy hắn đi cùng phe ma đạo, bối rối tránh né. Hàn Lập cảm thấy vô lực hơn bao giờ hết trước thực lực chênh lệch quá xa với Nguyên Anh kỳ."},{"chuong":457,"tieuDe":"Thác Thiên Ma Công","tomTat":"Hàn Lập ngồi trong nhóm ma đạo chờ đợi, nhóm tu sĩ Nguyên Anh kỳ của Vạn Thiên Minh bay đến trước, cười lạnh nhìn phe ma đạo rồi bàn bạc riêng. Thêm năm sáu tu sĩ và hai trưởng lão Tinh Cung tới, chỉ còn thiếu Man Hồ Tử. Cực Âm và Thanh Dịch cư sĩ dần lộ vẻ lo lắng. Man Hồ Tử cuối cùng xuất hiện trong quang cầu vàng kim, toàn thân phủ lớp vảy vàng cứng rắn — biểu hiện của Thác Thiên ma công — khiến mọi tu sĩ chấn kinh. Lão tiết lộ đã giết một con Băng Tuyết thiềm lấy nội đan hữu ích cho ma công. Man Hồ Tử chợt bạo phát khí thể uy áp lên Hàn Lập, khiến hắn tay chân nặng ngàn cân; Hàn Lập vận dụng Đại Diễn quyết kháng cự thành công, khiến Man Hồ Tử kinh ngạc rồi kinh hỉ. Cực Âm chặn trước mặt Hàn Lập bảo vệ, xác nhận hắn là ký danh đệ tử Cực Âm đảo. Man Hồ Tử khen thần thức Hàn Lập mạnh gấp mấy lần Ô Sửu, đề nghị nhượng hắn về tu luyện Thác Thiên ma công nhưng bị Thanh Dịch từ chối. Man Hồ Tử bỏ qua nhưng châm chọc hỏi trên người Hàn Lập có bí mật gì, khiến Thanh Dịch thần sắc khẽ biến rồi liếc nhìn Cực Âm."},{"chuong":458,"tieuDe":"Sinh Tử Lộ","tomTat":"Bặc Tự, tu sĩ Kết Đan kỳ tu luyện Thái Dương quyết, tiến vào Hư Thiên Điện và phát hiện có tám tu sĩ Nguyên Anh kỳ (gấp đôi bình thường). Trên Dung Nham lộ, Thái Dương quyết bị cấm chế khắc chế, pháp lực tiêu hao cực nhanh, hai kiện pháp khí tị hỏa gần như vô dụng. Tuyệt vọng, Bặc Tự liều bay lên thi triển Phi độn thuật, bị sấm sét từ bầu trời đỏ thẩm bổ trúng biến thành tro bụi. Một nữ tu sĩ khoác khinh sa lam đi trên thạch trụ qua sông dung nham rộng bốn mươi trượng, bị cơn lốc dung nham hóa cự long cuốn mất, tử vong. Gần băng sơn Huyền Tinh đạo, hai tu sĩ tựa lưng chiến đấu quái vật trong suốt rồi tử vong, trong khi Cực Âm lão tổ thảnh thơi phất tay cắt đôi quái thú đi qua dễ dàng. Hàn Lập dùng La Yên bộ vượt vùng cây cỏ quỷ dị, nhờ Hàn Băng châu của Man Hồ Tử qua ao đầm dung nham, đối phó Viêm Linh thú, đã mất hai ngày tới đoạn giữa hạp cốc. Đứng trước hắc sa mạc mênh mông, thời gian eo hẹp (giới hạn năm ngày, quá hạn truyền tống trận đóng kín), hắn cảm nhận có người tới phía sau và lập tức ẩn thân biến mất."},{"chuong":459,"tieuDe":"Hắc Sa Mạc","tomTat":"Một nam tử mặt vàng tu vi Kết Đan trung kỳ lên đỉnh núi cạnh hắc sa mạc thăm dò, dùng bát ngọc trắng phóng bạch quang dò tìm nhưng không phát hiện Hàn Lập đang ẩn thân bằng công pháp vô danh kết hợp La Yên bộ. Nam tử thả Hồng Ly thú cấp 1 vào sa mạc chục trượng bình yên trở về, rồi tự mình tiến vào. Hàn Lập do dự hơn nửa ngày giữa giết đoạt bảo vật hay để đối phương dò đường, cuối cùng chọn để nam tử đi trước vì bản thân đã có Bạch Tê bội và Hàn Băng châu tị hỏa. Khi nam tử tiến sâu khoảng trăm trượng, vô số hạt cát đen hóa thành hàng vạn kiến bay đen tấn công mãnh liệt. Nam tử dùng băng thuẫn tạo cụ phong chống đỡ nhưng kiến bay miễn dịch, phi đao pháp bảo bị phá hủy hoàn toàn khiến hắn nguyên khí đại thương. Đàn kiến bay hợp thể thành trường mâu dài vài trượng xuyên thủng hộ tráo, nam tử lâm vào cảnh nguy kịch."},{"chuong":460,"tieuDe":"Thiết Hỏa Kiến","tomTat":"Cơn lốc tan đi, lộ ra nam tử mặt vàng đã bị đàn kiến cánh ngưng tụ thành trường mâu đen xuyên thủng ngực rồi cắn nuốt hoàn toàn, chết không còn mảnh. Hàn Lập đứng trên đồi nhỏ xa xa chứng kiến, kinh hãi nhận ra đám kiến cánh chính là Thiết Hỏa Kiến — xếp hạng 37 trên kỳ trùng bảng, miễn nhiễm đao thương và đa số pháp thuật, có thể phun lửa đen và biến hình quần thể thành pháp bảo hỏa thuộc tính, nhưng không thể nhận chủ và cần quặng đồng sắt cùng nhiệt độ cao để sinh tồn. Hắn nhận ra hắc sa mạc chính là bẫy tự nhiên của Thiết Hỏa Kiến, bốc cát kiểm tra xác nhận chứa quặng hắc thiết, cảm khái chủ nhân Hư Thiên Điện đã dày công thu thập. Suy tính phù lục băng hệ và thủy thuộc tính không đủ vượt toàn bộ sa mạc, Hàn Lập nảy ý dùng Phệ Kim Trùng đối phó vì xếp hạng cao hơn và số lượng đông hơn. Trời vào giờ tý, hắn kích hoạt Linh Tê Phối và Hàn Băng Châu chống nóng tiến vào sa mạc, pháp lực tiêu hao đại tăng. Dùng thần thức dò xét nhưng không phát hiện được Thiết Hỏa Kiến do linh khí dao động như có như không, quyết định chỉ có thể dùng Phệ Kim Trùng thử."},{"chuong":461,"tieuDe":"Xảo Ngộ","tomTat":"Hàn Lập thả toàn bộ Phệ Kim Trùng đại chiến Thiết Hỏa Kiến, xác nhận chúng miễn dịch hoàn toàn hắc sắc hỏa diễm và áp đảo kiến, đủ sức vượt Hắc Sa Mạc. Suốt một ngày liên chiến, hắn tổn thất gần vạn Phệ Kim Trùng khi liên tục đụng độ các bầy kiến, bao gồm bầy siêu đại quy mô năm sáu vạn con tại khu vực trung tâm sa mạc. Hàn Lập lo lắng vì Phệ Kim Trùng ấp trứng rất lâu, khó bổ sung. Đi thêm vài chục dặm, hắn phát hiện một tu sĩ bị gần vạn Thiết Hỏa Kiến vây công, người đó bắn ra viên đạn bích lục dị bảo tạo lục sắc hỏa diễm khắc chế được hỏa thuộc tính linh trùng, khiến Hàn Lập kinh hãi. Hắn ban đầu lạnh lùng bỏ đi không muốn tốn Phệ Kim Trùng cứu người lạ, nhưng nghe tiếng gọi nhận ra đó là Nguyên Dao, lại vừa có ý tìm nàng có việc, bèn quay lại thả hơn ngàn Phệ Kim Trùng diệt sạch bầy kiến cứu nàng. Nguyên Dao sắc mặt tái nhợt do tiêu hao pháp lực, thi lễ cảm tạ Hàn Lập."},{"chuong":462,"tieuDe":"Minh Hồn Châu","tomTat":"Hàn Lập dùng thủ đoạn lấy lùi làm tiến, nhiều lần giả vờ bỏ đi để ép Nguyên Dao chủ động cầu xin và đưa ra thù lao. Nguyên Dao đề nghị tặng ba viên Thanh Hỏa Lôi bí chế bởi Thanh Dương Môn ma đạo nhưng Hàn Lập cho rằng chưa đủ. Nguyên Dao thi triển mị công gợi ý lấy thân báo đáp nhưng bị Hàn Lập bình thản phá giải. Hàn Lập cuối cùng nói ra điều kiện đã dự tính từ đầu: đổi Đề Hồn Thú lấy việc hộ tống qua Dung Nham lộ, nhằm giảm rủi ro khi hợp tác với Huyền Cốt lão quỷ. Nguyên Dao đồng ý nhanh chóng đáng ngờ, giao túi linh thú chứa Đề Hồn Thú rồi còn chủ động đưa Minh Hồn Châu — viên châu màu xám dùng khống chế Đề Hồn Thú. Hàn Lập nhận Đề Hồn Thú nhưng nghi ngờ thái độ hoan hỉ của Nguyên Dao, chưa vội tiếp nhận Minh Hồn Châu."},{"chuong":463,"tieuDe":"Ám Lưu Hung Dũng","tomTat":"Nguyên Dao chính thức giao Minh Hồn Châu cho Hàn Lập. Hàn Lập nghi ngờ luyện hóa có hại nhưng quyết định thu nhận, xác nhận chỉ cần giữ châu là chỉ huy được Đề Hồn thú. Hai người tiếp tục đi trong Dung nham lộ dưới sự bảo vệ của hàn khí từ Hàn Băng châu, Hàn Lập tuyên bố sẽ bảo hộ Nguyên Dao nhưng gặp nguy thật sự thì mỗi người tự lo. Nguyên Dao tiết lộ hắc sa mạc và Thiết Hỏa Kiến là bất thường chưa từng có ở Dung nham lộ. Ở Huyền tinh đạo, Thanh Dịch cư sĩ dễ dàng tiêu diệt đám Ngân Quang Thử bằng phi châm xanh, nhận ra sự xuất hiện bất thường và lo lắng cho Hàn Lập. Trong một thung lũng tối, hai trưởng lão Tinh Cung thừa nhận đã chủ động kích hoạt cấm chế Thiết Hỏa Kiến và Ngân Quang Thử tại Hư Thiên điện để uy hiếp chánh ma lưỡng đạo, trong bối cảnh hai thánh chủ bế quan không liên hệ được, nội bộ suy yếu tạm thời. Họ tin rằng chỉ cần thánh chủ xuất quan dùng Nguyên Từ Thần Quang thì bất khả chiến bại, và nhận định mười tu sĩ chánh ma đang hướng về Hư Thiên Đỉnh."},{"chuong":464,"tieuDe":"Luyện Tinh","tomTat":"Hàn Lập và Nguyên Dao tiếp tục hành trình qua sa mạc, gặp tổng cộng bảy đàn Thiết Hỏa Kiến nhỏ, Hàn Lập dùng Phệ Kim Trùng xử lý và cảnh báo phía trước còn đàn kiến khổng lồ cùng kiến chúa. Hai người phát hiện một cồn cát có trụ thủy tinh khổng lồ phát bạch quang âm hàn, bên trong là hình nhân do vô số kiến đen biết bay kết thành. Nguyên Dao nhận định đó là sản phẩm của Huyền Hoàng Kính — pháp bảo đại danh đỉnh đỉnh của Vạn Pháp môn — do Vạn Thiên Minh dùng tiêu diệt đàn kiến bay. Hàn Lập phóng Phệ Kim Trùng thôn phệ toàn bộ trụ thủy tinh và kiến đen, thu được Luyện Tinh — vật liệu cực hiếm tăng cường uy lực pháp bảo, dự định tế luyện Thanh Trúc Phong Vân Kiếm. Sau đó hai người vào thạch điện rộng lớn có truyền tống trận để trống và cửa đá đóng chặt, gặp lại Cực Âm tổ sư, Nho Sam lão giả, Vạn Thiên Minh cùng nhiều tu sĩ Kết Đan hậu kỳ đang ngồi trong bầu không khí căng thẳng. Cực Âm tổ sư sắc mặt tái nhợt, trừng mắt nhìn truyền tống trận với hung quang chớp động không ngừng."},{"chuong":465,"tieuDe":"Trọng Bảo Ở Lầu Các","tomTat":"Các tu sĩ đã vượt qua Băng Hỏa Đạo, Hắc Sa mạc và Huyết Băng Lâm tập trung trong thạch điện. Cực Âm lão tổ và Thanh Dịch cư sĩ lo lắng cho Hàn Lập vì nếu mất hắn thì Huyết Ngọc Tri Chu cũng mất. Hai bạch y trưởng lão Tinh Cung xuất hiện, giải thích bông lơn rằng dị biến Băng Hỏa Đạo do đạo hữu nóng nảy phá cấm chế, tuyên bố tự diện bích trăm năm tạ tội; mọi người phẫn nộ nhưng không dám chất vấn. Hàn Lập cùng Nguyên Dao xuất hiện từ cổ truyền tống trận, Cực Âm mừng rỡ đón tiếp, Man Hồ tử trả lại rồi tặng luôn Hàn Băng Châu cho Hàn Lập. Ô Sửu ganh ghét liếc Hàn Lập, bị Cực Âm truyền âm cảnh cáo. Cổ truyền tống trận biến mất, bốn vách tường mở ra bốn thông đạo đá xanh: ba thông đạo dẫn tới ba tòa lầu chứa Cổ bảo, Đan dược và Công pháp; thông đạo thứ tư trắng tay. Mỗi người chỉ được lấy một thứ rồi bị truyền tống tới Cực Diệu Huyễn Cảnh."},{"chuong":466,"tieuDe":"Bảo Quang Các","tomTat":"Tại thạch điện, các tu sĩ lần lượt chọn thông đạo tiến vào. Cực Âm lão tổ trao Bà La Châu (an thần định tâm) cho Hàn Lập để đối phó Cực Diệu Huyễn Cảnh. Nho sam lão giả tặng Hàn Lập Thanh Minh Châm phù bảo do tu sĩ Nguyên anh kỳ tạo ra, uy lực vượt xa pháp bảo thường. Man Hồ tử cho mượn Hoàng Lân Giáp (nội giáp đen có lân phiến trắng) vì Thác Thiên Công đã luyện thành nên bảo giáp không còn cần thiết. Ba lão quái chờ Hàn Lập đi trước làm tiên phong rồi cùng theo. Hai bạch y trưởng lão Tinh Cung ở lại thạch điện bàn luận, nhận định nhóm ma đạo nhắm Hư Thiên Đỉnh, nhắc lại lần trước có tu sĩ mở Hư Thiên Đỉnh lấy đi một viên Bổ Thiên Đan trốn thoát, lần này Vạn Thiên Minh có Kim Ti Tằm nên cũng có khả năng, quyết định sẽ ra tay cướp nếu nhóm kia thành công. Hàn Lập leo cầu thang xoắn ốc hơn trăm trượng, bước vào không gian hình trụ sương mù vàng, phát hiện toà lầu ngọc hai tầng Bảo Quang Các lơ lửng giữa không trung, có cấm chế bao bọc, thận trọng bước lên cầu bạch ngọc."},{"chuong":467,"tieuDe":"Được Bảo Vật","tomTat":"Hàn Lập vượt cầu ngọc tiến vào Bảo Quang Các, bên trong tầng một có nhiều ngọc đài bằng ngọc trắng trong suốt chứa vật phẩm nhưng không thực sự ấn tượng, một ngọc đài trống rỗng cho thấy có người đã đến lấy trước. Hắn dùng cổ truyền tống trận bỏ linh thạch vào để dịch chuyển lên tầng hai. Tầng hai có màn hào quang hình cầu màu lam khổng lồ chứa hơn mười kiện cổ bảo. Hàn Lập kết chín thanh phi kiếm thành cự kiếm tấn công màn hào quang nhưng bị lực phản đánh ngược, khe hở phục hồi ngay. Hắn nghĩ ra cách dùng Phệ Kim Trùng, thả đám trùng vụ vàng đục thủng lỗ hổng trên màn hào quang rồi kịp hóa thanh quang lọt vào bên trong. Thần thức bị phong tỏa bên trong màn hào quang, hắn phải dùng trực giác và kinh nghiệm lựa chọn, cuối cùng chọn được ba kiện cổ bảo: gương hình tròn màu vàng có thần thông kỳ lạ, ngũ xuyến đồng hoàn bao hàm thuộc tính ngũ hành, và áo choàng màu đỏ sậm rộng thùng thình chưa rõ công năng."},{"chuong":468,"tieuDe":"Hắc Giáp Quỷ Dị","tomTat":"Hàn Lập đối mặt ba cổ bảo trong thạch điện: gương tròn màu vàng, Ngũ sắc đồng hoàn và áo choàng lông chim đỏ sậm, nhưng quy định chỉ được lấy một. Hàn Lập nảy ra ý tưởng dùng mẹo tả đạo kết hợp kiến thức trận pháp từ Tân Như Âm và sách cổ, dùng năng lực thôn phệ thiên địa linh khí của Phệ Kim Trùng để khống chế cấm chế không gian. Hắn tế xuất mấy vạn Phệ Kim Trùng quấn quanh thân, dung hợp thành khôi giáp màu đen bao bọc toàn thân, cắt liên hệ linh lực với cấm chế. Mang hắc giáp, Hàn Lập đoạt được áo choàng trước, rồi gian nan di chuyển năm sáu trượng nắm thêm Ngũ sắc đồng hoàn. Lam quang cấm chế bùng lên dữ dội phá tan khôi giáp, Hàn Lập bị cuốn trong quả cầu lam quang truyền tống ra ngoài. Hắn xuất hiện trong thạch thất rộng lớn không người, kiểm lại vẫn giữ được cả hai cổ bảo trên tay. Thạch thất chỉ có cổ truyền tống trận và một thông đạo hình vuông phía trước, lạnh lẽo yên tĩnh."},{"chuong":469,"tieuDe":"Yêu Dị Cổ Bảo","tomTat":"Hàn Lập bắt đầu nghiên cứu hai kiện cổ bảo thu được. Thử nghiệm Ngũ xuyến đồng hoàn, phát hiện ba công năng: phòng ngự tạo màn ngũ sắc hào quang bảo hộ, vây khốn đánh lén bằng cách tự xuất hiện trên cổ và tay chân đối phương khiến cứng đờ, nhưng không thể dùng công kích trực tiếp. Hắn đánh giá ngay cả tu sĩ Nguyên Anh kỳ cũng khó tránh khi bị đánh lén. Thử áo choàng đỏ sậm, phát hiện cho tốc độ thuấn di kinh người vượt cả Nguyên Anh kỳ nhưng tiêu hao linh lực cực lớn và hoàn toàn không thể điều khiển hướng hay giảm tốc, xác định là cổ bảo thứ cấp dùng trốn thoát khi đại nạn. Sau nửa ngày khôi phục pháp lực, Hàn Lập đeo Bà La Châu vận Đại Diễn Quyết bước vào Cực Diệu Huyễn Cảnh. Hành lang dài với ảo cảnh bồng lai tiên cảnh, tiên âm mê hoặc và bạch hạc nhảy múa, nhưng hắn cười lạnh không bị ảnh hưởng, thoải mái bước đi."},{"chuong":470,"tieuDe":"Huyễn Cảnh Hắc Điện","tomTat":"Hàn Lập tiếp tục đi trong hành lang Cực Diệu Huyễn Cảnh, đối mặt thiên ngoại âm ma ngày càng mạnh cùng huyễn cảnh bạch hạc biến thành thiếu nữ rồi mỹ phụ khiêu gợi kết hợp hồ mỵ thuật nhằm mê hoặc. Nhờ Đại Diễn Quyết lưu chuyển trong đầu, hắn hoàn toàn không bị ảnh hưởng, coi như được một phen thưởng lãm. Sau khoảng một canh giờ, hắn tới cuối hành lang và phát hiện tòa hắc điện đỉnh bằng cao mười trượng, tường phủ máu khô hồng đen, tràn ngập huyết khí và khí tức tà ác. Bước vào bên trong, cấm chế nơi đây hấp thu mọi ánh sáng — hỏa cầu bị dập tắt, linh thạch mất quang, thần thức bị phong tỏa chỉ nhìn được ba bốn trượng. Hàn Lập quyết định dựa vào Bà La Châu để vượt ải. Trong bóng tối xuất hiện tiếng khóc bi oán của thiếu nữ cùng bóng bạch y nữ tử quỳ trước mặt. Khi nữ tử gọi hắn là Tứ ca và ngẩng mặt lộ khuôn mặt giống hệt tiểu muội của Hàn Lập thuở nhỏ, hắn bị chấn động mạnh — huyễn cảnh chuyển sang tấn công vào điểm yếu tình thân gia đình."},{"chuong":471,"tieuDe":"Nội Điện Khai Khải","tomTat":"Hàn Lập trong bóng tối gặp bóng ma giả dạng tiểu muội gọi hắn là Tứ ca, nhờ Bà La Châu phát nóng cảnh báo mà nhận ra là giả, phóng phi kiếm tiêu diệt. Hắn đến trước Nội điện Hư Thiên Đỉnh — tòa cự tháp đá xanh năm tầng — nơi hơn mười tu sĩ chính-ma lưỡng đạo đã tập hợp, gồm Cực Âm lão tổ, Vạn Thiên Minh, Man Hồ Tử, Huyền Cốt, Ô Sửu. Hàn Lập chủ động thi lễ Cực Âm giữ vỏ bọc, Cực Âm và Man Hồ Tử đều không đòi lại bảo vật đã cho mượn. Huyền Cốt bí mật truyền âm tiết lộ kế hoạch thu thập Cực Âm với chín phần nắm chắc, cần Hàn Lập dùng Huyết Ngọc Tri Thù sau khi đoạt bảo — Hàn Lập nghi hoặc bất an. Mặt đất rung chuyển, cánh cửa đá Nội điện mở ra lộ thông đạo đá xanh, truyền tống trận đồng thời thu liễm ánh sáng — hai trưởng lão Tinh Cung không kịp đến. Vạn Thiên Minh từ chối đề nghị đấu của Man Hồ Tử, đề xuất chính-ma luân phiên đoạt bảo rồi mới phân cao thấp, coi Tinh Cung là kẻ địch chung."},{"chuong":472,"tieuDe":"Đường Lang, Hoàng Tước","tomTat":"Cực Âm tổ sư đồng ý đề nghị của Vạn Thiên Minh tạm hưu chiến, hai phe chính tà cùng tiến vào cửa đá nội điện. Man Hồ Tử bất ngờ ra tay giết chết một tu sĩ Kết Đan kỳ, nhưng Nguyên Dao bạo phát Thanh Hỏa Lôi của Tam Dương lão ma đánh tan kim quang thoát thân, biến mất vào thạch tháp. Man Hồ Tử công khai tuyên bố Huyền Cốt là hậu nhân trưởng bối có ơn, không cho phép ai động đến, khiến Cực Âm tổ sư bất ngờ nhưng không dám phản đối. Thanh Dịch cư sĩ khuyên Man Hồ Tử không nên kết oán Tam Dương lão ma vì ba phe đang tranh đoạt Loan Tinh Hải. Sau khi tất cả đã vào, hai trưởng lão Tinh Cung bí mật xuất hiện từ Truyền tống trận, tiết lộ Tinh Cung ngàn năm trước đã phá giải cấm chế nơi đây, quyết định chỉ ra tay khi Hư Thiên đỉnh thật sự bị đoạt. Trong thông đạo, Ô Sửu đột ngột trở nên nhiệt tình với Hàn Lập, khiến Hàn Lập nghi ngờ Cực Âm đã sai Ô Sửu sau khi đoạt bảo sẽ giết mình, trong lòng cực kỳ nặng nề."},{"chuong":473,"tieuDe":"Lang Thủ Khôi Lỗi","tomTat":"Đoàn người Hàn Lập di chuyển trong mê cung tầng một Hư Thiên Điện, đi qua ít nhất 7-8 ngã tư cửa đá có cấm chế phù văn. Ô Sửu giải thích quy tắc: mỗi người chỉ được dùng Hư Thiên tàn đồ mở một cửa phòng lấy bảo vật, dù thành công hay không đều bị truyền tống ra ngoài, tu sĩ Kết Đan kỳ chỉ lấy được bảo vật tầng một. Hàn Lập ghi nhớ cơ chế truyền tống, nghĩ có thể lợi dụng làm cách chạy trốn sau này. Khi gặp cơ quan thủ vệ tầng một, Man Hồ Tử hưng phấn vận dụng Thiên Ma Công (lân phiến vàng bao thân), hóa kim quang xông vào dùng quyền cước tiêu diệt bốn khôi lỗi cấp A và khôi lỗi lang thủ kim sắc thực lực trên Kết Đan sơ kỳ. Cực Âm tổ sư và Thanh Dịch cư sĩ nhận xét tu vi hiện tại khác ba trăm năm trước, tầng thủ vệ thứ nhất không còn uy hiếp. Hàn Lập quan sát tàn tích khôi lỗi, bất chấp lời Huyền Cốt nói tài liệu không luyện chế được pháp bảo, vẫn thu viên bảo thạch xanh biếc tản hàn khí quỷ dị vào túi trữ vật để nghiên cứu thuật chế tạo khôi lỗi cổ xưa. Hắn nhận biết mình bị ba lão quái Nguyên Anh giám sát, tự biết Hư Thiên Đỉnh là hy vọng xa vời."},{"chuong":474,"tieuDe":"Nhị Tầng","tomTat":"Nhóm ma đạo tiếp tục đi trong tầng một nội điện Hư Thiên Điện, Man Hồ Tử một mình dùng Thiên Ma Công đập nát tất cả bảy tám con Khôi lỗi Lang thú gặp trên đường. Hàn Lập không chút khách khí thu lại tất cả mảnh vụn Khôi lỗi bị phá hủy, khiến Ô Sửu và Huyền Cốt nghi hoặc. Dù lần đầu tới nội điện, Man Hồ Tử tự tin dẫn đường đi trước khiến Hàn Lập thầm nghi ngờ. Nhóm đến Truyền tống trận giữa ngã tư và truyền tống lên tầng hai, phát hiện nhóm chính đạo Vạn Thiên Minh đã đi trước không còn dấu vết. Thanh Dịch cư sĩ đề ra kế sách: nếu đối phương lấy được Hư Thiên Đỉnh thì mai phục đoạt lại, vì chỉ bằng Kim Ti Tàm không đủ. Tầng hai ít ngã tư hơn nhưng có cấm chế và bẫy rập lợi hại, cơ quan thủ vệ đổi thành Xà vệ Khôi lỗi mạnh hơn nhiều. Ba vị Nguyên Anh kỳ hợp lực hạ một Xà vệ Khôi lỗi — Man Hồ Tử đấm xuyên ngực móc ra viên bảo thạch xanh lục bất hoại mà không ai biết cách sử dụng, rồi tiện tay ném cho Hàn Lập. Hàn Lập thu cả bảo thạch lẫn mảnh vụn Xà vệ Khôi lỗi vào túi trữ vật."},{"chuong":475,"tieuDe":"Ý Ngoại","tomTat":"Hàn Lập thu hồi hai ngọn giáo nhỏ bị biến dạng, phát hiện Cực Âm lão tổ lộ ánh mắt thèm muốn rồi che giấu, ý thức thêm mối nguy từ Cực Âm. Ba tu sĩ Nguyên Anh kỳ phe ma đạo đồng loạt ra tay đưa mọi người vượt qua Khôi lỗi và cấm chế tầng bốn an toàn. Nhóm chính đạo gồm Vạn Thiên Minh, Thiên Ngộ Tử và lão giả gầy ốm tu luyện Ngọc Đan công đã đến trước tầng năm, Vạn Thiên Minh dùng tử khí phá Thiên cương tráo cấm chế bao phủ thạch đài khổng lồ rồi dẫn cả ba tiến vào. Nhóm ma đạo đến sau, lão giả nho sam giải thích cấm chế thượng cổ chỉ có một lối ra vào, cả nhóm quyết nghỉ ngơi hồi phục trước khi đột nhập. Hàn Lập toan liên minh với Huyền Cốt nhưng đổi ý, cho rằng cả Huyền Cốt lẫn Cực Âm đều nhắm vào Huyết Ngọc Tri Thù, chủ động tìm tới sẽ lộ sợ hãi. Hắn một mình đi ra mặt sau đài cao, nhờ kinh nghiệm giang hồ về cơ quan mật thất mà phát hiện khối đá thứ ba khắc hình yêu thú có cánh mắt đỏ máu bên trong trống rỗng, dường như có giấu vật bí ẩn."},{"chuong":476,"tieuDe":"Kim Tằm Thủ Bảo","tomTat":"Trước khi nhóm tà đạo tiến vào đài cao, Hàn Lập lợi dụng lúc Cực Âm không giám sát để bí mật dùng kiếm quang mở vách đá, lấy được quyển trục vàng cũ kỹ giấu vào ngực nhưng chưa kịp xem nội dung. Man Hồ Tử dẫn đầu dùng Thiên Ma công phá vỡ màn hào quang bảo hộ đài cao, cả nhóm tiến vào vùng hàn khí cực mạnh — Hàn Lập phải dùng Bạch Linh Tê chống lạnh. Tại trung tâm tế đàn, mấy con Kim Ti Tằm bích lục dài vài trượng đang phun sợi tơ vàng vào cái động tỏa lam quang, kéo thứ gì đó ra ngoài, khiến Hư Thiên Đỉnh chớp sáng bất thường. Ba tu sĩ chính đạo gồm Vạn Thiên Minh và Thiên Ngộ Tử canh giữ tại đây. Man Hồ Tử ra đòn trước nhưng bị hai linh thú cấp Nguyên Anh — Hàn Giao (tiểu bạch giao mượn từ Phong Bà Tử) và Ly Quy (cự quy mượn từ Thiên Duyên Tử) — chặn đứng. Phe tà đạo kinh hãi trước sức mạnh linh thú, Man Hồ Tử vạch kế hoạch không đánh bại đối phương mà chỉ cần giết một con Kim Ti Tằm, yêu cầu Thanh Dịch cư sĩ và Cực Âm thả linh thú cầm chân đối thủ."},{"chuong":477,"tieuDe":"Kim Ti Tằm Dữ Thiên Thanh Hoa","tomTat":"Kế hoạch đoạt Hư Thiên Đỉnh của phe chính đạo thất bại hoàn toàn khi dược tính Thiên Thanh Hoa hết, sáu con Kim Ti Tằm đồng loạt mất kim quang, bị phế. Vạn Thiên Minh giận dữ nhưng kiềm chế, bỏ lại tằm bị phế dẫn phe chính đạo rời đi. Phe ma đạo hả hê, Man Hồ Tử khiêu khích, Thanh Dịch cư sĩ cho Thanh Cức Điểu canh chừng lối vào, Cực Âm tổ sư phái hai Thiên Đô Thi tiềm phục đề phòng. Huyền Cốt giải thích nguyên nhân thất bại: Kim tằm phục dùng Thiên Thanh Hoa tạm nâng đạo hạnh, nay dược tính hết thì bị phế. Hàn Lập ngăn Thanh Dịch cư sĩ diệt tằm, xin thu ba con còn sống vào túi linh vật. Cực Âm ra lệnh Hàn Lập phóng Huyết Ngọc Tri Thù thăm dò linh thú trong đại động, hứa không bạc đãi, nhưng Hàn Lập cảm thấy lạnh lẽo chạy dọc sống lưng."},{"chuong":478,"tieuDe":"Thủ Bảo","tomTat":"Hàn Lập bước tới miệng động nhìn xuống đáy sâu hai ba mươi trượng, thấy Hư Thiên đỉnh nằm trong Kiền Lam Băng Diễm — ngọn lửa lam chí âm chí hàn, Nguyên anh kỳ cũng không dám chạm. Cực Âm lão tổ giải thích chỉ có Kim ti Kim Ti Tằm, Thù ti Huyết Ngọc Tri Thù và hai con Hoả Mãng của lão là miễn dịch lửa này. Hàn Lập triệu hồi Huyết Ngọc Tri Thù, Man Hồ Tử kinh ngạc đánh giá nó đã đạt Yêu thú cấp bốn đỉnh phong sắp đột phá cấp năm. Cực Âm phân công: Tri Thù phun thù võng bọc đỉnh, Hoả Mãng hiệp lực kéo, Ô Sửu và Huyền Cốt lui xa, Thanh Dịch cư sĩ bảo vệ Hàn Lập vì muốn Bổ Thiên Đan trong đỉnh. Hàn Lập trong lòng tính kế, biết đoạt bảo thành công càng nguy hiểm, hy vọng đợi Huyền Cốt đối phó Huyền Âm để đục nước béo cò. Cực Âm lấy hai con Hoả Mãng dài bốn năm trượng toàn thân lân phiến đỏ cho nuốt dược hoàn đen rồi sai vào động. Tri Thù và Hoả Mãng cùng phát lực kéo, Hư Thiên đỉnh cực nặng chỉ lắc lư chưa nhấc lên được. Cực Âm phun tinh khí đen lên Hoả mãng và yêu cầu Man Hồ Tử thi triển Cuồng bạo chi thuật lên Huyết Ngọc Tri Thù để tăng lực."},{"chuong":479,"tieuDe":"Khứ Nhi Phục Phản","tomTat":"Man Hồ Tử không hỏi ý Hàn Lập, tự ý thi triển Cuồng bạo chi thuật — ma đạo bí thuật phun huyết kích thích Huyết Ngọc Tri Thù vào trạng thái cuồng bạo, tăng sức kéo Hư Thiên đỉnh nhưng khiến linh thú gần mất lý trí. Huyết Ngọc Tri Thù kéo Hư Thiên đỉnh lên được khoảng một nửa, chấn động mạnh kèm lam quang chói mắt; Thanh Dịch cư sĩ phóng bảo quang bảo hộ Hàn Lập và cảnh báo hàn lưu nguy hiểm sắp bạo phát, tiết lộ trước đây nhiều tu sĩ đã thất bại khi thử kéo. Hàn Lập phát hiện thù ti vốn trắng nhũ giờ xạ ra tầng lam mang nhàn nhạt bất thường nhưng chưa kịp tìm hiểu. Chính đạo Vạn Thiên Minh bất ngờ quay lại, xé vòng bảo hộ xâm nhập tế đàn; phe ma đạo triệu linh thú và Yêu Thi chuẩn bị nghênh chiến trong khi Huyền Cốt lại đứng yên con ngươi chuyển động đáng nghi. Vạn Thiên Minh tiết lộ đã sớm nhận ra Hàn Lập có Huyết Ngọc Tri Thù — loài biệt tích từ lâu — và cài sẵn Hoá thạch thú hình khỉ lam trong đá làm gián điệp giám sát. Hắn ra tối hậu thư: hoặc kích sát Huyết Ngọc Tri Thù khiến đỉnh nằm lại dưới động, hoặc hai bên chia đều bảo vật, hoàn toàn xoay chuyển tình thế."},{"chuong":480,"tieuDe":"Đại Chiến Khởi","tomTat":"Vạn Thiên Minh đề nghị Cực Âm hợp tác phân chia bảo vật từ Hàn Lập, nhưng Man Hồ Tử cự tuyệt và tuyên bố dùng vũ lực. Con báo ba mắt của Man Hồ Tử dùng Dị hóa thuật biến pháp khí/pháp bảo của Vạn Thiên Minh thành đá vụn, tiết lộ nó là linh thú biến dị cực hiếm — Loạn Tinh Hải hơn ngàn năm chưa xuất hiện. Cực Âm bỏ ý hợp tác với chính đạo, quyết độc chiếm bảo vật, cùng lão giả nho sam khai chiến trước. Vạn Thiên Minh hô lệnh phản công, phóng Hàn Giao ra và hóa hỏa nhân tím tấn công Man Hồ Tử; Thiên Ngộ Tử kích hoạt cự quy phóng hàn khí đối đầu Thanh Cức Điểu; lão giả gầy gò dùng cành liễu mộc thuộc tính trói chặt ba Thiên Đô Thi, Cực Âm hóa mây đen bay đến giải cứu vì Thiên Đô Thi Hỏa khắc chế mộc. Hàn Lập bị động lui ra phía sau, nhận thức rõ chính đạo muốn đoạt Hư Thiên Đỉnh và giết chủ nhân Huyết Ngọc Tri Thù, không dám chắc phe ma đạo sẽ bảo vệ mình, quan sát Huyền Cốt dưới tế đàn không đoán được ý định."},{"chuong":481,"tieuDe":"Hóa Hình Chi Bảo","tomTat":"Hàn Lập quan sát trận chiến Nguyên Anh kỳ giữa hai phe chính ma: Man Hồ Tử đấu Vạn Thiên Minh, Thiên Ngộ Tử đấu Thanh Dịch cư sĩ, Cực Âm tổ sư đấu lão giả gầy gò, nhận ra cuộc chiến mang tính cầm chừng chứ không phải sinh tử chiến chân chính. Huyền Cốt đứng bên cạnh ẩn chứa tia cười lạnh bí hiểm khiến Hàn Lập rùng mình. Bảo vật bên trong Hư Thiên đỉnh tự hóa hình thành hỏa diễm cự lang hai đầu phá đỉnh bay ra, toàn thân cháy lửa có linh tính, phát hào quang hồng hoàng đẩy bật công kích cấp Nguyên Anh. Hai phe ngừng tay tranh đoạt, Thiên Ngộ Tử phóng bàn tay xanh từ thiên linh cái chụp hỏa lang nhưng bị bật, Vạn Thiên Minh dùng phân thân công kích phá thế, các cao thủ quay sang đánh nhau dữ dội hơn bỏ rơi hỏa lang. Hỏa lang chạy về phía đám Kết Đan kỳ, Hàn Lập lấy Thất Hà Liên chuẩn bị thu nhưng Ô Sửu ra tay trước dùng Huyền Âm đại pháp hóa rắn đen quấn hỏa lang. Hàn Lập cân nhắc đoạt nhưng sợ chọc giận Cực Âm tổ sư, chưa kịp quyết thì Huyền Cốt ra tay dứt khoát phóng ti võng bích lục bao phủ cả hắc mãng lẫn hỏa lang."},{"chuong":482,"tieuDe":"Cổ Bảo Chi Tranh","tomTat":"Ô Sửu và Huyền Cốt dùng hắc sắc cự mãng và bích lục ti võng giằng co tranh đoạt hỏa lang cổ bảo nhưng bất phân thắng bại. Phe chính đạo muốn nhảy vào đoạt bảo nhưng bị Man Hồ Tử và Cực Âm sư tổ cản lại. Hàn Lập toát mồ hôi lạnh khi nhận ra hoa lam cổ bảo đang dùng chính là chiến lợi phẩm đoạt từ Sửu Hán, nếu bị Cực Âm phát hiện sẽ lộ chuyện thả Huyền Cốt, nhưng Cực Âm không nhận ra. Hư Thiên Đỉnh gần rời động khẩu, hai đạo hào quang bắn ra, sáu tu sĩ Nguyên Anh tranh đoạt. Vạn Thiên Minh dùng hai viên giả Thiên La chân lôi châu dọa Cực Âm và lão giả nho sam né tránh, thành công đoạt Cổ Bội hình tứ phương thượng cấp. Man Hồ Tử nhờ phòng ngự Thiên Ma công đón công kích của lão giả gầy ốm và Thiên Ngộ Tử, đoạt được đồng tiền cổ bạch quang. Hỏa lang cổ bảo cuối cùng bất ngờ rơi vào tay Hàn Lập, biến thành Ngọc Như Ý hoàng hồng điêu khắc hình sói, khiến Cực Âm sư tổ giật mình nghi hoặc và Ô Sửu oán hận."},{"chuong":483,"tieuDe":"Băng Phong","tomTat":"Hỏa lang đang bị Ô Sửu và Huyền Cốt vây khốn bất ngờ hợp nhất hai đầu thành cự lang lông bạc một sừng, phóng ngân quang đạn phá thủng hắc mãng và lục võng thoát vây. Huyền Cốt phun ra thanh tiểu đao xanh biếc tấn công ngân lang, Hàn Lập nhờ bổn mạng pháp bảo cũng là Kim Lôi Trúc nên cảm ứng nhận ra tiểu đao đó thực chất là Kim Lôi Trúc bị thuật che mắt che giấu, nghi ngờ ngân lang có điều cổ quái khiến Huyền Cốt dám mạo hiểm. Ngân lang thu nhỏ thoát qua lỗ hổng, bị Huyền Cốt đánh bắn đúng hướng Hàn Lập. Hàn Lập nhanh tay dùng hoa lam cổ bảo và năm vòng đồng thu phục ngân lang, vỗ nhẹ thì nó hiện nguyên hình thành Ngọc Như Ý. Cực Âm sư tổ đang giằng co với Vạn Thiên Minh trên không, nhíu mày khi thấy Hàn Lập đoạt cổ bảo nhưng không thể can thiệp, tự nhủ sau sẽ ép Hàn Lập giao lại. Đài cao chớp động dữ dội, hỏa diễm lam sắc từ động khẩu bùng phát, lam băng quái dị lan tràn phủ kín mặt đài. Ô Sửu chần chờ bị đóng băng hai chân, được Cực Âm dùng Thiên Đô thi hỏa giải cứu. Đệ nhất bí bảo Hư Thiên Đỉnh của Loạn Tinh Hải cuối cùng đang xuất thế, các lão quái hai phe chính ma đều tập trung theo dõi, Hàn Lập và các tu sĩ cấp thấp phải thối lui xa."},{"chuong":484,"tieuDe":"Hóa Thân Phù Dữ Bổ Thiên Đan","tomTat":"Man Hồ Tử phát hiện trưởng lão Tinh Cung ẩn thân trong nội điện bằng Hóa Thân Phù, đánh một quyền hóa bàn tay vàng nhưng đối phương đỡ được. Trưởng lão Tinh Cung thứ hai hiện thân phóng phi kiếm Quán Nhật Kiếm chém đứt đôi Huyết Ngọc Tri Thù và đánh văng Hàn Lập, nhưng Hàn Lập sống sót nhờ Ngọc Như Ý hộ thân. Cả hai trưởng lão hóa ra chỉ là phân thân từ Tinh Cung Hóa Thân Phù, tan biến để lại phù vàng tự thiêu, chân thân ẩn ở tầng thứ năm Hư Thiên điện. Hai chân thân bàn luận tiết lộ công dụng thật của Bổ Thiên Đan: bồi bổ linh căn bất thuần và củng cố Nguyên Anh cho tu sĩ Kết Đan kỳ, không tăng thọ hay đột phá bình cảnh Nguyên Anh kỳ như lời đồn. Hỏa Mãng của Cực Âm sư tổ cuối cùng không chịu nổi, nhả Hư Thiên Đỉnh ra. Hư Thiên Đỉnh trong lúc hạ xuống bất ngờ phát tiếng rồng gầm, phóng ra hào quang ngũ sắc chứa Bổ Thiên Đan bay lên trời, hai bên chính ma đồng thanh hô lớn vừa mừng vừa sợ."},{"chuong":485,"tieuDe":"Nguyên Anh Hiện","tomTat":"Viên Bổ Thiên Đan xuất hiện lơ lửng trong hào quang ngũ sắc phía trên động khẩu, toàn bộ tu sĩ Nguyên Anh Kỳ lao vào tranh đoạt hỗn chiến dữ dội. Cực Âm lão tổ ra lệnh cho Ô Sửu đi thu đan nhưng Huyền Cốt xuất hai quái xà xanh tập kích cản trở. Man Hồ Tử công khai tuyên bố phá bỏ liên thủ ma đạo, ai mạnh nấy tranh, khiến liên minh ma đạo chính thức tan rã. Hàn Lập kiểm tra vết thương, phát hiện mình sống sót nhờ Hoàng Lân Giáp chịu kiếm và đặc biệt nhờ Ngọc Như Ý bên trong lộ ra bàn chân soi màu bạc bí ẩn đón phần lớn uy lực. Hàn Lập định bỏ trốn theo đường cũ quay tầng một nhưng bị Huyền Cốt gọi tên trước mặt mọi lão quái, buộc phải quay lại. Vạn Thiên Minh nhiều lần bị Man Hồ Tử đánh bay, thẹn quá hóa giận, vỗ thiên linh cái cho Nguyên Anh xuất khiếu — hình trẻ con trắng nõn tay cầm viên châu tím trong tử quang, tuyên bố đại hạn sắp đến nên sẵn sàng liều chết đoạt đan."},{"chuong":486,"tieuDe":"Đan Dược Chi Tranh","tomTat":"Vạn Thiên Minh nguyên anh xuất khiếu, ném lôi hoàn kích hoạt Thiên La chân lôi tạo lôi vân tử sắc hơn mười trượng bao phủ Man Hồ Tử. Man Hồ Tử cũng nguyên anh xuất khiếu, dùng tiểu thuẫn gắn Hấp Lôi thạch (đoạt từ Lôi Kình yêu thú) hấp thu hơn phân nửa uy lực lôi điện, thoát ra chỉ bị thương nhẹ. Vạn Thiên Minh thi triển Nguyên Anh ngự kiếm — thuấn di chân chính cưỡi tiểu kiếm tử sắc — chộp được Bổ Thiên đan, khiến bốn tu sĩ Nguyên Anh kỳ đang giao chiến đều kinh hãi. Tuy nhiên Man Hồ Tử đã bắt giữ thân thể vô chủ của Vạn Thiên Minh, đe dọa phá hủy — vì nguyên anh trung kỳ không thể tồn tại rời thân thể — buộc hắn giao nộp Bổ Thiên đan. Man Hồ Tử đoạt đan rồi ném thân Vạn Thiên Minh để phân tâm đối phương, hóa kim hồng tẩu thoát khỏi Hư Thiên Điện, không giết Vạn Thiên Minh vì kiêng dè Phong Bà Tử — đệ nhất tu sĩ chính đạo của Vạn Pháp môn. Thiên Ngộ Tử cùng lão giả gầy ốm chỉ hư trương thanh thế không toàn lực ngăn Cực Âm sư tổ và Thanh Dịch cư sĩ rời đi. Cực Âm sư tổ bay qua đầu Hàn Lập và Ô Sửu, ra lệnh hai người ở lại, để lại hai con yêu thi cho Ô Sửu sử dụng, rồi cùng tất cả tu sĩ Nguyên Anh kỳ phá vỡ màn bảo hộ thềm đá đuổi theo Man Hồ Tử."},{"chuong":487,"tieuDe":"Ô Sửu Chi Tử","tomTat":"Sau khi Vạn Thiên Minh đoạt Bổ Thiên đan, Ô Sửu ngừng giao đấu với Huyền Cốt vì nhận ra yếu hơn nhiều, nhưng tự tin trở lại khi hai Thiên Đô yêu thi xuất hiện. Huyền Cốt hỏi Hàn Lập ý kiến rồi ra tay giết Ô Sửu: dùng thanh sắc quái xà phối hợp hoa sen lục phong ấn yêu thi, tay không bắt bổn mạng tiểu kiếm của Ô Sửu, rồi dùng quỷ trảo xuyên bụng thiêu thành tro bằng lục hỏa. Huyền Cốt thu tất cả di vật và tiết lộ bí mật: năm xưa chính hắn tìm được một đôi Huyết Ngọc Tri Thù giao cho nghịch đồ Cực Huyễn nuôi dưỡng, loài này mỗi lứa chỉ hai trứng sống nhất định thư hùng, phải thành đôi mới thăng cấp. Huyền Cốt phát hiện Hàn Lập còn giấu con Huyết Ngọc Tri Thù thứ hai và muốn ép hợp tác đoạt Hư Thiên Đỉnh. Hàn Lập từ chối vì lo động tĩnh quá lớn thu hút tu sĩ Nguyên Anh Kỳ, quyết định bỏ chạy nhưng vừa phi độn lên thì bị Huyền Cốt nói một câu kiềm hãm lại."},{"chuong":488,"tieuDe":"Bảo Đỉnh Tái Hiện","tomTat":"Huyền Cốt tiết lộ cho Hàn Lập công hiệu thật của Bổ Thiên Đan: không phải đột phá bình cảnh Nguyên Anh mà là tẩy luyện tiên thiên linh căn tu sĩ Kết Đan Kỳ, tăng tỉ lệ ngưng kết Nguyên Anh thêm ba bốn phần khi kết hợp Cửu Khúc Linh Sâm. Huyền Cốt tự nhận là sư phụ Cực Âm lão tổ, thi triển Luyện Thi thuật biến thi thể Huyết Ngọc Tri Thù bị chặt đôi thành yêu thi có thể chiến đấu. Hai bên đạt thỏa thuận liên thủ đoạt bảo: Bổ Thiên Đan toàn bộ thuộc Hàn Lập, cổ bảo chia đôi, Hư Thiên Đỉnh giao Huyền Cốt. Huyền Cốt giao ngọc giản luyện chế Cửu Khúc Linh Sâm làm tín vật, Hàn Lập kiểm tra rồi chấp thuận. Hai con Tri Thù phối hợp phun thù võng kéo Hư Thiên Đỉnh lên lần hai, tốc độ chậm hơn trước rất nhiều. Hàn Lập toàn lực vận chuyển Thanh Nguyên kiếm quyết chống hàn khí nhưng vẫn lạnh tận xương, nhận ra khoảng cách cực lớn giữa Kết Đan Kỳ và Nguyên Anh Kỳ. Cuối cùng lam hỏa xuất hiện, đài cao biến thành thế giới băng, bóng đen Hư Thiên Đỉnh lộ diện và Hàn Lập lần đầu quan sát chân diện mục bảo đỉnh."},{"chuong":489,"tieuDe":"Thu Đỉnh","tomTat":"Hư Thiên đỉnh bay ra khỏi động khẩu, Kiềm Lam Băng Diễm bùng phát đóng băng toàn bộ mười trượng quanh tế đàn. Hàn Lập và Huyền Cốt kịp thoát ra ngoài vùng băng phong. Huyền Cốt chủ động nhận đối phó băng diễm, thi triển Huyền hồn quỷ hỏa tạo hỏa trụ xanh đen rồi biến thành hoa sen lớn tách Kiềm Lam Băng Diễm khỏi Hư Thiên đỉnh. Hàn Lập lệnh Huyết Ngọc Tri Thù lôi kéo, dùng kiếm quang và chân nguyên thu nhỏ bảo đỉnh vào lòng bàn tay, chính thức sở hữu đệ nhất bảo vật Loạn Tinh Hải. Huyền Cốt lập tức cười điên cuồng tiết lộ mục đích thật: dung hợp Kiềm Lam Băng Diễm, Huyền hồn âm tỏa và Ích tà thần lôi thành Tu La thanh hỏa truyền thuyết, rồi tuyên bố giết Hàn Lập đoạt bảo. Hàn Lập không lãng phí lời, ra tay trước phóng ngũ xuyến đồng hoàn khóa chặt cổ và tứ chi lão ma, mở đầu trận đối đầu quyết liệt."},{"chuong":490,"tieuDe":"Ích Tà Thần Lôi Và Tu La Thánh Hỏa","tomTat":"Hàn Lập dùng cổ bảo Ngũ xuyến đồng hoàn trói Huyền Cốt nhưng lão ma dùng lam sắc băng diễm đóng băng và vẩy rơi, tuyên bố Ngũ Hành hoàn vô dụng với Dị linh căn và bàng môn tả đạo. Hàn Lập phóng bảy thanh tiểu kiếm hợp cự kiếm, thi triển Kiếm Ảnh Phân Quang thuật trong Thanh Nguyên công pháp phân thành ba thanh, phóng Ích Tà Thần Lôi chống băng long ngũ trảo và băng thuẫn tam giác của Huyền Cốt, hai bên giằng co không bên nào áp chế. Hàn Lập khoác áo choàng đỏ chuẩn bị đường rút, rồi tập trung toàn bộ Ích Tà Thần Lôi tạo lôi cầu khổng lồ khiến Huyền Cốt mặt trắng bệch kinh hãi vì không ngờ đối phương có quá nhiều phi kiếm Kim Lôi trúc. Nội tâm Huyền Cốt hé lộ dã tâm: đoạt lam sắc băng diễm để tu thành Tu La thánh hỏa xưng bá Loạn Tinh hải, đã cấu kết Man Hồ Tử để diệt Cực Âm lão tổ mà không cần Hàn Lập. Lâm thế cưỡi hổ, Huyền Cốt liều mạng hợp nhất lam sắc băng diễm, Huyền Hồn âm hỏa và hắc sắc điện hồ thành Tu La thánh hỏa xám trắng cực lạnh tấn công. Hàn Lập biến lôi cầu thành điện võng kim sắc phòng thủ, hai bên đối công dữ dội, chương kết ở thế giằng co."},{"chuong":491,"tieuDe":"Huyền Cốt Chi Tử","tomTat":"Hàn Lập bị Tu La thánh hỏa của Huyền Cốt vây khốn trong điện võng Ích Tà Thần Lôi, hỏa diễm liên tục thôn phệ khiến điện võng thu nhỏ dần. Hàn Lập bơm thêm thần lôi dự trữ phản công, khiến Huyền Cốt phải quyết định chuyển hóa toàn bộ lam sắc băng diễm thành Tu La thánh hỏa tổng tấn công. Khi thần lôi gần cạn, Hàn Lập phóng hết phần còn lại phá nổ điện võng thoát khỏi vòng vây, kích hoạt áo choàng đỏ cổ bảo định bay tới thạch đài đào thoát. Tuy nhiên quang cầu Tu La thánh hỏa của Huyền Cốt mất kiểm soát nổ tung do hạch tâm còn sót lam quang bất ổn — thánh hỏa không phải chân chính luyện hóa mà chỉ mượn ngoại lực thao túng. Hàn Lập chớp thời cơ bỏ ý đào thoát, bắn hơn mười đạo Thanh Nguyên kiếm quang chặn đường thoát Huyền Cốt. Huyền Cốt phun tiểu tiễn Kim Lôi trúc phá được vài đạo kiếm quang nhưng vẫn bị đánh trúng lùi lại, cuối cùng một tia Tu La thánh hỏa rơi trúng vai, bị thiêu thành tro bụi mà chết."},{"chuong":492,"tieuDe":"Kiền Lam Châu","tomTat":"Sau khi Huyền Cốt bị Tu La thánh hỏa thiêu chết, Kiền Lam Băng Diễm mất khống chế bùng phát toàn lực, đóng băng cả thạch đài thành núi băng khổng lồ. Hàn Lập dùng Bạch Tê bội phát bạch quang cực nóng chống hàn khí, pháp lực tiêu hao nhanh chóng suýt chết. Bất ngờ băng diễm tự lóe sáng ngưng kết thành viên băng châu màu lam, hàn khí hoàn toàn thu liễm. Hàn Lập dùng Ích Tà Thần Lôi cuối cùng phong ấn băng châu vào hộp ngọc, nhận định đây là bảo vật cấp trên Hư Thiên đỉnh, hoàn thành tâm nguyện sở hữu ma diễm. Hắn thu Huyết Ngọc Tri Chu bị đại thương vào túi linh thú, phát hiện khúc xương trắng bất hoại của Huyền Cốt không bị hỏa diễm hủy, suy đoán có thể chứa vật phẩm bên trong. Khi thử luyện hóa mũi tên Kim Lôi Trúc bằng đan hỏa không phản ứng, Hàn Lập dùng Đề Hồn thú phun hoàng quang, tiểu tiễn lập tức lóe lục quang kêu bén nhọn bay trốn, chứng tỏ có linh tính ẩn giấu sợ năng lực phệ hồn."},{"chuong":493,"tieuDe":"Họa Trục Chi Mê","tomTat":"Tàn hồn Huyền Cốt trú trong tiểu tiễn xanh cố trốn chạy nhưng bị Đề Hồn thú phóng hấp hồn thần quang cuốn lấy. Khuôn mặt quỷ già nua hiện ra cầu xin Hàn Lập tha mạng, đưa ra hàng loạt điều kiện dụ hoặc gồm tầng cuối Huyền Âm đại pháp, Huyền Hồn luyện yêu đại pháp, vị trí động phủ bí mật, nhược điểm công pháp Cực Âm lão tổ và giải ám ký truy tung. Hàn Lập giả vờ do dự khiến tàn hồn mất cảnh giác, rồi Đề Hồn thú tăng hấp lực gấp ba nuốt trọn thần thức Huyền Cốt, chính thức tiêu diệt. Nhờ lời cảnh báo, Hàn Lập thả mấy nghìn Phệ Kim trùng tìm ra ám ký truy tung ở cẳng chân. Hàn Lập phá cấm chế tầng năm bằng Thanh Trúc Phong Vân kiếm, thoát ra ngoài rồi mở quyển trục cổ phát hiện đó là sơ đồ nội điện năm tầng Hư Thiên điện với lộ tuyến đỏ duy nhất dẫn tới Truyền Tống trận. Cân nhắc rủi ro, Hàn Lập quyết định đi theo lộ tuyến đỏ, triệu cự viên khôi lỗi dò đường phía trước."},{"chuong":494,"tieuDe":"Diễm Nữ Và Linh Tuyền","tomTat":"Hàn Lập theo bản đồ mực đỏ trên quyển trục cũ kỹ tìm đến mật thất trong nội điện Hư Thiên điện, phát hiện bên trong có Truyền Tống trận thô sơ xiên xẹo nhưng vẫn hoạt động. Hắn cẩn thận trám lại lỗ thủng trên tường rồi đặt linh thạch kích hoạt trận, truyền tống đến một thạch thất rộng lớn ẩm ấm tỏa hương thơm. Trước mắt là hồ nước trắng sữa rộng vài chục trượng, Hàn Lập nhận ra đây là Linh nhãn chi tuyền chứa linh khí tinh thuần mà chủ nhân Hư Thiên điện đã chuyển dời đến. Trong hồ, Nguyên Dao đang xích lõa tắm, ban đầu xấu hổ yêu cầu hắn quay mặt nhưng hắn thẳng thắn từ chối, ngồi cạnh hồ bỏ chân xuống nước thưởng thức mỹ cảnh. Hàn Lập chú ý thấy bình ngọc xanh đặt dưới phù điêu đầu rồng bạch ngọc trên tường đá đang hứng thứ gì đó, Nguyên Dao biến sắc lo lắng khi hắn nhìn vào. Nguyên Dao nhanh chóng lấy lại bình tĩnh, chuyển sang thái độ kiều mị phong tình khiêu khích khiến Hàn Lập sững sờ mất cảnh giác. Trong sát na, nàng kích bức tường nước trắng sữa chắn tầm nhìn, bay lên bờ mặc đồ và lén giấu bình ngọc xanh, khi hắc khí tan thì bình đã biến mất vô ảnh vô tung."},{"chuong":495,"tieuDe":"Linh Nhũ Và Dưỡng Hồn Mộc","tomTat":"Bức tường nước hạ xuống, Hàn Lập và Nguyên Dao đối mặt tại mật thất tầng hai nội điện Hư Thiên điện. Hàn Lập giải thích do đụng phải cấm chế nên bị truyền tống tới đây, nhận ra ngâm linh tuyền đã giúp khôi phục một phần pháp lực. Hắn thử dùng Hư Thiên tàn đồ mở thạch môn cấm chế nhưng hoàn toàn vô hiệu — tàn đồ không thể mở cấm chế từ bên trong. Nguyên Dao chặn Hàn Lập lại, thừa nhận một mình không kịp phá cấm chế trước kỳ hạn trở về, đề nghị hợp tác phá trận. Nàng đưa ra giao dịch: tặng nửa bình Vạn niên linh nhũ — linh dịch huyền thoại hồi phục pháp lực tức thì do linh tuyền vạn năm sản sinh — để đổi lấy Hàn Lập nhường bảo vật bên trong. Dưới áp lực của Hàn Lập, Nguyên Dao tiết lộ bảo vật ẩn trong mật thất là Dưỡng Hồn mộc, một trong ba loại thần mộc có thể bồi dưỡng hồn phách và tăng cường thần thức, và nàng cần nó để ký gửi hồn phách bảo vệ thần trí không tiêu tán. Hàn Lập chưa đưa ra quyết định, lẩm nhẩm tên hai bảo vật cân nhắc."},{"chuong":496,"tieuDe":"Chân Giả Nan Biện","tomTat":"Hàn Lập đàm phán với Nguyên Dao, thỏa thuận chỉ lấy rễ nhỏ Dưỡng Hồn mộc và phần Vạn niên linh nhũ, nhường thân cây cho nàng. Nguyên Dao giải thích linh tuyền đã bị cấm chế gắn kết với nội điện, không thể thu. Hàn Lập tự cảnh tỉnh bản thân về lòng tham. Sau hai ngày hợp lực phá trận, cả hai bị truyền tống ra mặt biển bên ngoài Hư Thiên điện, Hàn Lập lập tức cáo từ hóa cầu vồng bay đi. Nguyên Dao lấy ra cây Dưỡng Hồn mộc, gọi tên Nghiên tỷ tỷ, hứa sẽ tìm người luyện chế thành Tàng hồn hộp để cứu tỷ thoát khỏi thuật luyện hồn, rồi phủ hắc bào hóa hắc khí bay đi. Trong khi đó tại nội điện Hư Thiên điện, các tu sĩ Nguyên Anh kỳ chính-ma lưỡng đạo tranh cãi gay gắt về ba người mất tích và Hư Thiên đỉnh bị cướp. Cực Âm lão tổ xác nhận ái tôn Ô Sửu đã chết qua bí thuật thăm dò, nghi Man Hồ Tử cấu kết Huyền Cốt. Man Hồ Tử phản pháo, trong lòng nghi Huyền Cốt phản bội ước định, khuấy nước đục bằng cách đề xuất khả năng hai trưởng lão Tinh Cung vẫn ẩn nấp, tiêu diệt ba người rồi lấy Hư Thiên đỉnh."},{"chuong":497,"tieuDe":"Lang Hình Khí Linh","tomTat":"Sau khi rời Nguyên Dao, Hàn Lập lấy Hư Thiên đỉnh ra nghiên cứu nhưng không thể mở nắp bằng bất kỳ cách nào, phỏng đoán cần tu vi Nguyên Anh kỳ hoặc yếu quyết liên quan Kiền lam băng diễm. Hắn khám phá hai thần thông của Ngọc Như Ý: vòng bảo hộ đỏ-vàng phòng ngự cực mạnh, và niệm chú thượng cổ triệu hoán lang hình khí linh — tiểu lang đỏ hỏa thuộc tính, tiểu lang vàng thổ thuộc tính biết Thổ độn chi thuật, cùng ngân sắc cự lang là khí linh chân chính nhưng bướng bỉnh chưa bị luyện hóa hoàn toàn. Hàn Lập sắp xếp chiến lợi phẩm: cất nhẫn, Hàn băng châu, Linh Tê bội vào túi trữ vật, chỉ giữ Hoàng Lân giáp mặc trên người. Hắn nhận ra viên châu ngũ sắc có màu giống Bổ Thiên đan, khẳng định hài cốt ngũ sắc tám chín phần là Cực Huyễn — nghịch đồ của Huyền Cốt. Dùng huyết sắc phi phong gấp rút bay về Thiên Tinh thành để lấy Phệ Kim trùng, kế hoạch qua Truyền Tống trận đi Ngoại Tinh hải đột phá Kết Đan sơ kỳ. Trên đường thấy tu sĩ Kết Đan kỳ cảnh giác bất thường, chặn đội tu sĩ Tam Tinh tông được biết Thiên Tinh thành vừa xảy ra đại sự, cơ hồ tất cả tông môn thế lực đều phái người đến."},{"chuong":498,"tieuDe":"Nghịch Tinh Minh","tomTat":"Hàn Lập vừa ra khỏi bế quan, chặn nhóm tu sĩ Tam Tinh tông trên biển hỏi tình hình. Lão giả dẫn đầu nhóm cho biết khắp Loạn Tinh Hải lan tin Nguyên Từ thần quang của Thiên Tinh Song Thánh đã đại thành, Tinh Cung nhân đó phát Thiên Tinh lệnh bắt tất cả thủ lĩnh tông phái đến diện kiến, đe dọa tiêu diệt kẻ bất tuân. Không lâu sau, Chính đạo và Ma đạo tuyên bố liên thủ thành lập Nghịch Tinh minh do Vạn Tam Cô và Lục đạo cực thánh đứng đầu, phát Nghịch Tinh lệnh đối kháng, tấn công ngoại đảo Thiên Tinh thành và chiếm thế thượng phong. Hàn Lập xem ngọc giản phục chế hình dạng Nghịch Tinh lệnh, nhận ra mặt quỷ trên lệnh bài gần giống lệnh bài trưởng lão Lục Liên điện đưa Ô Sửu, suy ra chính ma đã sớm câu kết cài nội gian. Phân tích lợi hại: đại chiến khiến lão quái truy đuổi Hư Thiên đỉnh phải phân tâm, nhưng khó vào Thiên Tinh thành dùng Truyền Tống trận thoát ra Ngoại Tinh hải. Hàn Lập cắn răng uống Vạn niên linh nhũ, dùng Huyết sắc phi phong phi hành nửa tháng liên tục với tốc độ ngang Nguyên Anh kỳ hướng về Thiên Tinh thành, các tu sĩ Kết Đan kỳ trên đường đều tưởng nhầm là cao nhân Nguyên Anh mà tránh xa."},{"chuong":499,"tieuDe":"Nam Minh Đảo","tomTat":"Hàn Lập đến gần hải vực Thiên Tinh thành, cất Huyết sắc phi phong dùng độn quang bình thường để tránh thu hút sự chú ý của tu sĩ Nguyên Anh kỳ. Dừng chân tại Nam Minh đảo — điểm trung chuyển cuối cùng trước Thiên Tinh thành — để bổ sung vật tư, phát hiện phường thị vắng vẻ hơn trước do đại chiến sắp đến, an ninh thắt chặt với ít nhất ba Kết Đan kỳ quét thần thức. Hắn mang phương thuốc Huyền Cốt lão ma cấp tìm nguyên liệu luyện Cửu Khúc Linh Sâm, còn thiếu hai loại cuối: Thiên Diệp lộ (chưởng quỹ chưa từng nghe, có thể là tên thượng cổ đã đổi) và Mã Não giác (độc giác Mã não thú, cực hiếm). Hắn mua lượng lớn phương thuốc và nguyên liệu phụ trợ chuẩn bị cho chuyến đi Ngoại Tinh hải dài ngày. Khi bay đến gần cảng lúc trời tối, chứng kiến hơn một nghìn tu sĩ Nghịch Tinh minh tấn công đại trận bảo vệ cảng khẩu, đại chiến chính thức bùng nổ. Hàn Lập dùng ẩn nặc thuật biến mất, phóng thần thức quan sát — xác nhận gần đó có năm sáu Kết Đan kỳ nhưng không có Nguyên Anh kỳ, phán đoán tấn công này hẳn do tu sĩ Nguyên Anh chủ sự. Quyết định đợi đại chiến kết thúc rồi lặng lẽ rời đi."},{"chuong":500,"tieuDe":"Bàn Tra","tomTat":"Trận đại chiến tại bến cảng Nam Minh đảo kết thúc với chiến thắng áp đảo của Nghịch Minh Tinh — liên thủ chính ma lưỡng đạo phá vỡ đại trận phòng thủ hồng quang của Tinh Cung, tu sĩ Tinh Cung nhân lúc hồi quang phản chiếu gây loạn mà tẩu thoát về các hướng. Hộ pháp Thương Vân Long (Kết Đan sơ kỳ) tuyên bố kiểm soát đảo, yêu cầu tất cả tu sĩ chứng minh thân phận mới được rời đi. Hàn Lập ẩn thân quan sát, phân tích chính ma đã sớm có chủ ý đánh chiếm Loạn Tinh Hải, nhận định Nam Minh đảo là bàn đạp tiến công Thiên Tinh Thành, suy đoán Tinh Cung cố ý bị động chờ Thiên Tinh Song Thánh xuất quan. Khi đến lượt bàn tra, Hàn Lập dùng yêu bài Khách khanh trưởng lão Diệu Âm Môn do Tử Linh Tiên Tử tặng trước đây để xưng họ Hàn, qua mặt Thương Vân Long. Thương Vân Long nhờ hắn nói tốt cho thiếu chủ Nghịch Minh Tinh (truyền nhân duy nhất của Thánh tổ, ngưỡng mộ Tử Linh Tiên Tử), Hàn Lập đáp ứng rồi bình thản rời đảo, lão giả nhìn theo với vẻ mặt cổ quái."},{"chuong":501,"tieuDe":"Trùng Đột Tái Khởi","tomTat":"Sau khi Hàn Lập dùng thân phận trưởng lão Diệu Âm môn đi qua cảng khẩu Nghịch Minh Tinh, hai hộ pháp Thương Vân Long và Lưu hộ pháp bàn luận về sát khí kinh người trên người hắn. Thương hộ pháp nhờ tu luyện Thất Sát Quyết nên cảm ứng được sát khí dày đặc, nhận định Hàn Lập có Liễm khí thuật thần diệu che giấu chín phần mười và độc đấu cả hai đều không phải đối thủ. Hai người bày kế sau đại chiến sẽ lấy cớ Diệu Âm môn tư thông Tinh Cung để ép khuất phục, bắt Tử Linh Tiên Tử dâng cho Thiếu chủ Nghịch Minh Tinh (đã Kết Đan hậu kỳ, tu công pháp cần mỹ nữ), đồng thời cưỡng ép Hàn Lập dâng pháp quyết tụ sát khí. Hàn Lập bị thần thức lão quái Nguyên Anh kỳ dò xét từ trên không nhưng nhờ không biến hóa dung mạo nên vượt qua an toàn. Bay nửa ngày về hướng Thiên Tinh thành, hắn bị hai tu sĩ Kết Đan sơ kỳ Nghịch Minh Tinh — nho sinh mặt trắng và đại hán da đen — chặn đường, nghi là tu sĩ Tinh Cung giả dạng, yêu cầu đi theo. Hàn Lập tức giận nhưng chưa phát tác, chương kết ở thế đối đầu."},{"chuong":502,"tieuDe":"Cổ Bảo Chi Uy","tomTat":"Hàn Lập giả vờ đồng ý đi cùng hai tu sĩ Kết Đan kỳ Nghịch Tinh Minh rồi bất ngờ ra tay. Tay phải tung Thanh Trúc Phong Vân Kiếm tấn công đại hán, tay trái dùng Ngũ Hành Hoàn âm thầm phong tỏa cổ và tứ chi nho sinh khiến mất toàn bộ chân nguyên. Nho sinh sở hữu Mê Huyễn Nghiên luyện bằng phương pháp cổ xưa nhưng không kịp thi triển thủ đoạn, bị Hàn Lập phát kiếm khí xuyên thủng giết chết tại chỗ. Giỏ hoa trúc cổ bảo phóng bạch quang nuốt trọn quái điểu và bao trùm đại ấn bạch ngọc. Đại hán thấy đồng đảng chết liền vứt pháp bảo bỏ chạy nhưng bị Ngũ Hành Hoàn phong tỏa, rơi xuống và bị chém đôi. Hàn Lập nhận ra Ích Tà Thần Lôi trong kiếm uy lực chưa đủ do tu luyện quá ngắn. Thu chiến lợi phẩm gồm hai túi trữ vật, đại ấn bạch ngọc và Mê Huyễn Nghiên. Sau đó phát hiện có người bí ẩn ẩn náu dưới biển, gọi ra — đối phương cuối cùng nhịn không được lên tiếng xin ra, danh tính chưa lộ."},{"chuong":503,"tieuDe":"Lăng Ngọc Linh","tomTat":"Sau khi Hàn Lập hạ sát hai tu sĩ Nghịch Tinh Minh, Lăng Ngọc Linh — Ngoại sự chấp pháp Tinh Cung — từ dưới nước bay lên cảm tạ cứu mạng. Người này dung mạo tuyệt mỹ, hoàn toàn không phân biệt được nam nữ, khiến Hàn Lập liên tưởng đến Điền Bất Khuyết nhưng nhận định hai người hoàn toàn khác nhau. Lăng Ngọc Linh đề nghị dẫn Hàn Lập vào Thiên Tinh thành đang giới nghiêm và chiêu dụ gia nhập Tinh Cung, nhưng Hàn Lập uyển chuyển từ chối bằng danh nghĩa khách khanh trưởng lão Diệu Âm môn. Gần đến thành, hai người gặp đội tuần tra do tu sĩ mặt vàng Kết Đan sơ kỳ (sư huynh Lăng Ngọc Linh) dẫn đầu. Lăng Ngọc Linh thừa nhận bị pháp bảo đánh trúng nhưng có Thiên Hương Tác hộ thân, nhận Thiên Linh đan từ sư huynh rồi giao Hàn Lập cho sư huynh dẫn vào thành, còn mình vào cung bẩm báo tình hình Nam Minh đảo bị tập kích. Khi Lăng Ngọc Linh chuyển thái độ mềm mại phong tình, tu sĩ mặt vàng tỏ ra mê mẩn, khiến Hàn Lập nghi ngờ đây thực sự là nữ nhân."},{"chuong":504,"tieuDe":"Truyện Tống Dữ Điều Kiện","tomTat":"Triệu hộ pháp kiểm tra thân phận Hàn Lập bằng lệnh bài trưởng lão Diệu Âm Môn và ngọc giản đối chiếu bức họa, xác nhận Hàn Lập là thật rồi hộ tống bay về Thiên Tinh thành. Dọc đường Hàn Lập dùng thần thức phát hiện ít nhất bốn năm tu sĩ ẩn mặt gồm hai vị Kết Đan kỳ, nhận ra an ninh thắt chặt sau vụ Nam Minh đảo bị tập kích. Tại cửa thành, Vu hộ pháp — tu sĩ Kết Đan trung kỳ — tiếp nhận Hàn Lập, nhắc quen biết Tử Linh Tiên Tử và tiết lộ giới tính thật của Lăng Ngọc Linh ngay cả Tinh Cung cũng ít ai biết. Vu hộ pháp đưa hai phương án: tham chiến tự do hoạt động có thù lao, hoặc không tham chiến bị hạn chế khi giới nghiêm, vi phạm sẽ bị đội chấp pháp giết không tha. Muốn dùng truyền tống trận đi Ngoại Tinh Hải phải giết một tu sĩ đồng cấp Nghịch Tinh Minh trong đại chiến chính thức. Hàn Lập nhận ra chiến lược ép tu sĩ nhiễm máu địch chặn đường đầu hàng, quyết định báo danh tham chiến và nhận chiếc nhẫn vàng làm bằng chứng thành viên tạm thời Tinh Cung."},{"chuong":505,"tieuDe":"Liễu Ám Hoa Minh","tomTat":"Hàn Lập đeo nhẫn vàng xác nhận thân phận, đi vào Thiên Tinh thành đang trong trạng thái giới nghiêm, đường phố vắng vẻ tiêu điều. Hắn bay về động phủ tầng 39 Thánh sơn sau gần trăm năm xa cách, kiểm tra Phệ Kim Trùng bình an vô sự rồi thu vào túi linh thú, đồng thời hái hết linh dược dược viên để chuẩn bị sẵn sàng rời đi. Lo sợ cao tầng Tinh Cung phát hiện Hư Thiên Đỉnh trên người hoặc đặt thêm điều kiện mới, Hàn Lập quyết định ngay từ đầu không thật lòng chờ đợi mà tìm cách lén dùng Truyền tống trận trốn đi, chấp nhận đắc tội Tinh Cung. Hắn bay lên tầng 50 Thánh sơn dò thám Tinh Không Điện, phát hiện cấm chế màu vàng xanh bảo vệ bên trong và đánh giá canh giữ nhiều nhất là tu sĩ Kết Đan trung-hậu kỳ. Trên đường về, hắn tình cờ nghe lén hai tán tu Trúc Cơ trung kỳ bàn chuyện hối lộ người canh giữ Truyền tống trận 5000 linh thạch mỗi người để truyền tống ra Ngoại Tinh Hải — người canh giữ chỉ dám làm với tu sĩ Trúc Cơ, tuyệt không dám với Kết Đan. Hàn Lập nghe xong trong lòng chợt động, phát hiện một con đường mới cho kế hoạch trốn đi."},{"chuong":506,"tieuDe":"Định Kế","tomTat":"Hàn Lập dùng tia thần thức đã gài sẵn trên người hán tử cao gầy bám theo hai tu sĩ tới tầng thứ tư Thánh sơn, lẻn vào trạch viện nhờ ẩn thân thuật vượt qua trận pháp Lưu thủy trận mà không bị phát hiện. Hắn phóng thần thức quét sương phòng, phát hiện nhóm bảy tu sĩ Trúc Cơ đang bàn bạc. Người có tu vi cao nhất là đại hán cẩm y mũi ưng Dịch đạo hữu (Trúc Cơ hậu kỳ sắp giả đan), phân tích rằng tham gia đại chiến thì tu sĩ cấp thấp chỉ là bia đỡ đạn, ngay Kết Đan kỳ cũng khó bảo mạng, Tinh Cung hiện tại không đáng tin. Nhóm quyết định chi 5000 linh thạch mỗi người lén truyền tống ra Ngoại Tinh hải trước đại chiến, sai Trương đạo hữu tới Tinh Không điện đàm phán giảm giá, hạn chót ngày mốt phải rời đi. Hôm sau Hàn Lập tiếp tục theo dõi, phát hiện hán tử cao gầy rời Tinh Không điện vẻ hưng phấn nhưng cố ý đổi sang sắc mặt sầu khổ trước khi vào trạch viện gặp đồng bạn. Hàn Lập nhận ra có khuất tất, nghi Trương đạo hữu có âm mưu phản bội, chìm vào trầm tư."},{"chuong":507,"tieuDe":"Hỗn Nhập","tomTat":"Sáng sớm ngày thứ ba, nhóm bảy người do đại hán cẩm y họ Dịch dẫn đầu lẳng lặng rời trang viên, bay tới tầng bốn mươi chín Thánh sơn hướng về Tinh Không Điện để sử dụng Truyền tống trận đi Ngoại Tinh Hải. Trên đường, Hàn Lập giả dạng tu sĩ xưng họ Khúc, tu vi giả đan, ẩn hình chặn đường nhóm. Hắn nắm rõ hành tung và tên tuổi thủ lĩnh, uy hiếp bằng lời đe dọa gọi người Tinh Cung tới, buộc đại hán cẩm y phải đồng ý cho đi theo. Tới Tinh Không Điện, hai tu sĩ áo trắng Tinh Cung (Cố tiền bối, Kiền tiền bối) đã chờ sẵn, lén mở trận thu linh thạch cấp Truyền tống phù. Khi Hàn Lập đề nghị trả gấp đôi để lấy suất, Kiền tiền bối từ chối vì trận chỉ truyền tối đa bảy người và chỉ dám mở một lần. Hàn Lập không khách khí quay sang một thành viên trong nhóm yêu cầu nhượng suất, khiến người đó ngạc nhiên."},{"chuong":508,"tieuDe":"Yếu Hiệp","tomTat":"Hàn Lập cải trang thành Khúc đạo hữu bằng Luyện khí thuật thu liễm tu vi, uy hiếp hán tử gầy gò (Trương đạo hữu) bằng bí mật hắn cấu kết hai tu sĩ Tinh Cung nâng giá truyền tống gạt người, kết hợp dụ dỗ bằng hai khối yêu đan cấp năm, buộc hắn nhường danh ngạch truyền tống. Trước đó Hàn Lập đã lén vào phòng hán tử gầy gò dùng mê hồn chi thuật kết hợp thần thức cường đại bắt đối phương thổ lộ bí mật. Hàn Lập tặng hai thanh phi đao pháp bảo (vốn của Hồ Nguyệt bị Huyền Cốt sát hại) cho hai tu sĩ Kết Đan Tinh Cung canh giữ Truyền tống trận (lão giả họ Cố và tu sĩ họ Kiền) để được đồng ý qua trận. Hai tu sĩ Kết Đan dùng ngọc bài trắng niệm chú dỡ cấm chế trên Truyền tống trận, lão giả họ Cố tiết lộ hôm nay may mắn vì người thứ ba thường trực trong điện đã ra ngoài. Hàn Lập dùng thần thức quét xác nhận an toàn rồi bước lên Truyền tống trận đầu tiên, tấm bia phía trước ghi hai chữ Kỳ Uyên — một địa danh hoàn toàn xa lạ."},{"chuong":509,"tieuDe":"Tái Lâm Ngoại Hải","tomTat":"Hàn Lập cùng sáu đại hán cẩm y do Dịch Kính dẫn đầu bước vào Truyền tống trận tại Nội Tinh Hải. Tu sĩ họ Kiền kích hoạt trận, truyền tống cả bảy người tới Kỳ Uyên đảo ở Ngoại Tinh Hải. Sau khi nhóm đi, tu sĩ họ Kiền tiết lộ với Cố đạo hữu rằng nhờ linh thú Yếm Não phát hiện thần thức Hàn Lập cao thâm y hệt Trưởng lão Tinh Cung, nên đã dùng Truyền tống phù thật thay vì phù giả. Hai người kết luận Hàn Lập là tán tu Nguyên Anh Kỳ muốn tránh cuộc chiến sắp tới. Hán tử gầy gò nghe được bí mật, bị Cố đạo hữu chém chết đốt xác diệt khẩu. Tại Kỳ Uyên đảo, tu sĩ Tinh Cung gầy trông coi trận cho biết thượng cấp đã thu hồi hết Truyền tống phù, trận chỉ truyền tống một chiều. Tu sĩ áo tro Hứa Vân đang kẹt lại vì muốn về Nội Tinh Hải luyện đan cho con trai nhưng không được. Dịch Kính xưng tên kết giao Hứa Vân, thông báo chính ma lưỡng đạo hợp sức lập Nghịch Tinh Minh, đại chiến sắp nổ ra, và đề nghị đổi thông tin tình hình Kỳ Uyên đảo. Hàn Lập đứng ngoài khoanh tay im lặng quan sát."},{"chuong":510,"tieuDe":"Hắc Thạch Thành","tomTat":"Đám người rời nhà đá Truyền tống trận, phát hiện mình đang ở bên trong Hắc Thạch thành — tòa thành toàn bằng đá đen trên Kỳ Uyên Đảo, hoàn toàn khác với tư liệu về Yêu Thú đảo mà họ chuẩn bị trước. Đại hán cẩm y chủ động mời Hàn Lập cùng nghe chuyện với ý muốn hợp tác, nhưng trung niên mặt đen phủ nhận quan hệ đồng hành. Hứa Vân tiết lộ sự thật chấn động: tin tức về Kỳ Uyên Đảo trước đây đại bộ phận là ngụy tạo, đảo bị một thế lực cường đại thống trị mà Tinh Cung cũng không dám đắc tội. Hắc Thạch thành là tòa thành duy nhất trên đảo, thiên đường mua sắm với Song tu lô đỉnh cấp, pháp bảo cường đại và linh thú quý hiếm, nhưng nghiêm cấm đấu pháp — vi phạm sẽ bị hình thần câu diệt, luôn có tu sĩ Nguyên Anh Kỳ tọa trấn. Hứa Vân dẫn đám người vào một thạch phòng bí ẩn trong thành, nơi có nữ tu sĩ Trúc Cơ trung kỳ với vẻ phong tình quyến rũ đang tiếp khách, ngụ ý nơi này cung cấp dịch vụ đặc biệt."},{"chuong":511,"tieuDe":"Hải Uyên Yêu Thú","tomTat":"Nhóm Hàn Lập theo Hứa Vân vào Minh Châu hiên trên Kỳ Uyên đảo, nơi chuyên mua thu vật phẩm tu sĩ hải ngoại. Minh phu nhân, nữ chủ quán, thi triển mị thuật đánh giá định lực nhóm mới đến, nhận ra Hàn Lập và đại hán cẩm y tu vi không kém Hứa Vân nên chủ động thu mị ý lại. Hứa Vân tiết lộ bí mật quan trọng: hải vực phụ cận Kỳ Uyên đảo có Hải uyên yêu thú sâu không lường, thường xuất hiện yêu thú cấp bảy, thậm chí cấp tám tương đương Nguyên Anh Kỳ. Kỳ Uyên đảo là Yêu Thú đảo duy nhất do nhiều thế lực liên thủ khống chế thay vì bị tứ đại thương minh lũng đoạn, sau đại chiến được Tinh Cung hòa giải. Ai tiết lộ thông tin này ra Nội Tinh Hải sẽ bị liên thủ diệt khẩu. Nhóm vào Bảo thính xem đấu giá lam quang thạch, Hàn Lập không hứng thú với pháp khí cấp thấp."},{"chuong":512,"tieuDe":"Nữ Tu Lô Đỉnh","tomTat":"Hứa Vân dẫn nhóm Hàn Lập (giả danh Khúc huynh), Dịch Kính, Lưu phu nhân và những người khác đến phòng đấu giá thường xuyên tại Hắc Thạch thành. Hứa Vân giải thích Kỳ Uyên đảo khác các đảo yêu thú khác vì phụ cận có mỏ linh thạch và nguồn nguyên liệu tu luyện, có thể tự cấp tự túc, phàm nhân và tu sĩ cấp thấp di cư đến sinh sống. Thế lực quản lý Hắc Thạch thành đang dời nhân lực từ Nội Tinh Hải đến, dự kiến qua vạn năm nữa nơi đây thành Nội Tinh Hải thứ hai. Phiên đấu giá bắt đầu với trứng yêu thú Tử Vân Ưng cấp bốn — thân cứng như sắt, phi hành cực nhanh, lợi trảo phá hộ thuẫn Trúc Cơ kỳ — bán với 3.300 linh thạch, rẻ hơn nhiều so với Thiên Tinh thành. Hứa Vân giải thích trứng yêu thú là đặc sản vì đại bộ phận không thể truyền tống qua truyền tống trận. Sau đó lão giả chủ trì đưa ra hai nữ tu Luyện Khí kỳ xinh đẹp làm lô đỉnh cấp thấp với giá 2.000 linh thạch, hồi lâu không ai ra giá. Hàn Lập kinh ngạc vì Nội Tinh Hải không công khai đấu giá lô đỉnh. Hứa Vân giải thích các nữ tu đều tự nguyện do linh căn kém, không có cao nhân chống lưng, không thể tu luyện bình thường lên cấp cao."},{"chuong":513,"tieuDe":"Thốn Kim Các","tomTat":"Buổi đấu giá kết thúc với hai nữ tu lô đỉnh tu vi quá kém không ai mua, bị dẫn ra ngoài. Hàn Lập thương xót nhưng tự thấy khó bảo vệ bản thân nên không can thiệp. Hứa Vân dẫn nhóm rời Minh Châu hiên tham quan Hắc Thạch thành, giới thiệu khu phàm nhân và cửa hàng nguyên liệu lớn nhất thành — Thốn Kim Các. Nghe vậy Hàn Lập chủ động tách nhóm, dùng ánh mắt hàn mang uy hiếp Hứa Vân và đại hán cẩm y Dịch đạo hữu khiến họ toát mồ hôi lạnh không dám giữ. Hứa Vân truyền âm cảnh báo Dịch đạo hữu rằng Hàn Lập tu vi vượt xa họ, không nên đàm luận sau lưng. Hàn Lập vào Thốn Kim Các xuất tu vi Kết Đan kỳ, được quản sự Ly Tầm (Kết Đan sơ kỳ) đón tiếp ở gian khách quý. Hàn Lập nói muốn mua linh dược chỉ biết tên thời thượng cổ, Ly Tầm nhận lời và nhận Truyền tấn phù tra ra Hàn Lập mới đến Hắc Thạch thành, thái độ càng nhiệt tình. Ly Tầm gọi chuyên gia nguyên liệu thượng cổ Cổ Ngọc (Luyện Khí kỳ) đến hỗ trợ, Cổ Ngọc cung kính nhận mệnh."},{"chuong":514,"tieuDe":"Bạn Yêu Thảo","tomTat":"Hàn Lập hỏi Cổ Ngọc về Thiên Diệp Lộ, được Cổ Ngọc đưa ngọc giản chứa điển tịch cổ ghi chép liên quan. Tra ngọc giản, Hàn Lập xác nhận Thiên Diệp Lộ chính là Bạn Yêu Thảo dạng lỏng — linh thảo sinh gần yêu thú, hấp thu yêu khí mà thành — nhưng chỉ loại mọc gần yêu thú cấp tám mới có tác dụng, trong khi Hắc Thạch thành chỉ có yêu thú cấp bảy. Hàn Lập đổi đan dược tăng tu vi và phù bảo hình tiểu kiếm để giữ ngọc giản, đồng thời mua sừng Mã Não thú giá năm nghìn linh thạch từ cửa hàng Ly Tầm. Ly Tầm đề nghị giới thiệu tu sĩ Kết Đan cùng cấp để kết đội xuất hải, lộ ý muốn mượn sức Hàn Lập, nhưng Hàn Lập lấy cớ cần luyện đan bế quan để từ chối. Sau khi Hàn Lập rời đi, một người áo trắng bí ẩn khuôn mặt bị ánh sáng xanh che kín xuất hiện từ sau bức tranh sơn thủy, bàn bạc với Ly Tầm. Người này sở hữu Tàng Nặc thuật khiến tu sĩ cao hơn một bậc cũng không phát hiện, nhưng thừa nhận trong lúc nói chuyện luôn có cảm giác bị Hàn Lập giám sát, nghi ngờ Hàn Lập là Kết Đan hậu kỳ hoặc có công pháp, bảo vật đặc thù."},{"chuong":515,"tieuDe":"Vụ Trung Đảo","tomTat":"Hàn Lập rời Thốn Kim Các và Hắc Thạch thành, mua hải vực đồ nghiên cứu tình hình biển quanh Kỳ Uyên đảo, phát hiện phụ cận toàn khu vực nguy hiểm và Hải Uyên diện tích cực lớn chưa ai dò được độ sâu. Hắn bay hơn mười ngày về phía Bắc rồi chuyển hướng Tây tìm đảo hoang xây động phủ mới, tránh xa vùng tụ tập tu sĩ. Trong lúc truy đuổi yêu thú cấp bốn Ngân Dực Điểu, hắn bay vào sương và phát hiện hoang đảo thứ tư có linh mạch, bị sương trắng bao phủ hoàn toàn do đàn Thôn Hải Ngư dưới đáy đảo phun ra. Hàn Lập xẻ vào lòng núi xây động phủ trong nửa ngày, bố trận ảo giác che giấu dãy núi thành rừng cây, rồi luyện chế mười mấy bộ khí cụ bố trận trong 6-7 ngày tạo sương mù nhân tạo phòng thủ toàn đảo. Sau khi thu xếp trùng thất và linh thảo, hắn dùng thần thức đọc kỹ ngọc giản vàng mà Cổ Ngọc đưa, vẻ mặt vô cùng ngưng trọng, trầm tư rồi lấy ra hộp ngọc trắng chứa vài viên châu nhỏ màu sắc sặc sỡ."},{"chuong":516,"tieuDe":"Huyễn Diễm Nga","tomTat":"Hàn Lập đối chiếu hạt châu ngũ sắc luyện từ hài cốt Cực Huyễn với họa đồ trong ngọc giản mua ở Thốn Kim Các, xác định đây chính là Bổ Thiên Đan chân chính — tàn dư dược tính quá mạnh từng ngưng trong xương khi nghịch đồ Huyền Cốt vào Hư Thiên Đỉnh uống đan. Hàn Lập kiểm tra trùng thất năm gian: nhóm mấy vạn Phệ Kim Trùng có dấu hiệu tiến hóa tiếp, bắt đầu thôn phệ lẫn nhau; Đề Hồn Thú nằm ngủ suốt ngày chưa dám luyện hóa Minh Hồn Châu; Kim Ti Tằm bị Vạn Thiên Minh vứt bỏ đang hấp hối dù uống Tự Linh Hoàn. Hàn Lập biết bí mật Kim Ti Tằm có thể tiến hóa lần hai thành Huyễn Diễm Nga xếp thứ 17 bảng kỳ trùng với năng lực biến ảo, liền cho con to nhất ăn hai hạt châu ngũ sắc thí nghiệm. Sau đó trồng Cửu Khúc Linh Sâm trong dược viên với trận kỳ cấm chế, thả hóa thân bạch thỏ nhập về bản thể. Hàn Lập dùng toàn bộ lục dịch nuôi rễ Dưỡng Hồn Mộc, tin vài năm nữa sẽ tái hiện vạn năm. Cuối cùng phát hiện khúc xương trắng trong suốt của Huyền Cốt lão ma từng chịu được Tu La Thánh Hỏa rơi ra từ túi trữ vật, bắt đầu tò mò nghiên cứu."},{"chuong":517,"tieuDe":"Huyền Âm Kinh","tomTat":"Hàn Lập dùng Tụ Hồn Bát hút âm khí truyền vào khúc xương trắng thu được từ Huyền Cốt lão ma, kích hoạt nó thành ngọc giản đặc chế chứa toàn bộ Huyền Âm Kinh. Nửa trên là Huyền Âm đại pháp — công pháp ma đạo bá đạo, nửa dưới chứa các bí thuật ma đạo uy lực kinh người. Hắn không thể tu công pháp chính vì đã tu Thanh Nguyên kiếm quyết, nhưng chọn được hai ba bí thuật mà tu sĩ Kết Đan kỳ có thể luyện, đồng thời nắm được nhược điểm Thiên Đô Thi Hỏa để đối phó Cực Âm lão tổ. Sau đó dành nửa tháng dùng mọi biện pháp cố mở Hư Thiên Đỉnh nhưng thất bại hoàn toàn, nghi có liên quan Kiền Lam Băng Diễm nhưng tu vi chưa đủ thao túng. Quan sát hai con Kim Ti Tằm phục dụng châu ngũ sắc chưa có phản ứng, mấy vạn Phệ Kim Trùng bắt đầu thôn phệ lẫn nhau quy mô lớn chuẩn bị sản sinh thế hệ mới. Cuối cùng quyết định dùng toàn bộ luyện tinh từ Dung Nham lộ luyện hóa vào 72 thanh Thanh Trúc Phong Vân kiếm, ước tính tối thiểu nửa năm dùng pháp trận liên tục."},{"chuong":518,"tieuDe":"Hóa Hình Chi Kiếp","tomTat":"Hàn Lập bế quan gần một năm trong mật thất trên đảo nhỏ, hoàn thành tế luyện 72 thanh phi kiếm Thanh Trúc Phong Vân bằng luyện tinh và linh dịch vạn năm, quá trình khó hơn dự kiến. Khi vừa xong thì đảo chấn động dữ dội, sóng biển bao vây. Hắn dùng trận kỳ vàng kích hoạt cấm chế bảo vệ động phủ rồi bay ra ngoài quan sát. Trên biển gần đảo, một yêu thú hình rùa khổng lồ — Cự Quy — thể tích gần ngàn trượng đang chịu Hóa Hình Lôi Kiếp để tiến từ cấp bảy lên cấp tám, mây đen ngàn dặm phủ trời, lôi điện liên tục đánh xuống. Hàn Lập cân nhắc đánh lén sau khi yêu thú tổn hao nguyên khí nhưng phủ nhận vì thực lực cấp tám ngang Nguyên Anh kỳ, tiếc Phệ Kim Trùng chưa sẵn sàng, quyết định di dời động phủ. Khi vừa quay người, hắn phát hiện kim quang và hỏa hồng từ xa bay đến, đồng thời một cự thú toàn thân đỏ tươi phá nước trồi lên từ biển gần Cự Quy, phát tiếng rống kinh hồn khiến hắn suýt rơi — nhiều thế lực đang hội tụ về nơi độ kiếp."},{"chuong":519,"tieuDe":"Độc Giao","tomTat":"Hàn Lập nhận ra cự thú đỏ tươi dài trăm trượng chính là Độc Giao — yêu thú cấp tám hung danh, uy lực ngang Nguyên Anh kỳ, có thể đối đầu cấp chín không lọt hạ phong. Hắn lặng lẽ khoác Huyết sắc phi phong và lấy Ngũ Hành Hoàn phòng thân. Độc Giao thu nhỏ thân hình hóa hình thành nhân hình với đầu giao long, vảy hồng phủ khắp, liếc mắt xanh biếc lạnh lùng về phía Hàn Lập. Ba tu sĩ bay tới: Kim Hà đạo sĩ (Nguyên Anh sơ kỳ) và Hoắc thị huynh đệ (Kết Đan hậu kỳ, mang Phá Thiên Thần Sa), thương lượng hợp lực — Kim Hà lấy tinh hồn giao long, Hoắc thị lấy yêu đan cấp tám. Độc Giao chủ động ra tay trước, lấy một địch ba để trì hoãn bảo vệ cự quy đang độ kiếp: phun huyết quang tấn công Kim Hà, ẩn thân tập kích Hoắc thị huynh đệ từ phía sau. Hàn Lập thừa cơ rót toàn bộ pháp lực vào Huyết sắc phi phong hóa huyết quang trốn mấy ngàn dặm, ba bên chiến đấu nhận ra chỉ Kết Đan sơ kỳ nên bỏ qua. Sau vài ngày, Hàn Lập cẩn thận quay lại hải vực đã yên tĩnh, thả thần thức dò xét và lặn xuống biển nhặt được một món đồ."},{"chuong":520,"tieuDe":"Ngũ Sắc Châu Dữ Tân Phệ Kim Trùng","tomTat":"Hàn Lập thu dọn tàn tích trận chiến giữa tu sĩ Nguyên Anh và cự quy, ném đuôi cự quy và nửa quỷ đầu quải trượng xuống biển để tránh bị truy tìm. Hắn đổi ý ở lại đảo vì cự quy bị thương nặng sẽ không quay lại, bố trí thêm ảo trận và cấm chế phòng vệ. Phệ Kim Trùng sau khi thôn phệ lẫn nhau đẻ trứng có dấu hiệu biến dị bất thường với điểm đen trên vỏ, Hàn Lập dùng Khống Thần pháp trận lấy máu nhận chú toàn bộ. Hai con Kim Ti Tằm cuối cùng được cho ăn Nghê Thường Thảo, sinh trứng chết rồi chết theo, chủng Kim Ti Tằm tuyệt diệt hoàn toàn, qua đó nghiệm chứng Nghê Thường Thảo có tác dụng đề cao năng lực sinh sản yêu thú cấp cao. Hàn Lập bế quan nửa năm luyện hóa sáu viên Ngũ sắc châu bằng đan hỏa, mơ hồ nhận thấy tốc độ hấp thụ thiên địa linh khí và vận chuyển linh lực nhanh hơn trước. Phệ Kim Trùng thế hệ mới nở ra với thân vàng thêm đốm đen bên cạnh đốm bạc, uy lực vượt dự đoán do biến dị từ việc đời trước thôn phệ Thiết Hỏa Kiến. Tác giả hé lộ trận đại chiến đó là mồi lửa cho cuộc chiến giữa yêu thú và tu sĩ tại Loạn Tinh Hải, bộ tộc Giao Long bị chọc giận tham gia đồ sát tu sĩ nhân loại. Hàn Lập chuẩn bị ra biển săn yêu thú cấp cao, mang theo Nghê Thường Thảo, Huyết Ngọc Tri Thù, Đề Hồn, chia nửa Phệ Kim Trùng mới canh giữ động phủ."},{"chuong":521,"tieuDe":"Trừu Hồn Thủ Đan","tomTat":"Dưỡng Hồn Mộc trưởng thành sau hơn hai năm dùng lục dịch, Hàn Lập khắc thành chuỗi viên châu đen đeo cổ có diệu dụng dưỡng thần bồi hồn. Hắn rời động phủ bay về phía tây một tháng đến mảng san hô đỏ, bày bốn pháp trận vây kín, trồng Nghê Thường Thảo ở trung tâm dụ yêu thú. Trong thời gian chờ, ba lần ra lá dẫn tới ba bốn yêu thú cấp năm bị Hàn Lập dùng Thanh Trúc Phong Vân Kiếm dễ dàng chém giết. Nghê Thường Thảo sinh lá thứ tư dụ đến cự hà xanh sáu mắt cấp sáu — Hàn Lập dùng trận bàn xanh biếc nhốt, Ngũ Hành Hoàn trói chặt, kiếm quang chém đôi, rồi lần đầu thi triển Trừu Hồn thuật phóng bạch tuyến từ ngón tay rút hồn phách vào Tụ Hồn Bát, lấy nội đan cấp sáu. Hắn cắt giữ hai càng cự hà, đốt phần thừa, ung dung ngồi chờ con mồi tiếp theo."},{"chuong":522,"tieuDe":"Thâu Khuy","tomTat":"Bảy năm sau, tại hải vực Ngoại Tinh Hải, ba tu sĩ Kết Đan (lão giả Thu — trung kỳ, tu sĩ Mẫn và hán tử Tuyên — sơ kỳ) dẫn hơn mười tu sĩ Trúc Cơ tìm kiếm Lưu Ly thú cấp sáu đã nhiều ngày không thành. Ba người bàn luận tình hình: thâm uyên trên Kỳ Uyên Đảo từ hai năm trước yêu thú bạo động trở thành cấm địa, ngay cả Nguyên Anh kỳ liên thủ xông vào cũng chỉ còn Nguyên Anh sống sót. Tinh Cung và Nghịch Tinh Minh đang đại chiến quyết liệt, Truyền tống trận chỉ cho ra không cho vào, tu sĩ bị kẹt tại Ngoại Tinh Hải. Lão giả Thu phân tích trở về Nội Tinh Hải còn nguy hiểm hơn, đề xuất tìm hoang đảo ẩn náu. Đột nhiên phát hiện một thanh niên áo lam tu vi Kết Đan sơ kỳ một mình dụ và diệt Lưu Ly thú cấp sáu chỉ bằng một nhát kiếm — bảy đạo thanh quang hợp thành cự kiếm mười trượng, dùng chiêu ảo phân thân kiếm giết tức thì. Ba người kinh ngạc trước thực lực vượt xa tầm Kết Đan sơ kỳ, nghi ngờ ẩn giấu tu vi, ẩn thân quan sát rình mò toan tính cướp đoạt."},{"chuong":523,"tieuDe":"Hung Danh Thao Thiên","tomTat":"Ba tu sĩ lưu lạc Ngoại Tinh Hải (họ Thu, họ Tuyên, họ Mẫn) ẩn nấp quan sát thanh niên áo lam giết Lưu Ly Thú và thu hồn phách bằng bát đen. Lão giả họ Thu nhận ra đối phương chính là Trùng Ma — ma đầu khét tiếng trên Ngoại Tinh Hải. Ba người bàn tán về hung danh Trùng Ma: bốn năm trước hắn một mình diệt bảy tám tu sĩ Kết Đan kỳ của Bích Vân Môn khiến thế lực này mất gần một phần ba lực lượng, Thái thượng Trưởng lão Diệu Hạc chân nhân xuất hải truy tìm rồi biệt vô âm tín, và trong hai năm Trùng Ma đã giết không dưới trăm tu sĩ. Hàn Lập thu xong tinh hồn, nội đan, lột da trong suốt Lưu Ly Thú làm nguyên liệu hộ giáp, đốt xác rồi thu Nghê Thường Thảo và khí cụ bố trận đảo san hô. Phát hiện ba tu sĩ ẩn nấp, Hàn Lập gọi họ hiện thân nhưng cả ba hoảng sợ bỏ chạy. Hàn Lập tung ba túi linh thú, giáp trùng ba màu tuôn ra tụ thành ba thanh giáo khổng lồ truy đuổi theo ba hướng, bắt sống cả ba với vòng ba màu quanh cổ khống chế. Hàn Lập bình thản hỏi vì sao họ kinh hoàng bỏ chạy khi thấy hắn."},{"chuong":524,"tieuDe":"Bàn Vấn","tomTat":"Ba tu sĩ Kết Đan kỳ (lão giả họ Thu, tu sĩ họ Mẫn, đại hán họ Tuyên) hoảng sợ tưởng Hàn Lập là Trùng Ma khét tiếng, cầu xin tha mạng. Hàn Lập phủ nhận rồi phóng pháp quyết giải trừ vòng cổ giáp trùng trên cổ ba người, thu đàn trùng về túi linh thú. Lão giả họ Thu nhận ra thần thức Hàn Lập vượt xa mình, dặn dò đồng bạn coi Hàn Lập như lão quái Nguyên Anh kỳ. Ba người cùng bay đến đảo san hô gặp Hàn Lập để trả lời câu hỏi. Lão giả họ Thu thuật lại sự kiện thâm uyên kinh biến hai năm trước: yêu thú phát cuồng giết nhiều tu sĩ cao cấp, kể cả Nguyên Anh kỳ cũng phải bỏ chạy, thâm uyên trở thành vùng cấm. Hàn Lập trong lòng khiếp sợ, suy đoán Ngoại Tinh Hải sắp đại loạn. Tu sĩ họ Mẫn kể về Trùng Ma: sử dụng phi kiếm xanh, tướng mạo trẻ, tu vi Kết Đan kỳ, dùng vạn phi trùng, bốn năm trước một mình diệt bảy tám Kết Đan kỳ thành danh, sau giết hơn trăm tu sĩ đoạt bảo quanh Kỳ Duyên Đảo. Hàn Lập nhận ra đặc điểm trùng khớp hoàn toàn với mình, trong lòng đập loạn."},{"chuong":525,"tieuDe":"Chân Giả Trùng Ma","tomTat":"Ba tu sĩ họ Mẫn, lão giả mặt khô gầy và đại hán họ Tuyên nhận ra phi trùng của Hàn Lập là tam sắc giáp trùng, khác kim ngân lưỡng sắc của Trùng Ma thật, nên yên tâm được tha đi sau khi hứa giữ kín. Hàn Lập hồi tưởng lại trận chiến ở biển sâu Ngoại Tinh Hải: khi đang dùng Nghê Thường Thảo dụ yêu thú cấp bảy, bị 7-8 tu sĩ Kết Đan kỳ Bích Vân Môn muốn giết người đoạt bảo, hắn buộc phải thả hơn mười vạn Phệ Kim Trùng tiêu diệt gần hết, chỉ một Kết Đan hậu kỳ nhờ Cổ bảo thoát, đây là nguồn gốc biệt danh Trùng Ma và cừu hận với Bích Vân Môn. Sau trận đó hắn mạo hiểm ở biển sâu mấy năm, thu mấy trăm khối yêu đan cấp bảy. Hàn Lập phân tích nghi ngờ Bích Vân Môn tạo Trùng Ma giả nhưng phát hiện mâu thuẫn về loại phi trùng, rùng mình nghĩ đến khả năng lão quái Hư Thiên Điện truy tung, rồi quyết định bay về động phủ bế quan ít nhất 20-30 năm. Tại Hắc Thạch Thành trên Kỳ Uyên Đảo, Cực Âm lão tổ và đạo sĩ họ Tề thuộc Bích Vân Môn đang bàn mưu trong mật thất: đã hai ba năm phái đệ tử giả mạo Trùng Ma giết người đoạt bảo nhưng không hiệu quả, Cực Âm bất mãn. Đạo sĩ họ Tề tò mò hỏi lý do thật sự Cực Âm truy sát Hàn Lập, nghi ngờ cớ lệnh tôn chết chỉ là hàm hồ."},{"chuong":526,"tieuDe":"Ám Lưu Dũng Động","tomTat":"Tề đạo sĩ (cao nhân Nguyên Anh Kỳ Bích Vân Môn) đối chất Cực Âm Lão Tổ, vạch trần việc nhiều tu sĩ Nguyên Anh Kỳ từ Vạn Pháp Môn và các nơi tiềm nhập hải vực Kỳ Uyên Đảo truy tìm Hàn Lập. Bị dồn ép, Cực Âm thừa nhận tâm ma phát thệ đã vô hiệu do Vạn Thiên Minh tiết lộ trước, rồi truyền âm cho Tề đạo sĩ về bảo vật Hư Thiên Điện đã xuất thế. Tề đạo sĩ chấn động, vội cáo từ để phái thêm nhân thủ. Cực Âm ở lại tính toán mượn thế lực Bích Vân Môn truy tìm Hàn Lập. Trên hải vực, một thanh niên áo xanh mạo danh Trùng Ma dùng Phệ Kim Trùng màu bạc tàn sát mấy tu sĩ cấp thấp, tu sĩ mặt trắng Kết Đan Sơ Kỳ đến muộn bất lực. Nửa tháng sau, Hàn Lập trở về động phủ trên hải đảo sương mù, nghỉ ngơi hồi phục rồi vào đan thất, cảm nhận luyện đan thuật sắp đột phá cảnh giới mới gần đạt cấp đại sư, quyết định dùng yêu đan cấp năm luyện tập trước."},{"chuong":527,"tieuDe":"Bất Tốc Chi Khách","tomTat":"Hàn Lập xuất quan sau ba năm luyện đan, dùng yêu đan cấp năm luyện chế đan dược trân quý, luyện đan thuật nâng cao một tầng, tỉ lệ thành công với yêu đan cấp sáu, cấp bảy tăng đáng kể. Kiểm tra hai trùng thất, phát hiện Nghê Thường Thảo đã mất khả năng kích thích sinh sản đối với tam sắc Phệ Kim Trùng đã tiến hóa, chỉ còn hiệu quả với Phệ Kim Trùng kim ngân sắc chưa tiến hóa đang sắp sinh sản. Hàn Lập vào bế quan tu luyện tầng thứ tám Thanh Nguyên Kiếm Quyết, sau 15-16 năm phá tan chướng ngại Kết Đan trung kỳ, tiếp tục tu luyện tầng thứ chín, động phủ phủ bụi dày như di tích mộ cổ. Một buổi sáng, năm tu sĩ (một Trúc Cơ, bốn Luyện Khí) bị truy đuổi bay đến hải vực gần Vụ Hải, pháp lực cạn kiệt, phát hiện đảo động phủ Hàn Lập có linh khí tốt, hạ xuống hồi phục pháp lực."},{"chuong":528,"tieuDe":"Thanh Linh Môn","tomTat":"Một nhóm năm tu sĩ Thanh Linh Môn (dẫn đầu bởi trung niên tu sĩ Trúc Cơ kỳ, còn lại là Luyện Khí kỳ) đang hồi phục pháp lực trên đảo nhỏ giữa biển sau khi ra biển hái linh dược. Khi chuẩn bị lên đường thì bị mười mấy Ưng Diên Thú cấp hai bao vây chặn đường thoát. Nhóm chạy về phía rừng cây, vô tình lạc vào một ảo trận bí ẩn — cảnh vật đại biến thành núi non xa lạ với linh khí nồng đậm. Ưng Diên Thú không bị ảo giác nhưng vẫn tấn công, đúng lúc nguy cấp thì từ bên trong trận pháp phóng ra mười cự viên Khôi Lỗi, bắn hơn trăm cột sáng xuyên thủng toàn bộ yêu thú trong chớp mắt. Chủ nhân trận pháp là một nam tử đang bế quan, mời nhóm vào nhưng trung niên tu sĩ cẩn thận từ chối. Trong cuộc đối thoại, trung niên tu sĩ tiết lộ Thanh Linh Môn là môn phái nhỏ, trưởng lão Kết Đan kỳ duy nhất đã chết trong sự kiện thú triều hơn hai mươi năm trước. Khi nghe nhắc thú triều, nam tử bí ẩn tỏ ra kinh ngạc hỗn loạn — cho thấy hắn đã bế quan cách ly thế giới cực lâu, không hay biết biến cố lớn này."},{"chuong":529,"tieuDe":"Lãnh Mạc Dữ Khổ Cầu","tomTat":"Nam tử thần bí ẩn sau màn sáng (Hàn Lập) nghe trung niên tu sĩ Thanh Linh Môn kể về Thú Triều xảy ra hơn hai mươi năm trước: hơn vạn yêu thú từ Thâm uyên hải vực tấn công Kỳ Uyên Đảo, phá hủy Hắc Thạch Thành, hai vị Nguyên Anh Kỳ tử trận, tu sĩ và phàm nhân gần như bị tàn sát. Nội Tinh Hải cắt đứt liên lạc, không viện binh, Ngoại Tinh Hải bị bỏ rơi. Các lão Nguyên Anh Kỳ sống sót đang bí mật chuẩn bị kế hoạch chiếm lại Kỳ Uyên Đảo. Thiếu nữ áo vàng Công Tôn Hạnh kể cha nàng vì muốn dịch kinh tẩy tủy cho con gái (nàng trời sinh thể chất bất thường) mà cưỡng tu tầng sáu Thanh Linh huyền công, dẫn đến chân nguyên nghịch chuyển, liệt giường nhiều năm. Nam tử thần bí chỉ nghe đã phán đoán chuẩn xác bệnh trạng nhưng lạnh lùng từ chối giúp. Công Tôn Hạnh quỳ rạp trước màn sáng thề nguyện làm nô tỳ, cho phép hạ cấm chế, cầu xin cứu cha. Chương kết thúc trong im lặng, nam tử không đáp."},{"chuong":530,"tieuDe":"Trĩ Nữ Lô Đỉnh","tomTat":"Nam tử thần bí tu luyện bình cảnh truyền âm qua cự viên Khôi Lỗi, đề nghị thiếu nữ Công Tôn Hạnh (Thanh Linh Môn) tự nguyện làm lô đỉnh song tu, đổi lấy ba viên Chí Nguyên Đan cứu phụ thân — chưởng môn Thanh Linh Môn đang bệnh nặng. Dù sư thúc trung niên và đồng môn phản đối kịch liệt, Công Tôn Hạnh quyết định hy sinh bản thân, ném bình đan dược cho sư thúc rồi chạy vào màn sáng. Sư thúc mở bình xác nhận đan dược luyện từ Yêu Đan là vật trân quý, buồn bã chấp nhận vì tương lai môn phái. Công Tôn Hạnh bị truyền tống đến tiểu sơn cốc — động phủ của nam tử thần bí, được bố trí thạch thất để ở. Trong lúc chờ nam tử bế quan hai ngày, nàng vượt qua sợ hãi ra ngoài thăm dò, bị cự viên chặn ở một số cửa nhưng được phép qua cửa khác, tìm thấy phòng chứa ngọc giản đủ màu với nội dung trận pháp và đạo luyện khí, tò mò đọc liên tiếp nhiều cái."},{"chuong":531,"tieuDe":"Tặng Bảo","tomTat":"Công Tôn Hạnh dùng thần thức xem hết ngọc giản trong thạch thất động phủ, phát hiện Kim Chân Công (đỉnh cấp công pháp toàn phái) và đặc biệt động tâm với Triền Ngọc Quyết — đỉnh cấp công pháp thích hợp nữ tử, vượt xa Thanh Linh Công trung cấp của môn phái mình. Nàng vào phòng chứa pháp bảo thấy hơn mười pháp bảo và gần trăm pháp khí đỉnh cấp, buồn bã khi nhớ thân phận lô đỉnh. Hai ngày sau Hàn Lập xuất quan, cho phép nàng tùy ý chọn công pháp, hỏi thăm phường thị trong hải vực và nhận ngọc giản hải đồ. Hắn vuốt tóc thiếu nữ hẹn buổi tối đến phòng ngủ, nhưng thực ra lặng lẽ rời đi, để lại khăn lụa ghi lời nhắn tặng toàn bộ động phủ kèm Triền Ngọc Quyết, số lượng lớn pháp khí, vài bình đan dược và hai kiện pháp bảo. Hàn Lập hào phóng vì kính trọng lòng hiếu xả thân cứu cha của Công Tôn Hạnh, liên tưởng tới thân ảnh tiểu muội và nỗi tiếc nuối không thể phụng dưỡng cha mẹ. Hắn hóa cầu vồng rời xa hòn đảo ngàn dặm, hướng tới phường thị."},{"chuong":532,"tieuDe":"Viện Thủ Diệt Yêu","tomTat":"Hàn Lập xuất quan sau hơn hai mươi năm bế quan, tu vi gần Kết Đan Hậu Kỳ nhưng gặp bình cảnh không thể đột phá dù dùng linh đan. Hắn mang theo Cửu Khúc Linh Sâm rời hòn đảo nhỏ trong vụ hải, lên đường tìm Bạn Yêu Thảo và phường thị. Trên đường đi, hắn lần đầu thi triển bí thuật Hoán Hình Quyết (thuộc Huyền Âm Kinh) để thay đổi diện mạo giấu thân phận, chấp nhận giới hạn bảy thành pháp lực. Hàn Lập gặp lão giả Hoàng Minh Lễ đang bị năm yêu thú cấp ba, bốn truy đuổi, ra tay cứu bằng kiếm quang và Thanh Nguyên Kiếm Quang, cố ý kìm tu vi. Hoàng Minh Lễ tiết lộ phường thị Nam Lê Đảo đã bị yêu thú cấp bốn, năm phá hủy mấy ngày trước. Lão đề nghị dẫn Hàn Lập tới một bí thị dành cho tu sĩ trên Trúc Cơ Kỳ, hàng hóa đều trân phẩm, lộ trình hơn nửa tháng. Hàn Lập đồng ý đi theo, trong lòng so sánh tâm tính Hoàng Minh Lễ với Công Tôn Hạnh."},{"chuong":533,"tieuDe":"Giao Hoán Hội","tomTat":"Hàn Lập mạo danh họ Lệ, tự xưng tu sĩ Kết Đan kỳ mới xuất quan, cùng Hoàng Minh Lễ bay nửa tháng đến một đảo nhỏ hướng đông ngoài hải vực. Cả hai sử dụng Ẩn nặc thuật thu liễm tu vi rồi vào phường thị ngầm dưới lòng đảo — không gian khổng lồ dùng Thạch Hóa thuật tạo thành, có hai tầng giao dịch và Thính Phong các cung cấp tình báo yêu thú. Hàn Lập tìm kiếm Bạn yêu thả loại sinh trưởng cạnh yêu thú cấp 8 nhưng không ai có, Thính Phong các cũng không có tin yêu thú trên cấp 7. Hắn thuê tĩnh thất tu luyện hai ngày, cố đột phá bình cảnh nhưng hoàn toàn không tiến triển. Khi được cô gái áo trắng mời dự Giao hoán hội dành cho tu sĩ Kết Đan kỳ, Hàn Lập nhận ra cô là người quen, chấn động trong lòng nhưng giấu kín. Cô gái dẫn hắn qua hai tầng đến bức tường đá hẻo lánh, ấn vào tường mở ra cửa đá có phù văn bao quanh — cổng vào Giao hoán hội."},{"chuong":534,"tieuDe":"Thân Cận Nữ Sắc","tomTat":"Hàn Lập giả danh Lệ đạo hữu bằng Hoán Hình quyết, được nữ tử dẫn đường đưa vào nơi tổ chức Giao hoán hội bí mật do Vân Thiên Khiếu (Kết Đan trung kỳ) chủ trì. Khi Vân Thiên Khiếu gọi nữ tử là Văn cô nương, Hàn Lập nhận ra nàng chính là Văn Tư Nguyệt — con gái cố nhân Văn Tường thuộc Diệu Âm môn — đang bị ép làm mĩ nữ phục vụ tu sĩ Kết Đan và rất sợ hãi Vân Thiên Khiếu. Phạm phu nhân (Phạm tả sứ Diệu Âm môn) xuất hiện thân thiết bên Vân Thiên Khiếu, Hàn Lập rùng mình suy đoán mối liên hệ. Theo quy tắc nơi này, Văn Tư Nguyệt dựa vào lòng Hàn Lập, hắn vô ý chạm ngực nàng rồi giật mình rút tay vì xấu hổ. Giao hoán hội bắt đầu, lão giả mập áo lam đưa ra Thiên Linh tử, yêu đan Ngọa Hổ Sa cấp sáu và da Hỏa Hải thú — Hàn Lập cười lạnh không thèm. Quái nhân cao gầy đưa ra trứng yêu thú Bàn Lê Dẫn cấp năm, khiến toàn bộ tu sĩ trong phòng lộ vẻ khát khao."},{"chuong":535,"tieuDe":"Tiêu Tức","tomTat":"Đại hội trao đổi tại bí thị tiếp diễn, các tu sĩ Kết Đan kỳ lần lượt đưa trân phẩm ra trao đổi. Tu sĩ trung niên da ngăm đen họ Tôn (Kết Đan trung kỳ) đưa ra miếng đồng khắc văn tự cổ quái và linh cốt yêu thú cấp tám, Vân Thiên Khiếu nhận dạng linh cốt khiến cả trường chấn động. Hàn Lập nhận ra văn tự trên miếng đồng giống công pháp luyện khí vô danh bằng da thú hắn từng có, sinh hứng thú. Lão giả béo bán yêu đan cấp sáu và Thiên Linh Tử, Thanh phu nhân bỏ một vạn rưỡi linh thạch mua yêu đan. Đến phiên Hàn Lập, hắn tuyên bố muốn đổi toàn bộ tài liệu lấy tin tức sào huyệt yêu thú cấp tám, khiến toàn trường kinh ngạc nhưng không ai biết. Cuối cùng, Văn Tư Nguyệt — nữ tu sĩ bồi tiếp ngồi cạnh Hàn Lập — bất ngờ tuyên bố biết vị trí đại khái một con yêu thú cấp tám, nhưng không cần tài liệu mà đặt điều kiện khác với Hàn Lập, bị Phạm phu nhân trách mắng nhưng khẳng định dứt khoát."},{"chuong":536,"tieuDe":"Kiếm Uy Sơ Hiện","tomTat":"Hàn Lập trực tiếp thẩm vấn Văn Tư Nguyệt về sào huyệt yêu thú. Văn Tư Nguyệt kể lại việc tình cờ phát hiện sào huyệt Liệt Phong Thú cấp tám ở Ngoại Tinh hải qua bản đồ, nơi nhất định có Bạn Yêu Thảo mà Hàn Lập cần. Nàng đưa ra điều kiện gây chấn động: muốn Hàn Lập thu nàng làm thiếp và mang rời khỏi Diệu Âm Môn. Vân Thiên Khiếu nổi giận bùng Bạch Cốt Âm Hỏa, phán phạt Văn Tư Nguyệt diện bích nửa tháng. Hàn Lập đề nghị dùng tài liệu yêu thú lục-thất cấp trị mấy vạn linh thạch đổi tự do cho nàng, nhưng Phạm phu nhân ghé tai nói nhỏ khiến Vân Thiên Khiếu đổi ý cự tuyệt. Hàn Lập cười lạnh, phóng mười hai thanh tiểu kiếm trắng phá vỡ hộ thể Bạch Cốt Âm Hỏa, xuyên thủng thân Vân Thiên Khiếu hơn mười lỗ, hạ gục trưởng lão Kết Đan kỳ chỉ trong nháy mắt. Toàn bộ tu sĩ kinh ngạc sững sờ."},{"chuong":537,"tieuDe":"Chấn Nhiếp Quần Tu","tomTat":"Hàn Lập thu mười hai thanh tiểu kiếm tụ thành một, trấn nhiếp toàn bộ tu sĩ Kết Đan kỳ tại đại sảnh, khiến mọi người phỏng đoán hắn là lão quái Nguyên Anh kỳ. Vân Thiên Khiếu bị trọng thương gượng đứng dậy, thừa nhận bại trận và cảnh cáo rằng có vị tiền bối Nguyên Anh kỳ (Diệu Hạc) nhìn trúng Văn Tư Nguyệt dùng làm lô đỉnh. Hàn Lập không quan tâm, đe dọa huyết tẩy nơi này nếu ai cản trở, rồi hút tấm đồng từ tay hắc tu sĩ họ Tôn đổi bằng yêu đan cấp năm, đồng thời đặt tài liệu trao đổi tự do cho Văn Tư Nguyệt. Phạm phu nhân gọi Hàn Lập lại, tiết lộ Diệu Âm Môn đang chuẩn bị Truyền Tống Trận trở về Nội Tinh Hải nhưng thiếu Huyễn Mộng Thạch, nơi có đá này bị yêu thú cấp cao canh giữ, mời hợp lực thanh trừ. Hàn Lập từ chối tham gia, mang Văn Tư Nguyệt phá không rời đi. Vân Thiên Khiếu bình tĩnh đứng lên giới thiệu tình huống yêu thú cho các tu sĩ còn lại. Hai ngày sau, Hàn Lập tìm được một hoang đảo linh khí thưa thớt và hạ xuống."},{"chuong":538,"tieuDe":"Thị Thiếp Chi Ngôn","tomTat":"Hàn Lập bay quanh đảo hoang rồi dùng phi kiếm khai phá động phủ nhỏ dưới chân núi, bố trí trận pháp và an trí Văn Tư Nguyệt ở lại tu luyện. Hắn vẫn duy trì dung mạo giả trung niên, xưng Lệ tiên sinh. Văn Tư Nguyệt kể lại biến cố Diệu Âm môn: khi Tử Linh Tiên Tử vào Hư Thiên Điện, Phạm tả sứ cùng tu sĩ ma đạo họ Vân đoạt quyền, Trác hữu sứ mất tích, môn phái phụ thuộc ma đạo, bị ép đến Ngoại Tinh Hải lập bí thị tại Kỳ Uyên đảo. Hàn Lập phân tích mối liên hệ thời gian: biến cố xảy ra đúng lúc hắn cùng Tử Linh Tiên Tử bị vây trong Hư Thiên Điện, Phạm phu nhân truyền tống đệ tử trước rồi Nghịch Tinh Minh mới tấn công Thiên Tinh thành, thế lực ma đạo có địa vị không nhỏ trong Nghịch Tinh Minh. Hắn cảnh giác vì Hư Thiên Đỉnh trên người khiến nhiều lão quái Nguyên Anh kỳ lùng sục, tự tin Hoán Hình Quyết không bị nhìn thấu. Hàn Lập chủ động hủy bỏ ước định thiếp thân, Văn Tư Nguyệt ban đầu kiên quyết giữ lời nhưng cuối cùng thừa nhận vui mừng cảm tạ. Cuối chương Hàn Lập hỏi về sào huyệt Liệt Phong Thú, biết nơi đó gần ranh giới Thâm Uyên cực kỳ nguy hiểm."},{"chuong":539,"tieuDe":"Ba Đầu Sáu Tay","tomTat":"Hàn Lập cấp đan dược cho Văn Tư Nguyệt rồi vào mật thất nghiên cứu tấm đồng mới có được. Rót linh lực vào tấm đồng, nó phóng bức họa yêu thú vảy bạc biểu diễn 36 tư thế tu luyện — Hàn Lập kết luận đây là công pháp yêu tu, so sánh thấy văn tự cùng nguồn gốc quyển sách da thú, từ bỏ cả hai. Hắn hồi tưởng hiệu quả Bổ Thiên đan: tư chất đã cải thiện ngang tam linh căn, thêm hy vọng ngưng kết Nguyên Anh. Để lại pháp khí và cách khống chế pháp trận cho Văn Tư Nguyệt rồi lên đường tới Thâm uyên hải vực, bay một tháng mới tới. Dùng Ẩn thân thuật tránh yêu thú cấp cao, bố trí huyễn trận trên mỏm đá cách xa hòn đảo, mai phục quan sát sào huyệt Liệt Phong Thú mấy tháng không thấy động tĩnh. Cuối cùng quyết định xâm nhập, ẩn hình tiến vào hang động thiên nhiên khổng lồ bên trong hòn đảo, phát hiện hồ nước nóng xanh sâu không dò nổi và Bạn Yêu Thảo màu đen (chứng tỏ gần yêu thú cấp tám). Lo ngại Liệt Phong Thú ở dưới đáy hồ, Hàn Lập vẫn lao tới bờ hồ lấy hộp ngọc phất tay thu hái Bạn Yêu Thảo."},{"chuong":540,"tieuDe":"Cửu Cấp Yêu Tộc","tomTat":"Hàn Lập thu thành công mấy cây Bạn Yêu Thảo vào hộp ngọc, hoàn thành mục tiêu mai phục lâu ngày. Khi định rời đi thì bị một yêu tộc áo xanh chặn lại — chính là Liệt Phong Thú đã trưởng thành, hoàn thành hóa hình giai đoạn hai, tương đương yêu thú cấp chín. Biết không có cơ sống sót, Hàn Lập phun phi kiếm hộ thân nhưng bị đối phương chớp mắt đoạt mất túi linh thú, liền nuốt Kim Ti cầu vào bụng chuẩn bị dùng Ích Tà Thần Lôi châm ngòi Kiền Lam châu tự bạo. Liệt Phong Thú bất ngờ tuyên bố không có ý giết, tự nhận là loại trung gian giữa hải thú và yêu điểu, không thuộc quản hạt hải tộc đang khai chiến với nhân loại, trả lại túi linh thú và mời Hàn Lập làm khách. Hàn Lập miễn cưỡng đáp ứng, theo quang cầu xanh của Liệt Phong Thú chìm xuống đáy Lân Hỏa đàm, qua cửa đá đen có cấm chế, vào động phủ trang hoàng san hô diễm lệ với bàn ghế ngọc trắng và tiểu đỉnh đốt hương đen cổ xưa."},{"chuong":541,"tieuDe":"Bích Diễm Tửu","tomTat":"Liệt Phong Thú mời Hàn Lập ngồi, tự xưng tên thật là Phong Hi, nhận ra Hàn Lập đang dùng Liễm khí thuật — mật truyền thuật của một vị cố nhân yêu tu đã chết, tò mò tại sao loài người sử dụng được yêu bí thuật. Phong Hi tiết lộ giữ mạng Hàn Lập vì cần mượn công pháp mộc thuộc tính tinh thuần của hắn làm một việc quan trọng, yêu cầu tu vi Kết Đan hậu kỳ. Phong Hi lấy ra Bích Diễm Tửu — linh tửu tự chế hơn trăm năm, cần hóa hình giai yêu đan và thiên phú bộ tộc Liệt Phong Thú mới luyện được, có thể giúp Kết Đan kỳ tu sĩ đột phá bình cảnh. Hàn Lập bị ép uống, nếu không uống hoặc không đột phá sẽ bị giết, đành chấp nhận dùng pháp thuật biến rượu thành thủy tiễn nuốt thẳng. Phong Hi dẫn Hàn Lập tới mật thất san hô khổng lồ, giam bên trong để luyện hoá rượu, ước tính cần hơn nửa năm. Mật thất rộng ba bốn mươi trượng, vách tường đầy nốt li ti giống ma điểm, thần thức chạm vách đều bị bắn ngược. Phong Hi đứng ngoài lộ vẻ hưng phấn yêu dị rồi biến mất. Hàn Lập dùng thần thức thăm dò không tìm được sơ hở, bắt đầu phóng kiếm quang thử phá vách tường."},{"chuong":542,"tieuDe":"Hậu Kỳ Đại Thành","tomTat":"Hàn Lập thử phá vách san hô bằng kiếm quang kết hợp Ích Tà Thần Lôi nhưng thất bại trước cấm chế nhiều tầng, nghĩ đến Phệ Kim Trùng nhưng sợ Phong Hi phát giác nên từ bỏ. Hắn bắt đầu luyện hoá Bích Diễm Tửu bằng đan hoả từ tam sắc kim đan, mạo hiểm bức toàn bộ đan hoả và liên tục tiêu hao linh dịch ngàn năm để đẩy nhanh tiến độ. Khi pháp lực khô kiệt, Kiền Lam Băng Châu đột nhiên chuyển động biến hình trong cơ thể suýt bạo nổ, Hàn Lập dùng phần Bích Diễm Tửu còn thừa bao lại may mắn ổn định rồi lấy viên châu ra ngoài. Sau khi sắp xếp xong, hắn phát hiện mình đã lặng lẽ đột phá bình cảnh tiến vào Kết Đan Hậu Kỳ, có thể đồng thời xuất ra 24 Thanh Trúc Phong Vân Kiếm. Hết thời hạn nửa năm, Phong Hi mở cửa vách san hô, vui mừng khi thấy Hàn Lập đột phá, dẫn hắn đến đại sảnh gặp hai yêu thú cấp tám thuộc Thiên Địa Linh Tộc: Độc Giao (Giao Thủ Cương Vĩ) và Cự Quy (Quy Xác Thanh Diện), tiết lộ muốn bốn người hợp tác làm một việc gì đó. Hàn Lập nhận ra Độc Giao chính là con giao long từng giết tu sĩ nhân loại ở vùng biển trước kia, nhờ lần trước dùng huyết sắc phi phong che tướng mạo nên đối phương chỉ nghi ngờ mà không nhận ra, bèn hàm hồ trả lời tự hạ mình để tránh phiền toái."},{"chuong":543,"tieuDe":"Phong Lôi Sí","tomTat":"Phong Hi triệu tập Độc Giao, Quy yêu và Hàn Lập, tiết lộ kế hoạch luyện chế pháp bảo Phong Lôi Sí từ bộ xương cánh bạc di hài Lôi Bằng điểu thượng cổ tìm được ở cô đảo dưới đáy biển. Độc Giao và Quy yêu ban đầu phản đối vì cho rằng yêu tộc nên tu luyện thân thể thay vì luyện pháp bảo, nhưng sau cùng đồng ý hỗ trợ. Phong Hi phân công bốn thuộc tính phối hợp: thổ (Quy yêu), thủy (Độc Giao), phong (Phong Hi), mộc (Hàn Lập). Phong Hi tiết lộ Bích Diễm Tửu do yêu tộc chế tạo, nhân loại uống vào sẽ tạo hỗn độn tà khí trong cơ thể, sau tà khí tản ra khiến chân nguyên hỗn tạp rồi linh lực tự bạo mà chết, ngay cả tu sĩ Nguyên Anh kỳ cũng không giải được, chỉ Phong Hi mới trừ bỏ tận gốc. Hàn Lập buộc phải chấp nhận hợp tác nhưng trong lòng lo sợ luyện thành pháp bảo cũng là lúc mạng mình kết thúc. Độc Giao xác nhận Giao Long Nhất tộc có yêu tộc cấp cao tham chiến Vạn trượng hải, phá thành trì nhân loại và giết hai tu sĩ Nguyên Anh kỳ, Hàn Lập nghe tin thần sắc hơi đổi."}];
